function viewHeader(title, subtitle, viewId) {
  const meta = NAV.find(n => n.id === viewId) || {};
  const docUrl = meta.docUrl || '';
  // Q2 (v2.66.3) вҖ” match the Orchestrator screenshot: tighter title row,
  // generous subtitle, optional doc link on the right. Subtitle becomes
  // ``max-width: 64ch`` so long descriptions wrap naturally instead of
  // spanning the full card width.
  return `
    <div class="lc-view-header mb-5 flex items-start justify-between gap-3 flex-wrap">
      <div class="min-w-0 flex-1">
        <h1 class="text-2xl font-bold leading-tight">${escapeHtml(t(title))}</h1>
        ${subtitle ? `<p class="text-sm text-[var(--text-mute)] mt-2" style="max-width:64ch;line-height:1.5;">${t(subtitle)}</p>` : ''}
      </div>
      ${docUrl ? `<a class="btn text-xs" href="${docUrl}" target="_blank" rel="noopener">рҹ“– ${t('кіөмӢқ л¬ём„ң вҶ—')}</a>` : ''}
    </div>`;
}

// ліҖкІҪ(POST/PUT/DELETE) нӣ„ мһҗлҸҷ нҺҳмқҙм§Җ лҰ¬лЎңл“ң вҖ” л””л°”мҡҙмҠӨлЎң м—°мҶҚ нҳём¶ң н•©м№ҳкё°
let __autoReloadTimer = null;
let __lastRenderedView = null;
let __lastRenderTs = 0;
function _scheduleAutoReload() {
  if (__autoReloadTimer) clearTimeout(__autoReloadTimer);
  __autoReloadTimer = setTimeout(() => {
    __autoReloadTimer = null;
    // к°ҷмқҖ л·°м—җм„ң 500ms мқҙлӮҙ мӨ‘ліө л ҢлҚ” л°©м§Җ
    const now = Date.now();
    if (state.view === __lastRenderedView && now - __lastRenderTs < 500) return;
    __lastRenderedView = state.view;
    __lastRenderTs = now;
    try { renderView && renderView(); } catch (e) { console.warn('autoReload renderView failed', e); }
  }, 500);
}
// лҚ°мқҙн„° к°ұмӢ кіј л¬ҙкҙҖн•ң м—”л“ңнҸ¬мқёнҠёлҠ” мһҗлҸҷ лҰ¬лЎңл“ң м ңмҷё (LLM нҳём¶ң, лӢЁмҲң лҜёлҰ¬ліҙкё°, мҷёл¶Җ IO л“ұ)
const __noReloadPaths = [
  '/api/feature/recommend', '/api/file/recommend', '/api/recommend',
  '/api/translate/batch', '/api/translate', '/api/settings/preview',
  '/api/open-folder', '/api/open-session', '/api/sessions/reindex',
  '/api/login', '/api/auth', '/api/chat',
  // мӣҢнҒ¬н”ҢлЎңмҡ° м—җл””н„°лҠ” н”„лЎ нҠёк°Җ к¶Ңмң„ мғҒнғңлҘј л“Өкі  мһҲмңјлҜҖлЎң м„ңлІ„ мқ‘лӢө нӣ„
  // renderView() лЎң л·°лҘј лҰ¬м…Ӣн•ҳл©ҙ л“ңлһҳк·ё мӨ‘ к№ңл№Ўмһ„В·м„ нғқ мҙҲкё°нҷ” л°ңмғқ
  '/api/workflows/', '/api/session/spawn',
  // AI н”„лЎңл°”мқҙлҚ” вҖ” н…ҢмҠӨнҠё/л№„көҗ/н—¬мҠӨ/м„Өм • м ҖмһҘмқҖ лҰ¬лЎңл“ң л¶Ҳн•„мҡ”
  '/api/ai-providers/',
  // Ollama вҖ” pull/serve/info/settings лҠ” мқёлқјмқё мғҒнғң м—…лҚ°мқҙнҠё
  '/api/ollama/',
  // Auto-Resume вҖ” лӘЁлӢ¬ м•Ҳм—җм„ң нҶ кёҖн•ҳлҜҖлЎң мһҗлҸҷ лҰ¬лЎңл“ң мӢң лӘЁлӢ¬мқҙ лӢ«нһҳ
  '/api/auto_resume/',
  // Crew Wizard вҖ” preview/create/test нҳём¶ң нӣ„ renderView() к°Җ нҠёлҰ¬кұ°лҗҳл©ҙ
  // мһ…л Ҙ мӨ‘мқё 4-step нҸј мғҒнғң(__cw.form)к°Җ лӮ м•„к°җ (v2.38.0 hotfix)
  '/api/wizard/',
  '/api/slack/',
  '/api/obsidian/',
  // Quick Settings prefs вҖ” мӮ¬мқҙл“ң л“ңлЎңм–ҙ м•Ҳм—җм„ң нҶ кёҖн•ҳлҜҖлЎң лҰ¬лЎңл“ң мӢң лӢ«нһҳ
  '/api/prefs/',
  // Hyper Agent вҖ” toggle/configure/refine-now лҠ” лӘЁлӢ¬ м•Ҳм—җм„ң мӢӨн–үлҗҳлҜҖлЎң
  // мһҗлҸҷ лҰ¬лЎңл“ң мӢң лӘЁлӢ¬ лӢ«нһҲкі  м§„н–ү мӨ‘ нҸј мҙҲкё°нҷ” (v2.39.0)
  '/api/hyper-agents/',
];
// в”Җв”Җ мқёл©”лӘЁлҰ¬ GET мәҗмӢң вҖ” л№ҲлІҲн•ң GET нҳём¶ңмқҳ мӨ‘ліө л„ӨнҠёмӣҢнҒ¬ л№„мҡ© м ңкұ° в”Җв”Җ
// v2.46.0 perf вҖ” Map preserves insertion order so we can evict the oldest
// entry when the cache exceeds _API_CACHE_MAX. Re-insertion (set) on a hit
// could be used for true LRU, but for our usage (read-only catalog data)
// FIFO eviction with TTL is sufficient and cheaper.
const _apiCache = new Map();
const _API_CACHE_MAX = 50;
const _apiCacheTTL = {
  '/api/ai-providers/list': 30000,
  '/api/ai-providers/health': 20000,
  '/api/ollama/catalog': 60000,
  '/api/workflows/stats': 30000,
};
function _apiCacheInvalidate(path) {
  // POST/PUT/DELETE мӢң кҙҖл Ё мәҗмӢң л¬ҙнҡЁнҷ”
  const prefix = path.replace(/\/[^/]*$/, '');
  for (const key of Array.from(_apiCache.keys())) {
    if (key.startsWith(path) || path.startsWith(key.replace(/\/[^/]*$/, '')) || key.startsWith(prefix)) {
      _apiCache.delete(key);
    }
  }
}
function _apiCacheSet(path, data) {
  if (_apiCache.size >= _API_CACHE_MAX && !_apiCache.has(path)) {
    // evict oldest insertion
    const oldest = _apiCache.keys().next().value;
    if (oldest !== undefined) _apiCache.delete(oldest);
  }
  _apiCache.set(path, { data, ts: Date.now() });
}
function cachedApi(path, ttlMs) {
  const ttl = ttlMs || _apiCacheTTL[path] || 30000;
  const c = _apiCache.get(path);
  if (c && Date.now() - c.ts < ttl) return Promise.resolve(c.data);
  return api(path).then(d => { _apiCacheSet(path, d); return d; });
}

// v2.40.1 вҖ” In-flight GET dedupe. Many views fetch the same endpoint in parallel
// (e.g. /api/agents from agents tab + chatbot prompt rebuild). Coalescing them
// halves boot-time concurrent requests with zero behaviour change.
const _apiInflight = new Map();

async function api(path, opts = {}) {
  const method = ((opts && opts.method) || 'GET').toUpperCase();
  if (method === 'GET' && !opts.body && _apiInflight.has(path)) {
    return _apiInflight.get(path);
  }
  const promise = (async () => {
    const r = await fetch(path, opts);
    if (!r.ok && r.status !== 200) {
      let msg = r.status.toString();
      try {
        const j = await r.json();
        msg = errMsg(j);
      } catch {}
      throw new Error(msg);
    }
    return r.json();
  })();
  if (method === 'GET') {
    _apiInflight.set(path, promise);
    promise.finally(() => _apiInflight.delete(path));
  }
  const data = await promise;
  if (method !== 'GET') {
    // POST/PUT/DELETE м„ұкіө мӢң кҙҖл Ё GET мәҗмӢң л¬ҙнҡЁнҷ”
    _apiCacheInvalidate(path.replace(/\/[^/]*$/, ''));
    const ok = data && (data.ok === true || data.ok === undefined && !data.error);
    const skip = __noReloadPaths.some(p => path.startsWith(p));
    if (ok && !skip) _scheduleAutoReload();
  }
  return data;
}
// error_key кё°л°ҳ i18n м—җлҹ¬ л©”мӢңм§Җ н—¬нҚј
function errMsg(r) {
  if (!r) return 'error';
  return (r.error_key && t(r.error_key) !== r.error_key) ? t(r.error_key) : (r.error || 'error');
}

function toast(msg, kind='info') {
  const div = document.createElement('div');
  // V1 (v2.66.8) вҖ” toast styling unified. The kind-specific class adds
  // a left-border tint matching the .lc-* palette (purple/blue/amber/rose
  // are reserved for modes вҖ” toasts use the semantic ok/warn/err set).
  div.className = `lc-toast lc-toast-${kind}`;
  // v2.33.5 вҖ” err/warn нҶ мҠӨнҠёлҠ” рҹ“Ӣ ліөмӮ¬ лІ„нҠј + кёҙ н‘ңмӢң мӢңк°„ (л””лІ„к№… нҺёмқҳ)
  const isFailure = kind === 'err' || kind === 'warn';
  const copyBtn = isFailure
    ? `<button class="btn-ghost btn text-[11px] px-2 py-0.5 ml-2" onclick="(function(b){try{navigator.clipboard.writeText(${JSON.stringify(String(msg))});b.textContent='вң“';setTimeout(()=>b.textContent='рҹ“Ӣ',1200);}catch{}})(this)" title="${t('ліөмӮ¬')}" aria-label="${t('ліөмӮ¬')}">рҹ“Ӣ</button>`
    : '';
  div.innerHTML = `<span>${({info:'в„№пёҸ', ok:'вң…', err:'вқҢ', warn:'вҡ пёҸ'})[kind]||'в„№пёҸ'}</span><span style="flex:1;min-width:0;overflow:hidden;text-overflow:ellipsis;">${escapeHtml(msg)}</span>${copyBtn}`;
  _translateDOM(div);
  document.getElementById('toast').appendChild(div);
  const holdMs = isFailure ? 6000 : 2600;
  setTimeout(() => div.style.opacity='0', holdMs);
  setTimeout(() => div.remove(), holdMs + 600);
}

// v2.46.0 perf вҖ” hoist replacement map so it isn't reallocated per call.
const _ESC_HTML_MAP = {'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'};
function escapeHtml(s) {
  if (s == null) return '';
  return String(s).replace(/[&<>"']/g, ch => _ESC_HTML_MAP[ch]);
}

// O1 (v2.66.0) вҖ” render an email with the local part redacted by default.
// User can flip with `cc.showFullEmail = true` in localStorage. This is a
// privacy hint, not a security boundary вҖ” the same value can still be
// scraped via `/api/auth/status`. Reduces accidental over-the-shoulder
// leakage when sharing a screenshot, which is the actual user complaint.
function _renderEmail(email) {
  if (email == null) return '';
  const s = String(email);
  let showFull = false;
  try { showFull = localStorage.getItem('cc.showFullEmail') === '1'; } catch (_) {}
  if (showFull) return escapeHtml(s);
  const at = s.indexOf('@');
  if (at <= 0) return escapeHtml(s);   // no local part to redact
  const local = s.slice(0, at);
  const domain = s.slice(at);
  // Keep first 2 chars + "***" + last char (if length allows) so the
  // recipient stays vaguely identifiable to the owner.
  let masked = local;
  if (local.length > 3) {
    masked = local.slice(0, 2) + '***' + local.slice(-1);
  } else {
    masked = local[0] + '**';
  }
  return escapeHtml(masked + domain);
}

// P3 (v2.66.2) вҖ” empty / loading / error state helpers. Standardises the
// "no data" / "loadingвҖҰ" / "failed" markup across every tab. Use them
// in VIEWS.* for any state that's empty/in-progress/errored.
function _emptyState(msg, emoji) {
  const e = emoji || 'рҹ“ӯ';
  return `<div class="lc-empty"><span class="lc-empty-emoji">${e}</span>${escapeHtml(msg || t('лҚ°мқҙн„° м—ҶмқҢ'))}</div>`;
}
function _loadingState(msg) {
  return `<div class="lc-loading">${escapeHtml(msg || t('лЎңл”© мӨ‘...'))}</div>`;
}
function _errorState(msg) {
  return `<div class="lc-error">вҡ  ${escapeHtml(msg || t('мӢӨнҢЁ'))}</div>`;
}

function _toggleShowFullEmail() {
  let cur = false;
  try { cur = localStorage.getItem('cc.showFullEmail') === '1'; } catch (_) {}
  try { localStorage.setItem('cc.showFullEmail', cur ? '0' : '1'); } catch (_) {}
  if (typeof renderView === 'function') renderView();
  if (typeof _renderCliStatus === 'function') {
    try { _renderCliStatus(); } catch (_) {}
  }
}
// JSON к°қмІҙлҘј HTML мҶҚм„ұ(мһ‘мқҖ/нҒ°л”°мҳҙн‘ң лӘЁл‘җ м•Ҳм „) мңјлЎң мқёмҪ”л”©
function jsonAttr(obj) {
  return escapeHtml(JSON.stringify(obj));
}
function fmtMs(ms) {
  if (!ms) return 'вҖ”';
  const d = new Date(ms);
  return d.toLocaleString('ko-KR', { month:'2-digit', day:'2-digit', hour:'2-digit', minute:'2-digit' });
}
function fmtRel(ms) {
  if (!ms) return 'вҖ”';
  const d = Math.max(0, Math.floor((Date.now() - ms) / 1000));
  if (d < 60) return `${d}мҙҲ м „`;
  if (d < 3600) return `${Math.floor(d/60)}л¶„ м „`;
  if (d < 86400) return `${Math.floor(d/3600)}мӢңк°„ м „`;
  return `${Math.floor(d/86400)}мқј м „`;
}
function fmtDur(ms) {
  if (!ms) return 'вҖ”';
  const s = Math.floor(ms / 1000);
  if (s < 60) return `${s}s`;
  if (s < 3600) return `${Math.floor(s/60)}m ${s%60}s`;
  return `${Math.floor(s/3600)}h ${Math.floor((s%3600)/60)}m`;
}
function scoreColor(n) {
  n = Number(n) || 0;
  if (n >= 80) return '#4ade80';
  if (n >= 60) return '#a78bfa';
  if (n >= 40) return '#fbbf24';
  return '#f87171';
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// SIDEBAR
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// v2.26.0 вҖ” мғҒмң„ м№ҙн…Ңкі лҰ¬ + hover/focus flyout кө¬мЎ°.
// мӮ¬мқҙл“ңл°”м—җлҠ” 6 м№ҙн…Ңкі лҰ¬л§Ң ліҙмқҙкі , л§Ҳмҡ°мҠӨ/нҸ¬м»ӨмҠӨк°Җ к°Җк№Ңмқҙ к°Җл©ҙ мҳӨлҘёмӘҪмңјлЎң м„ңлёҢнғӯ нҢЁл„җмқҙ м—ҙлҰ°лӢӨ.
// G3 (v2.59.0) вҖ” top-level mode switcher. Each mode is a curated subset of
// the full NAV. Tabs not listed in any mode-specific bucket fall through to
// 'all'. Modes persist in localStorage.
//
// Why a per-id allow-list instead of a `modes:[]` field on every NAV entry:
// the mapping is small (a few dozen ids) and lives in one place вҖ” easy to
// audit, easy to reorganise without touching the NAV array.
const MODE_TABS = {
  claude: new Set([
    'features','onboarding','guideHub','overview','projects','analytics',
    'aiEval','sessions','agents','projectAgents','skills','commands',
    'sessionReplay','rtk',
    'hooks','permissions','mcp','plugins','marketplaces','settings',
    'claudemd','envConfig','modelConfig','statusline',
    'memory','memoryManager','tasks','plans','outputStyles','team',
    'eventForwarder','autoResumeManager','backupRestore','backups',
    'system','telemetry','metrics','costsTimeline',
    'securityScan','claudeDocs','zclaude','homunculus','routines',
    'usage','ideStatus','scheduled','bashHistory','cliSessions','openPorts',
  ]),
  workflow: new Set([
    'workflows','runCenter','promptLibrary','agentSdkScaffold',
    'learner','artifacts','crewWizard',
    'agents','projectAgents','skills','commands',
    'settings',
  ]),
  providers: new Set([
    'aiProviders','modelConfig',
    'promptCache','thinkingLab','toolUseLab','batchJobs','apiFiles',
    'visionLab','modelBench','serverTools','citationsLab','embeddingLab',
    'computerUseLab','memoryLab','advisorLab',
    'costsTimeline','zclaude','envConfig','settings',
  ]),
  lazyclaw: new Set([
    'orchestrator','ralph','agents','workflows',
    'aiProviders','runCenter','sessionReplay',
    'settings',
  ]),
};

// N2 (v2.66.0) вҖ” one-shot migration of legacy 'openclaw' storage keys to
// 'lazyclaw'. Idempotent and silent.
(function _migrateOpenClawKeys() {
  try {
    if (localStorage.getItem('cc.mode') === 'openclaw') {
      localStorage.setItem('cc.mode', 'lazyclaw');
    }
    const oldLast = localStorage.getItem('cc.mode.openclaw.lastTab');
    if (oldLast) {
      localStorage.setItem('cc.mode.lazyclaw.lastTab', oldLast);
      localStorage.removeItem('cc.mode.openclaw.lastTab');
    }
    const oldCounts = localStorage.getItem('cc.mode.openclaw.counts');
    if (oldCounts) {
      localStorage.setItem('cc.mode.lazyclaw.counts', oldCounts);
      localStorage.removeItem('cc.mode.openclaw.counts');
    }
  } catch (_) {}
})();

function _getMode() {
  try { return localStorage.getItem('cc.mode') || 'all'; } catch (_) { return 'all'; }
}

// H1 (v2.60.0) вҖ” per-mode last-tab memory. Switching to a mode jumps back
// to whatever you last viewed in that mode. Defaults below seed the very
// first switch.
const MODE_DEFAULT_TAB = {
  all:        'overview',
  claude:     'overview',
  workflow:   'workflows',
  providers:  'aiProviders',
  lazyclaw:   'orchestrator',
};

function _modeLastTab(m) {
  try {
    const stored = localStorage.getItem('cc.mode.' + m + '.lastTab');
    if (stored && (m === 'all' || (MODE_TABS[m] && MODE_TABS[m].has(stored)))) {
      return stored;
    }
  } catch (_) {}
  return MODE_DEFAULT_TAB[m] || 'overview';
}

function _rememberLastTab(mode, tabId) {
  try { localStorage.setItem('cc.mode.' + mode + '.lastTab', tabId); }
  catch (_) {}
}

function setMode(m) {
  if (!['all','claude','workflow','providers','lazyclaw'].includes(m)) m = 'all';
  // Remember the tab the user was on in the OLD mode before switching.
  const prev = state.mode || 'all';
  if (state.view) _rememberLastTab(prev, state.view);
  try { localStorage.setItem('cc.mode', m); } catch (_) {}
  state.mode = m;
  // S1 (v2.66.5) вҖ” body data attribute drives the mode-aware accent stripe.
  if (document && document.body) document.body.dataset.mode = m;
  const sel = document.getElementById('modeSelect');
  if (sel && sel.value !== m) sel.value = m;
  // Restore the user's last tab in the NEW mode (or its default).
  const target = _modeLastTab(m);
  if (target && target !== state.view) {
    go(target);
  } else {
    renderNav();
  }
}
function _navInMode(navItem) {
  const m = state.mode || _getMode();
  if (m === 'all') return true;
  return MODE_TABS[m] && MODE_TABS[m].has(navItem.id);
}

function renderNav() {
  const nav = document.getElementById('nav');
  nav.setAttribute('role', 'menubar');
  nav.setAttribute('aria-label', t('л©”мқё л„Өл№„кІҢмқҙм…ҳ'));
  nav.innerHTML = '';

  // v2.40.0 вҖ” render Favorites + Recent above the categorical groups so the
  // user reaches frequent tabs in one click instead of opening a flyout.
  // v2.59.0 вҖ” additionally filter by current mode (G3).
  const navById = {};
  NAV.forEach(n => { navById[n.id] = n; });

  const inMode = (id) => _navInMode({ id });
  const favIds = ((window.CC_PREFS && window.CC_PREFS.ui && window.CC_PREFS.ui.favoriteTabs) || [])
    .filter(id => navById[id] && inMode(id));
  const recIds = _getRecentTabs().filter(id => navById[id] && !favIds.includes(id) && inMode(id))
    .slice(0, ((window.CC_PREFS && window.CC_PREFS.ui && window.CC_PREFS.ui.recentTabsLimit) || 5));

  const _renderQuickItem = (n, kind) => {
    const item = document.createElement('div');
    item.className = 'nav-quick-item' + (state.view === n.id ? ' active' : '');
    item.setAttribute('role', 'menuitem');
    item.setAttribute('tabindex', '0');
    item.title = t(n.label) + (n.desc ? ' вҖ” ' + t(n.desc) : '');
    item.innerHTML = `
      <span class="nav-quick-icon" aria-hidden="true">${n.icon}</span>
      <span class="nav-quick-label flex-1 truncate">${escapeHtml(t(n.label))}</span>
      ${kind === 'fav'
        ? `<button class="nav-fav-btn" aria-label="${t('мҰҗкІЁм°ҫкё° н•ҙм ң')}" title="${t('мҰҗкІЁм°ҫкё° н•ҙм ң')}">вҳ…</button>`
        : `<button class="nav-fav-btn" aria-label="${t('мҰҗкІЁм°ҫкё° м¶”к°Җ')}" title="${t('мҰҗкІЁм°ҫкё° м¶”к°Җ')}" style="opacity:0.4;">вҳҶ</button>`
      }
    `;
    item.onclick = (e) => {
      if (e.target.closest('.nav-fav-btn')) { toggleFavoriteTab(n.id, e); return; }
      go(n.id);
    };
    item.onkeydown = e => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); go(n.id); } };
    return item;
  };

  if (favIds.length || recIds.length) {
    const quick = document.createElement('div');
    quick.className = 'nav-quick-block';
    if (favIds.length) {
      const fh = document.createElement('div');
      fh.className = 'nav-quick-header';
      fh.innerHTML = `<span>вҳ…</span> <span>${escapeHtml(t('мҰҗкІЁм°ҫкё°'))}</span> <span class="ml-auto text-[9px] opacity-60">${favIds.length}</span>`;
      quick.appendChild(fh);
      favIds.forEach(id => quick.appendChild(_renderQuickItem(navById[id], 'fav')));
    }
    if (recIds.length) {
      const rh = document.createElement('div');
      rh.className = 'nav-quick-header';
      rh.innerHTML = `<span>рҹ•’</span> <span>${escapeHtml(t('мөңк·ј мӮ¬мҡ©'))}</span> <span class="ml-auto text-[9px] opacity-60">${recIds.length}</span>`;
      quick.appendChild(rh);
      recIds.forEach(id => quick.appendChild(_renderQuickItem(navById[id], 'recent')));
    }
    nav.appendChild(quick);
  }

  GROUPS.forEach(g => {
    const items = NAV.filter(n => n.group === g.id && _navInMode(n));
    if (!items.length) return;
    const activeHere = items.some(n => n.id === state.view);
    const cat = document.createElement('div');
    cat.className = 'nav-category' + (activeHere ? ' has-active' : '');
    cat.setAttribute('role', 'menuitem');
    cat.setAttribute('tabindex', '0');
    cat.setAttribute('aria-haspopup', 'true');
    cat.setAttribute('aria-expanded', 'false');
    cat.setAttribute('aria-label', g.label + ' вҖ” ' + (g.desc || ''));
    // v2.33.1 вҖ” collapsed мғҒнғңм—җм„ң м•„мқҙмҪҳл§Ң лӮЁмқ„ л•ҢлҸ„ мқҳлҜё м „лӢ¬. title мқҖ л„ӨмқҙнӢ°лёҢ нҲҙнҢҒмҡ©.
    cat.setAttribute('title', t(g.label) + (g.desc ? ' вҖ” ' + t(g.desc) : ''));
    cat.dataset.cat = g.id;
    const activeMark = activeHere
      ? '<span class="nav-cat-dot" aria-hidden="true"></span>'
      : '';
    cat.innerHTML = `
      <span class="nav-cat-icon" aria-hidden="true">${g.icon}</span>
      <div class="nav-cat-meta flex-1 min-w-0">
        <div class="nav-cat-label flex items-center gap-1">
          ${activeMark}<span class="nav-cat-label-full">${escapeHtml(t(g.label))}</span><span class="nav-cat-label-short">${escapeHtml(t(g.short || g.label))}</span>
        </div>
        <div class="nav-cat-desc text-[10px] text-[var(--text-dim)] truncate">${escapeHtml(t(g.desc || ''))}</div>
      </div>
      <span class="nav-cat-count text-[10px]" style="color:var(--text-dim)">${items.length}</span>
      <span class="nav-cat-chevron" aria-hidden="true">вҖә</span>
    `;
    const flyout = document.createElement('div');
    flyout.className = 'nav-flyout';
    flyout.setAttribute('role', 'menu');
    flyout.setAttribute('aria-label', g.label);
    flyout.innerHTML = `
      <div class="nav-flyout-header text-[10px] uppercase tracking-widest" style="color:var(--text-dim);">
        <span>${g.icon}</span>
        <span class="ml-1">${escapeHtml(t(g.label))}</span>
        <span class="ml-1 text-[9px]">В· ${items.length}</span>
      </div>`;
    items.forEach(n => {
      const el = document.createElement('div');
      el.className = 'nav-item' + (state.view === n.id ? ' active' : '');
      el.setAttribute('role', 'menuitem');
      el.setAttribute('tabindex', '-1');
      el.setAttribute('aria-label', n.label + (n.desc ? ' вҖ” ' + n.desc : ''));
      el.title = n.label + (n.desc ? ' вҖ” ' + n.desc : '');
      const descHtml = n.desc ? `<div class="nav-desc text-[10px] text-[var(--text-dim)] mt-0.5 leading-tight">${escapeHtml(t(n.desc))}</div>` : '';
      const isFav = _isFavoriteTab(n.id);
      const favBtn = `<button class="nav-fav-btn" aria-label="${isFav?t('мҰҗкІЁм°ҫкё° н•ҙм ң'):t('мҰҗкІЁм°ҫкё° м¶”к°Җ')}" title="${isFav?t('мҰҗкІЁм°ҫкё° н•ҙм ң'):t('мҰҗкІЁм°ҫкё° м¶”к°Җ')}" style="${isFav?'':'opacity:0.4;'}">${isFav?'вҳ…':'вҳҶ'}</button>`;
      // I3 (v2.61.0) вҖ” рҹ”Ҙ hot badge for the current mode's top-3 tabs.
      const _topInThisMode = _topTabsForMode(state.mode || 'all', 3);
      const isHot = _topInThisMode.includes(n.id);
      const hotBadge = isHot
        ? '<span title="' + escapeHtml(t('мқҙ лӘЁл“ңм—җм„ң к°ҖмһҘ л§Һмқҙ мӮ¬мҡ©н•ң нғӯ')) + '" style="margin-left:4px;font-size:10px;">рҹ”Ҙ</span>'
        : '';
      // H3 (v2.60.0) вҖ” mode badges, only visible in 'all' mode so users can
      // see at a glance which mode each tab also lives in.
      let modeBadges = '';
      if ((state.mode || 'all') === 'all') {
        const tags = [];
        if (MODE_TABS.claude.has(n.id))    tags.push({ k:'C',  c:'#a78bfa', t:'Claude' });
        if (MODE_TABS.workflow.has(n.id))  tags.push({ k:'W',  c:'#60a5fa', t:'Workflow' });
        if (MODE_TABS.providers.has(n.id)) tags.push({ k:'P',  c:'#fbbf24', t:'Providers' });
        if (MODE_TABS.lazyclaw.has(n.id))  tags.push({ k:'L',  c:'#fb7185', t:'LazyClaw' });
        if (tags.length) {
          modeBadges = '<div class="nav-mode-badges" style="display:inline-flex;gap:2px;margin-left:4px;">'
            + tags.map(x => `<span title="${x.t}" style="font-size:8px;padding:1px 3px;border-radius:3px;background:${x.c}22;color:${x.c};font-weight:600;line-height:1;">${x.k}</span>`).join('')
            + '</div>';
        }
      }
      el.innerHTML = `
        <span class="w-5 text-center self-start mt-0.5 flex-shrink-0">${n.icon}</span>
        <div class="nav-label flex-1 min-w-0">
          <div>${escapeHtml(t(n.label))}${hotBadge}${modeBadges}</div>
          ${descHtml}
        </div>
        ${favBtn}`;
      el.onclick = (e) => {
        if (e.target.closest('.nav-fav-btn')) { toggleFavoriteTab(n.id, e); return; }
        e.stopPropagation();
        go(n.id);
        // flyout лӢ«кё°
        document.querySelectorAll('.nav-category.open').forEach(c => c.classList.remove('open'));
        if (window.matchMedia('(max-width: 900px)').matches) {
          document.getElementById('sidebar').classList.remove('open');
          document.body.classList.remove('sidebar-open');
          _syncNavToggleVisibility();
        }
      };
      el.onkeydown = (e) => {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); el.click(); }
      };
      flyout.appendChild(el);
    });
    cat.appendChild(flyout);
    // v2.33.2 вҖ” flyout мқҙ viewport м—җ л“Өм–ҙк°ҖлҸ„лЎқ mouseenter/focusin мӢң top/max-height мһ¬кі„мӮ°
    const reposition = () => _positionNavFlyout(cat);
    cat.addEventListener('mouseenter', reposition);
    cat.addEventListener('focusin', reposition);
    // м№ҙн…Ңкі лҰ¬ мһҗмІҙ нҒҙлҰӯ: open нҶ кёҖ (лӢӨлҘё м№ҙн…Ңкі лҰ¬лҠ” лӢ«кё°)
    cat.onclick = (e) => {
      if (e.target.closest('.nav-item')) return;
      const isOpen = cat.classList.contains('open');
      document.querySelectorAll('.nav-category.open').forEach(c => c.classList.remove('open'));
      if (!isOpen) {
        cat.classList.add('open');
        cat.setAttribute('aria-expanded', 'true');
        _positionNavFlyout(cat);
      } else {
        cat.setAttribute('aria-expanded', 'false');
      }
    };
    cat.onkeydown = (e) => {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); cat.click(); }
      else if (e.key === 'Escape') {
        document.querySelectorAll('.nav-category.open').forEach(c => {
          c.classList.remove('open'); c.setAttribute('aria-expanded', 'false');
        });
      }
    };
    nav.appendChild(cat);
  });
  _translateDOM(nav);
}

// v2.33.2 вҖ” flyout мқҙ viewport м•Ҳм—җ л“Өм–ҙк°ҖлҸ„лЎқ top/max-height лҘј лҸҷм Ғ кі„мӮ°
// мқҙмң : `.nav-flyout { top: 0; max-height: 80vh }` л§ҢмңјлЎңлҠ” н•ҳлӢЁ м№ҙн…Ңкі лҰ¬(Observe)мқҳ
// flyout мқҙ category мөңмғҒлӢЁм—җм„ң мӢңмһ‘ вҶ’ viewport м•„лһҳлЎң мӮҗм ёлӮҳк°Җ л’ӨмӘҪ м•„мқҙн…ңмқҙ мһҳлҰј.
// лӮҙл¶Җ overflow лҠ” мһҲм§Җл§Ң мҠӨнҒ¬лЎӨл°”к°Җ л·°нҸ¬нҠё л°–мқҙлқј мӮ¬мҡ©мһҗк°Җ м ‘к·ј л¶Ҳк°Җ.
function _positionNavFlyout(cat) {
  const fl = cat && cat.querySelector('.nav-flyout');
  if (!fl) return;
  // v2.33.9 вҖ” лӘЁл°”мқј(вүӨ900px) мқҖ м•„мҪ”л””м–ё лӘЁл“ңлқј position кі„мӮ° л¶Ҳн•„мҡ”.
  // inline style мқ„ м°ҢлҒјлЎң лӮЁкё°л©ҙ @media к·ңм№ҷкіј м¶©лҸҢн•ҳлҜҖлЎң л°ҳл“ңмӢң мҙҲкё°нҷ”.
  if (window.matchMedia && window.matchMedia('(max-width: 900px)').matches) {
    fl.style.top = '';
    fl.style.maxHeight = '';
    return;
  }
  const margin = 12;
  const vh = window.innerHeight;
  const cr = cat.getBoundingClientRect();
  // мһҗм—° лҶ’мқҙ мёЎм • вҖ” display:none мғҒнғңл©ҙ мһ„мӢңлЎң block мІҳлҰ¬ нӣ„ ліөмӣҗ
  const priorDisplay = fl.style.display;
  const priorVisibility = fl.style.visibility;
  fl.style.maxHeight = '';
  fl.style.top = '0';
  if (getComputedStyle(fl).display === 'none') {
    fl.style.visibility = 'hidden';
    fl.style.display = 'block';
  }
  const naturalH = fl.scrollHeight;
  // мёЎм • нӣ„ мӣҗліө (CSS :hover к°Җ кі§ display:block мқ„ м Ғмҡ©)
  fl.style.display = priorDisplay;
  fl.style.visibility = priorVisibility;
  const maxAllowed = vh - 2 * margin;
  const wantH = Math.min(naturalH, maxAllowed);
  let topOffset = 0;
  if (cr.top + wantH + margin > vh) {
    topOffset = vh - cr.top - wantH - margin;
    if (cr.top + topOffset < margin) topOffset = margin - cr.top;
  }
  fl.style.top = `${topOffset}px`;
  fl.style.maxHeight = `${wantH}px`;
}
window._positionNavFlyout = _positionNavFlyout;

// viewport ліҖнҷ” мӢң м—ҙл ӨмһҲлҠ” flyout мһ¬кі„мӮ°
window.addEventListener('resize', () => {
  document.querySelectorAll('.nav-category').forEach(cat => {
    if (cat.matches(':hover') || cat.classList.contains('open') || cat.contains(document.activeElement)) {
      _positionNavFlyout(cat);
    }
  });
});

// мӮ¬мқҙл“ңл°” л°”к№Ҙ нҒҙлҰӯ мӢң flyout лӢ«кё°
document.addEventListener('click', (e) => {
  if (e.target.closest('.nav-category, .nav-flyout')) return;
  document.querySelectorAll('.nav-category.open').forEach(c => {
    c.classList.remove('open'); c.setAttribute('aria-expanded', 'false');
  });
});

// лӘЁл°”мқј мҳӨлІ„л Ҳмқҙ нҒҙлҰӯ вҶ’ мӮ¬мқҙл“ңл°” лӢ«кё°
document.addEventListener('click', (e) => {
  if (!window.matchMedia('(max-width: 900px)').matches) return;
  const sb = document.getElementById('sidebar');
  if (!sb || !sb.classList.contains('open')) return;
  // нҒҙлҰӯмқҙ мӮ¬мқҙл“ңл°” лӮҙл¶Җк°Җ м•„лӢҲкі  нҶ кёҖ лІ„нҠјлҸ„ м•„лӢҲл©ҙ лӢ«кё°
  if (sb.contains(e.target)) return;
  if (e.target.closest('#navToggle, #sbToggle')) return;
  sb.classList.remove('open');
  document.body.classList.remove('sidebar-open');
});
// v2.33.4 вҖ” нғӯ нһҲмҠӨнҶ лҰ¬ (Alt+вҶҗ/вҶ’) В· мөңк·ј 20к°ң мң м§Җ
const _tabHistory = [];
let _tabHistoryIdx = -1;
let _tabNavigating = false;

function go(id) {
  if (state.view === 'rtk' && id !== 'rtk' && typeof _rtkStopPolling === 'function') _rtkStopPolling();
  // W5 (v2.66.9) вҖ” close any leaked EventSource / interval timers when
  // navigating away. Prevents the orchestrator + ralph SSE connections
  // (and the ralph-list polling timer) from holding HTTP sockets +
  // DOM refs open after the user moves on. The AFTER hooks already do
  // this on tab-leave when registered, but not every view registers
  // one вҖ” defence in depth.
  if (id !== state.view) {
    try { if (state.data._orchEs) { state.data._orchEs.close(); state.data._orchEs = null; } } catch (_) {}
    try { if (state.data._ralphEs) { state.data._ralphEs.close(); state.data._ralphEs = null; } } catch (_) {}
    try { if (state.data._ralphPollTimer) { clearInterval(state.data._ralphPollTimer); state.data._ralphPollTimer = null; } } catch (_) {}
  }
  // нһҲмҠӨнҶ лҰ¬м—җ кё°лЎқ вҖ” м•ҢнҠё ВұлЎң мқҙлҸҷ мӨ‘мқј л•ҢлҠ” append м•Ҳ н•Ё
  if (!_tabNavigating && id !== _tabHistory[_tabHistoryIdx]) {
    _tabHistory.splice(_tabHistoryIdx + 1);
    _tabHistory.push(id);
    if (_tabHistory.length > 20) _tabHistory.shift();
    _tabHistoryIdx = _tabHistory.length - 1;
  }
  // v2.40.0 вҖ” recent-tabs MRU (localStorage). Capped at prefs.ui.recentTabsLimit.
  try { _pushRecentTab(id); } catch {}
  state.view = id;
  location.hash = '#/' + id;
  // H1 (v2.60.0) вҖ” per-mode last-tab memory.
  try { _rememberLastTab(state.mode || 'all', id); } catch {}
  // I3 (v2.61.0) вҖ” per-mode visit counter for "most-used" рҹ”Ҙ badge.
  try { _bumpModeTabCounter(state.mode || 'all', id); } catch {}
  renderNav();
  renderView();
}

// I3 (v2.61.0) вҖ” per-mode tab visit counter. Stored as
// localStorage 'cc.mode.<mode>.counts' = {tabId: count, ...}.
// Cap each count at 9999 so a single noisy day doesn't dominate forever.
const _COUNT_CAP = 9999;

function _modeTabCounts(mode) {
  try {
    const raw = localStorage.getItem('cc.mode.' + mode + '.counts');
    return raw ? JSON.parse(raw) : {};
  } catch (_) { return {}; }
}

function _bumpModeTabCounter(mode, tabId) {
  const counts = _modeTabCounts(mode);
  counts[tabId] = Math.min((counts[tabId] || 0) + 1, _COUNT_CAP);
  try { localStorage.setItem('cc.mode.' + mode + '.counts', JSON.stringify(counts)); }
  catch (_) {}
}

function _openModeUsageModal() {
  const modes = ['all','claude','workflow','providers','lazyclaw'];
  const navById = {};
  NAV.forEach(n => { navById[n.id] = n; });
  const sections = modes.map(m => {
    const counts = _modeTabCounts(m);
    const total = Object.values(counts).reduce((a, b) => a + b, 0);
    const ranked = Object.entries(counts).sort((a, b) => b[1] - a[1]).slice(0, 10);
    if (!ranked.length) {
      return `<div class="card p-3 mb-2">
        <div class="text-[12px] font-semibold mb-1">${m}</div>
        <div class="text-[10px]" style="color:var(--text-dim)">${t('м•„м§Ғ кё°лЎқ м—ҶмқҢ')}</div>
      </div>`;
    }
    const max = ranked[0][1] || 1;
    const rows = ranked.map(([id, c]) => {
      const n = navById[id];
      const label = n ? `${n.icon} ${escapeHtml(t(n.label))}` : `<span style="color:var(--text-dim)">${escapeHtml(id)}</span>`;
      const pct = Math.max(2, Math.round(c / max * 100));
      return `<div class="text-[11px] mb-1">
        <div class="flex items-center gap-2">
          <span class="flex-1 truncate">${label}</span>
          <span class="font-mono" style="color:var(--text-dim)">${c}</span>
        </div>
        <div style="height:3px;background:rgba(255,255,255,0.05);border-radius:2px;overflow:hidden;">
          <div style="height:100%;width:${pct}%;background:var(--accent);"></div>
        </div>
      </div>`;
    }).join('');
    return `<div class="card p-3 mb-2">
      <div class="flex items-center gap-2 mb-2">
        <div class="text-[12px] font-semibold">${m}</div>
        <div class="text-[10px]" style="color:var(--text-dim)">${total} ${t('лІҲ л°©л¬ё')}</div>
        <button class="chip text-[10px] ml-auto" onclick="_resetModeCounts('${m}')">${t('лҰ¬м…Ӣ')}</button>
      </div>
      ${rows}
    </div>`;
  }).join('');
  showModal(`
    <div class="text-[14px] font-semibold mb-3">рҹ“Ҡ ${t('лӘЁл“ңлі„ мӮ¬мҡ©лҹү')}</div>
    ${sections}
    <div class="flex justify-end mt-3">
      <button class="btn text-xs" onclick="closeModal()">${t('лӢ«кё°')}</button>
    </div>
  `, { title: '' });
}

function _resetModeCounts(mode) {
  if (!confirm(t('мқҙ лӘЁл“ңмқҳ м№ҙмҡҙн„°лҘј лҰ¬м…Ӣн• к№Ңмҡ”?'))) return;
  try { localStorage.removeItem('cc.mode.' + mode + '.counts'); } catch {}
  _openModeUsageModal();   // re-render
  renderNav();             // рҹ”Ҙ badges may change
}

function _topTabsForMode(mode, n = 3) {
  const counts = _modeTabCounts(mode);
  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, n)
    .filter(([, c]) => c >= 3)   // need вүҘ3 visits to qualify
    .map(([id]) => id);
}

// в”Җв”Җ v2.40.0 вҖ” Sidebar discovery: favorites + recents + '/' spotlight в”Җв”Җ
const _RECENT_TABS_KEY = 'cc-recent-tabs';
// v2.46.0 perf вҖ” memoize parsed list so renderNav() doesn't re-parse
// localStorage on every navigation render. Updated in-place by _pushRecentTab.
let _recentTabsCache = null;
function _getRecentTabs() {
  if (_recentTabsCache !== null) return _recentTabsCache;
  try {
    const raw = localStorage.getItem(_RECENT_TABS_KEY);
    const arr = raw ? JSON.parse(raw) : [];
    _recentTabsCache = Array.isArray(arr) ? arr.filter(s => typeof s === 'string') : [];
  } catch { _recentTabsCache = []; }
  return _recentTabsCache;
}
function _pushRecentTab(id) {
  if (!id || typeof id !== 'string') return;
  const limit = (window.CC_PREFS && window.CC_PREFS.ui && window.CC_PREFS.ui.recentTabsLimit) || 5;
  if (limit <= 0) return;
  let cur = _getRecentTabs().slice();
  cur = cur.filter(x => x !== id);
  cur.unshift(id);
  if (cur.length > limit) cur = cur.slice(0, limit);
  _recentTabsCache = cur;
  try { localStorage.setItem(_RECENT_TABS_KEY, JSON.stringify(cur)); } catch {}
}
function _isFavoriteTab(id) {
  const f = (window.CC_PREFS && window.CC_PREFS.ui && window.CC_PREFS.ui.favoriteTabs) || [];
  return Array.isArray(f) && f.includes(id);
}
// v2.40.1 вҖ” coalesce sidebar re-renders into the next animation frame. Without
// this, rapid вҳ… toggles (or recent-tab MRU updates from successive go() calls)
// each trigger a full nav rebuild on the same tick.
let _renderNavRaf = 0;
function _scheduleRenderNav() {
  if (_renderNavRaf) return;
  _renderNavRaf = requestAnimationFrame(() => {
    _renderNavRaf = 0;
    renderNav();
  });
}
function toggleFavoriteTab(id, ev) {
  if (ev) { ev.stopPropagation(); ev.preventDefault(); }
  const cur = ((window.CC_PREFS && window.CC_PREFS.ui && window.CC_PREFS.ui.favoriteTabs) || []).slice();
  const idx = cur.indexOf(id);
  if (idx >= 0) cur.splice(idx, 1);
  else cur.unshift(id);
  // setPref defined in v2.38 Quick Settings вҖ” debounces a POST to /api/prefs/set
  if (typeof setPref === 'function') setPref('ui', 'favoriteTabs', cur, {skipApply: true});
  else if (window.CC_PREFS && window.CC_PREFS.ui) window.CC_PREFS.ui.favoriteTabs = cur;
  _scheduleRenderNav();
}
function _tabHistoryBack() {
  if (_tabHistoryIdx <= 0) return;
  _tabHistoryIdx--;
  _tabNavigating = true;
  go(_tabHistory[_tabHistoryIdx]);
  _tabNavigating = false;
}
function _tabHistoryForward() {
  if (_tabHistoryIdx >= _tabHistory.length - 1) return;
  _tabHistoryIdx++;
  _tabNavigating = true;
  go(_tabHistory[_tabHistoryIdx]);
  _tabNavigating = false;
}
window.addEventListener('hashchange', () => {
  const h = location.hash.replace(/^#\//, '') || 'overview';
  if (h !== state.view) {
    if (state.view === 'rtk' && h !== 'rtk' && typeof _rtkStopPolling === 'function') _rtkStopPolling();
    // II2 (v2.66.25) вҖ” leaving the workflow tab while a run was in
    // flight: tear down SSE / poll / ticker so they don't keep firing
    // in the background and rebuild DOM on a tab the user can't see.
    // Auto-restore re-attaches when the user comes back.
    if (state.view === 'workflows' && h !== 'workflows') {
      try {
        if (typeof _wfStopSSE === 'function') _wfStopSSE();
        if (typeof _wfStopElapsedTicker === 'function') _wfStopElapsedTicker();
        if (typeof __wf !== 'undefined' && __wf.pollTimer) {
          clearInterval(__wf.pollTimer); __wf.pollTimer = null;
        }
      } catch (_) {}
    }
    state.view = h; renderNav(); renderView();
  }
});
// v2.47 perf вҖ” single global keydown dispatcher.
// Each former module-level handler is pushed as a function on this array.
// Returning truthy from a handler consumes the event (later handlers skipped).
// Order matters: register hot/global handlers (Cmd+K spotlight, Esc) first.
// v2.47 perf вҖ” registry of live Chart.js instances keyed by canvas id.
// Lets render-paths update existing charts in place instead of destroy+new.
const _chartInstances = window._chartInstances || (window._chartInstances = new Map());

// Render or update a Chart.js chart on `canvasEl` with `cfg`.
// If a chart already exists for this canvas id and matches the requested type,
// data is patched in place and `update('none')` runs for animation-free refresh.
// Otherwise the old instance is destroyed and a fresh chart is created.
async function _renderChart(canvasEl, cfg) {
  if (!canvasEl) return null;
  // HH2 вҖ” load Chart.js on first call, then proceed.
  if (typeof Chart === 'undefined') {
    try { await window._loadVendor('chart'); } catch (_) { return null; }
  }
  if (typeof Chart === 'undefined') return null;
  const id = canvasEl.id;
  if (!id) {
    // Fallback for unidentified canvases вҖ” behave like the old destroy+new flow
    return new Chart(canvasEl, cfg);
  }
  // Sweep entries whose canvas was removed from the DOM by a renderView swap
  _chartInstances.forEach((c, key) => {
    if (!document.getElementById(key)) {
      try { c.destroy?.(); } catch (_) {}
      _chartInstances.delete(key);
    }
  });
  const existing = _chartInstances.get(id);
  if (existing && existing.config && existing.config.type === cfg.type
      && existing.data && cfg.data
      && Array.isArray(existing.data.datasets) && Array.isArray(cfg.data.datasets)
      && existing.data.datasets.length === cfg.data.datasets.length) {
    try {
      existing.data.labels = cfg.data.labels;
      cfg.data.datasets.forEach((ds, i) => {
        const target = existing.data.datasets[i];
        target.data = ds.data;
        if ('label' in ds) target.label = ds.label;
        if ('backgroundColor' in ds) target.backgroundColor = ds.backgroundColor;
        if ('borderColor' in ds) target.borderColor = ds.borderColor;
      });
      existing.update('none');
      return existing;
    } catch (_) {
      // Fall through to recreate on any update failure
      try { existing.destroy(); } catch (_) {}
      _chartInstances.delete(id);
    }
  }
  if (existing) { try { existing.destroy(); } catch (_) {} }
  const fresh = new Chart(canvasEl, cfg);
  _chartInstances.set(id, fresh);
  return fresh;
}

const _KEYDOWN_HANDLERS = [];
document.addEventListener('keydown', (e) => {
  for (const h of _KEYDOWN_HANDLERS) {
    try { if (h(e)) break; } catch (err) { /* one bad handler must not break others */ console.error(err); }
  }
});

// Global Alt+ArrowLeft/Right вҖ” tab history nav
_KEYDOWN_HANDLERS.push((e) => {
  if (!e.altKey || e.ctrlKey || e.metaKey) return;
  const inInput = ['INPUT','TEXTAREA','SELECT'].includes((document.activeElement||{}).tagName);
  if (inInput) return;
  if (e.key === 'ArrowLeft') { e.preventDefault(); _tabHistoryBack(); return true; }
  if (e.key === 'ArrowRight') { e.preventDefault(); _tabHistoryForward(); return true; }
});

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// VIEW DISPATCHER
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
const VIEWS = {};
const AFTER = {};

let __renderLock = false;
let __renderQueued = false;
// v2.33.4 вҖ” нғӯлі„ skeleton л§Өн•‘ (мқҙлҰ„/м•„мқҙмҪҳ мҰүмӢң л…ём¶ң вҶ’ мӮ¬мҡ©мһҗк°Җ "м—ҙкі  мһҲлҠ” нғӯ" нҷ•мӢӨнһҲ мқём§Җ)
const _SKELETONS = {
  aiProviders: () => `
    <div class="shimmer h-10 mb-4" style="width:40%"></div>
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
      ${Array.from({length:6}).map(()=>'<div class="shimmer h-44"></div>').join('')}
    </div>`,
  commands: () => `
    <div class="shimmer h-10 mb-4" style="width:30%"></div>
    <div class="space-y-2">
      ${Array.from({length:10}).map(()=>'<div class="shimmer h-14"></div>').join('')}
    </div>`,
  workflows: () => `
    <div class="shimmer h-10 mb-4" style="width:40%"></div>
    <div class="grid grid-cols-1 md:grid-cols-4 gap-3">
      <div class="shimmer h-96"></div>
      <div class="shimmer h-96 md:col-span-2"></div>
      <div class="shimmer h-96"></div>
    </div>`,
  overview: () => `
    <div class="shimmer h-12 mb-4" style="width:50%"></div>
    <div class="grid grid-cols-1 md:grid-cols-4 gap-3 mb-4">
      ${Array.from({length:4}).map(()=>'<div class="shimmer h-28"></div>').join('')}
    </div>
    <div class="shimmer h-64"></div>`,
  sessions: () => `
    <div class="shimmer h-10 mb-4" style="width:35%"></div>
    <div class="shimmer h-8 mb-3" style="width:60%"></div>
    ${Array.from({length:8}).map(()=>'<div class="shimmer h-12 mb-2"></div>').join('')}`,
  projects: () => `
    <div class="shimmer h-10 mb-4" style="width:35%"></div>
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
      ${Array.from({length:6}).map(()=>'<div class="shimmer h-40"></div>').join('')}
    </div>`,
  analytics: () => `
    <div class="shimmer h-10 mb-4" style="width:40%"></div>
    <div class="grid grid-cols-1 md:grid-cols-4 gap-3 mb-4">
      ${Array.from({length:4}).map(()=>'<div class="shimmer h-24"></div>').join('')}
    </div>
    <div class="shimmer h-80"></div>`,
};
function _skeletonFor(tabId) {
  if (_SKELETONS[tabId]) return _SKELETONS[tabId]();
  // кё°ліё вҖ” header + м№ҙл“ң grid
  return `
    <div class="shimmer h-10 mb-4" style="width:35%"></div>
    <div class="grid grid-cols-1 md:grid-cols-2 gap-3 mb-4">
      ${Array.from({length:4}).map(()=>'<div class="shimmer h-28"></div>').join('')}
    </div>
    <div class="shimmer h-48"></div>`;
}
async function renderView() {
  // лҸҷмӢң л ҢлҚ” л°©м§Җ вҖ” мқҙм „ л ҢлҚ” мҷ„лЈҢ м „ нҳём¶ң мӢң нҒҗмһү
  if (__renderLock) { __renderQueued = true; return; }
  __renderLock = true;
  __renderQueued = false;
  const v = document.getElementById('view');
  v.innerHTML = `<div class="tab-enter">${_skeletonFor(state.view)}</div>`;
  try {
    const fn = VIEWS[state.view] || VIEWS.overview;
    const html = await fn();
    v.innerHTML = `<div class="tab-enter">${html}</div>`;
    const after = AFTER[state.view];
    if (after) await after();
    // мқён„°лһҷнӢ°лёҢ нҡЁкіј
    _animateCounters(v);
    _animateCards(v);
    _translateDOM(v);
  } catch (e) {
    console.error(e);
    v.innerHTML = `<div class="card p-8 empty">${t('л·° л ҢлҚ” мӢӨнҢЁ:')} ${escapeHtml(e.message)}</div>`;
  } finally {
    __renderLock = false;
    // нҒҗм—җ мҢ“мқё л ҢлҚ” мҡ”мІӯ мІҳлҰ¬
    if (__renderQueued) { __renderQueued = false; renderView(); }
  }
}

// мҲ«мһҗ м№ҙмҡҙнҠём—… м• лӢҲл©”мқҙм…ҳ вҖ” data-count мҶҚм„ұмқҙ мһҲлҠ” мҡ”мҶҢ мһҗлҸҷ м Ғмҡ©
function _animateCounters(root) {
  root.querySelectorAll('[data-count]').forEach((el, i) => {
    const target = parseInt(el.dataset.count, 10);
    if (isNaN(target)) return;
    el.classList.add('count-up');
    el.style.animationDelay = (i * 80) + 'ms';
    const duration = 600;
    const start = performance.now();
    const step = (now) => {
      const p = Math.min((now - start) / duration, 1);
      const ease = 1 - Math.pow(1 - p, 3); // ease-out cubic
      el.textContent = Math.round(target * ease);
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  });
}

// м№ҙл“ң мҠӨнғңкұ° мһ…мһҘ м• лӢҲл©”мқҙм…ҳ
function _animateCards(root) {
  // T1 (v2.66.6) вҖ” respect prefers-reduced-motion. Users who set the
  // OS-level reduce-motion preference never get the staggered fade-in
  // (also a perf win on slow devices).
  const reduce = window.matchMedia && window.matchMedia('(prefers-reduced-motion: reduce)').matches;
  if (reduce) return;
  root.querySelectorAll('.card').forEach((el, i) => {
    if (i > 10) return; // м„ұлҠҘ: мІҳмқҢ 10к°ңл§Ң м• лӢҲл©”мқҙм…ҳ
    el.classList.add('card-animate');
    el.style.animationDelay = (i * 40) + 'ms';
  });
  // н”„лЎңк·ёл ҲмҠӨ л°” + мҠӨмҪ”м–ҙ л§Ғ м• лӢҲл©”мқҙм…ҳ
  setTimeout(() => {
    root.querySelectorAll('[data-bar]').forEach(el => {
      el.style.width = el.dataset.bar + '%';
    });
    root.querySelectorAll('[data-ring]').forEach(el => {
      const target = parseInt(el.dataset.ring, 10);
      el.style.transition = '--p 1s cubic-bezier(0.16,1,0.3,1)';
      el.style.setProperty('--p', target);
    });
  }, 100);
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// рҹҶ• мӢ кё°лҠҘ нғӯ + macOS мҠӨнғҖмқј н”ҢлЎңнҢ… м°Ҫ кҙҖлҰ¬мһҗ
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.features = async () => {
  const r = await api('/api/features/list');
  state.data.features = r;
  const all = [...(r.builtin || []), ...(r.dynamic || []).map(f => ({ ...f, isDynamic: true }))];
  // мөңмӢ мҲң
  all.sort((a, b) => (b.released || '').localeCompare(a.released || ''));
  return `
    <div class="mb-4 flex items-start justify-between gap-3 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">рҹҶ• мӢ кё°лҠҘ</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">Anthropic мөңмӢ  л°ңн‘ң В· м№ҙл“ң нҒҙлҰӯ вҶ’ м°ҪмңјлЎң м—ҙлҰј В· м—¬лҹ¬ к°ң лҸҷмӢң В· рҹ”ҙлӢ«кё° рҹҹЎлӮҙлҰ¬кё° рҹҹўнҺјм№ҳкё°</p>
      </div>
      <div class="flex gap-2">
        <button class="btn text-xs" onclick="refreshFeatures()">рҹ“Ў мөңмӢ  м •ліҙ лЎңл”©</button>
        <a class="btn text-xs" href="https://platform.claude.com/docs/en/release-notes/overview" target="_blank" rel="noopener">рҹ“– м „мІҙ лҰҙлҰ¬мҰҲ л…ёнҠё</a>
      </div>
    </div>
    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
      ${all.map(f => `
        <div class="card p-4 hover-lift cursor-pointer" onclick="openFeatureWindow(JSON.parse(this.dataset.f))" data-f="${jsonAttr(f)}">
          <div class="flex items-start justify-between gap-2 mb-2">
            <div class="flex items-center gap-2 min-w-0">
              <div class="text-2xl">${f.icon||'вңЁ'}</div>
              <div class="min-w-0">
                <div class="font-semibold text-sm truncate">${escapeHtml(f.label)}</div>
                ${f.released ? `<div class="text-[10px] text-[var(--text-dim)]">${escapeHtml(f.released)}</div>` : ''}
              </div>
            </div>
            ${f.isDynamic ? '<span class="chip text-[9px]" style="background:rgba(167,139,250,0.18);color:#c4b5fd;">AI</span>' : ''}
          </div>
          <div class="text-xs text-[var(--text-mute)] line-clamp-3">${escapeHtml(f.summary||'')}</div>
        </div>`).join('') || '<div class="empty card" style="grid-column:1/-1;">лҚ°мқҙн„° м—ҶмқҢ</div>'}
    </div>
  `;
};

async function refreshFeatures() {
  showModalLoading('Claude м—җкІҢ мөңмӢ  л°ңн‘ң мЎ°нҡҢ мӨ‘ (~1л¶„)вҖҰ');
  try {
    const r = await api('/api/features/refresh', {
      method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({}),
    });
    closeModal();
    if (r.error) { toast(errMsg(r), 'err'); return; }
    const n = (r.features||[]).length;
    toast(n ? `вңЁ мӢ кё°лҠҘ ${n}к°ң л°ңкІ¬` : 'мғҲлЎңмҡҙ кё°лҠҘ м—ҶмқҢ (мқҙлҜё мөңмӢ )', n?'ok':'info');
    renderView();
  } catch (e) { closeModal(); toast(e.message, 'err'); }
}

// м°Ҫ кҙҖлҰ¬мһҗ
const _winMgr = { zIndex: 1000, openIds: new Set() };
function openFeatureWindow(feat) {
  const winId = 'feat-win-' + feat.id;
  // мқҙлҜё м—ҙл Ө мһҲмңјл©ҙ foreground лЎң
  const existing = document.getElementById(winId);
  if (existing) {
    existing.style.zIndex = ++_winMgr.zIndex;
    existing.classList.remove('feat-win-minimized');
    return;
  }
  const w = document.createElement('div');
  w.id = winId;
  w.className = 'feat-win';
  w.style.zIndex = ++_winMgr.zIndex;
  // мҙҲкё° мң„м№ҳ: нҷ”л©ҙ мӨ‘м•ҷм—җм„ң мҳӨн”„м…Ӣ (м—¬лҹ¬ м°Ҫ лқ„мҡ°л©ҙ мӮҙм§қ кі„лӢЁмӢқ)
  const offset = _winMgr.openIds.size * 30;
  w.style.left = (80 + offset) + 'px';
  w.style.top = (60 + offset) + 'px';
  w.innerHTML = `
    <div class="feat-win-title" data-winid="${winId}">
      <div class="feat-win-lights">
        <button class="feat-light feat-light-close" title="лӢ«кё°" onclick="closeFeatureWindow('${winId}')"></button>
        <button class="feat-light feat-light-min" title="лӮҙлҰ¬кё°" onclick="minimizeFeatureWindow('${winId}')"></button>
        <button class="feat-light feat-light-max" title="нҺјм№ҳкё°" onclick="maximizeFeatureWindow('${winId}')"></button>
      </div>
      <div class="feat-win-title-text">${feat.icon||'вңЁ'} ${escapeHtml(feat.label)}</div>
    </div>
    <div class="feat-win-body">
      <div class="mb-3">
        <div class="text-[10px] uppercase tracking-widest text-[var(--text-dim)] mb-1">${feat.released?'м¶ңмӢңмқј '+escapeHtml(feat.released):''} ${feat.isDynamic?'В· рҹӨ– AI л°ңкІ¬':''}</div>
        <div class="text-sm">${escapeHtml(feat.summary||'')}</div>
      </div>
      <div class="flex gap-2 mb-4 flex-wrap">
        ${feat.launchUrl ? `<a class="btn-primary btn text-xs" href="${escapeHtml(feat.launchUrl)}" target="_blank" rel="noopener">рҹҡҖ мӮ¬мҡ©н•ҳкё°</a>` : ''}
        ${feat.docUrl ? `<a class="btn text-xs" href="${escapeHtml(feat.docUrl)}" target="_blank" rel="noopener">рҹ“– кіөмӢқ л¬ём„ң вҶ—</a>` : ''}
      </div>
      ${feat.id === 'design' ? '<div id="feat-win-design-extras" class="mt-3 pt-3 border-t border-[var(--border)]"><div class="text-xs text-[var(--text-mute)]">лЎңл”© мӨ‘вҖҰ</div></div>' : ''}
      ${feat.isDynamic ? '<div class="card p-3 text-[10px] mt-3" style="background:rgba(167,139,250,0.08);">рҹӨ– AI к°Җ мһҗлҸҷ л°ңкІ¬н•ң н•ӯлӘ© вҖ” кіөмӢқ л¬ём„ң л§ҒнҒ¬лЎң нҷ•мқё к¶ҢмһҘ</div>' : ''}
      <details class="mt-3 text-[10px]">
        <summary class="cursor-pointer text-[var(--text-dim)]">рҹ“Ӣ мӣҗліё JSON</summary>
        <pre class="mono whitespace-pre-wrap bg-[var(--code-bg)] p-2 rounded mt-2">${escapeHtml(JSON.stringify(feat, null, 2))}</pre>
      </details>
    </div>
  `;
  document.body.appendChild(w);
  _winMgr.openIds.add(winId);
  // мҪҳн…җмё  нҒ¬кё°м—җ л§һм¶° мһҗлҸҷ мЎ°м • (DOM л¶ҷмқё л’Ө н•ң н”„л Ҳмһ„ нӣ„)
  requestAnimationFrame(() => _autoSizeWindow(w));
  // м ңлӘ©л°”лЎң л“ңлһҳк·ё
  _makeDraggable(w);
  // нҸ¬м»ӨмҠӨ вҖ” нҒҙлҰӯ мӢң z-index мғҒмҠ№
  w.addEventListener('mousedown', () => { w.style.zIndex = ++_winMgr.zIndex; });

  // Design м°ҪмқҖ лЎңм»¬ export лӘ©лЎқ м¶”к°Җ лЎңл“ң
  if (feat.id === 'design') {
    api('/api/design/exports').then(r => {
      const slot = document.getElementById('feat-win-design-extras');
      if (!slot) return;
      const files = r.files || [];
      slot.innerHTML = `
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] mb-2">рҹ“Ғ лЎңм»¬ export (${files.length})</div>
        ${files.length ? files.slice(0, 10).map(f => `
          <div class="flex justify-between py-1 text-xs">
            <span class="truncate">${escapeHtml(f.name)}</span>
            <span class="text-[var(--text-dim)] ml-2">${fmtRel(f.mtime)}</span>
          </div>`).join('') : '<div class="text-xs text-[var(--text-dim)]">Export лҗң нҢҢмқј м—ҶмқҢ. claude.ai/design вҶ’ Export PDF/PPTX/HTML</div>'}
      `;
    });
  }
}

function closeFeatureWindow(winId) {
  const w = document.getElementById(winId); if (!w) return;
  _detachDragListeners(w);
  w.remove(); _winMgr.openIds.delete(winId);
}
function minimizeFeatureWindow(winId) {
  const w = document.getElementById(winId); if (!w) return;
  w.classList.toggle('feat-win-minimized');
}
function maximizeFeatureWindow(winId) {
  const w = document.getElementById(winId); if (!w) return;
  w.classList.toggle('feat-win-maxed');
  if (w.classList.contains('feat-win-maxed')) {
    w.dataset.prevLeft = w.style.left; w.dataset.prevTop = w.style.top;
    w.dataset.prevW = w.style.width; w.dataset.prevH = w.style.height;
    w.style.left = '24px'; w.style.top = '24px';
    w.style.width = 'calc(100vw - 48px)'; w.style.height = 'calc(100vh - 48px)';
  } else {
    w.style.left = w.dataset.prevLeft || '80px';
    w.style.top = w.dataset.prevTop || '60px';
    w.style.width = w.dataset.prevW || '';
    w.style.height = w.dataset.prevH || '';
  }
}
function _autoSizeWindow(w) {
  const isMobile = window.matchMedia('(max-width: 900px)').matches;
  if (isMobile) {
    // лӘЁл°”мқј: CSS к°Җ мқҙлҜё 100vw лЎң лҚ®м–ҙм“°лҜҖлЎң лҶ’мқҙл§Ң м„Өм •
    w.style.height = 'calc(100vh - 16px)';
    return;
  }
  const body = w.querySelector('.feat-win-body');
  const title = w.querySelector('.feat-win-title');
  if (!body || !title) return;
  const titleH = title.offsetHeight;
  const contentH = body.scrollHeight;
  const desired = titleH + contentH + 8;
  const maxH = window.innerHeight - 80;
  const minH = 180;
  const finalH = Math.max(minH, Math.min(maxH, desired));
  w.style.height = finalH + 'px';
  const rect = w.getBoundingClientRect();
  if (rect.bottom > window.innerHeight - 20) {
    w.style.top = Math.max(20, window.innerHeight - finalH - 20) + 'px';
  }
  if (rect.right > window.innerWidth - 20) {
    w.style.left = Math.max(20, window.innerWidth - rect.width - 20) + 'px';
  }
}

function _makeDraggable(w) {
  const title = w.querySelector('.feat-win-title');
  if (!title) return;
  let startX, startY, origLeft, origTop, dragging = false;
  title.addEventListener('mousedown', e => {
    // Traffic-light click does not initiate drag
    if (e.target.classList.contains('feat-light')) return;
    if (w.classList.contains('feat-win-maxed')) return;
    dragging = true;
    startX = e.clientX; startY = e.clientY;
    origLeft = parseInt(w.style.left) || 0;
    origTop = parseInt(w.style.top) || 0;
    w.style.zIndex = ++_winMgr.zIndex;
    e.preventDefault();
  });
  // v2.47 perf вҖ” keep references so closeFeatureWindow / _wfCloseNodeEditor
  // can detach these document-level listeners and avoid leaking one pair
  // per opened feature window.
  const onMove = (e) => {
    if (!dragging) return;
    w.style.left = (origLeft + (e.clientX - startX)) + 'px';
    w.style.top = Math.max(0, origTop + (e.clientY - startY)) + 'px';
  };
  const onUp = () => { dragging = false; };
  w._dragMoveBound = onMove;
  w._dragUpBound = onUp;
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
}

// v2.47 perf вҖ” shared drag-listener teardown for any window-closer.
function _detachDragListeners(el) {
  if (!el) return;
  if (el._dragMoveBound) {
    document.removeEventListener('mousemove', el._dragMoveBound);
    delete el._dragMoveBound;
  }
  if (el._dragUpBound) {
    document.removeEventListener('mouseup', el._dragUpBound);
    delete el._dragUpBound;
  }
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// рҹҡҖ ONBOARDING вҖ” лӢЁкі„лі„ мІҙнҒ¬лҰ¬мҠӨнҠё (нҳ„мһ¬ м…Ӣм—… мһҗлҸҷ к°җм§Җ)
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.onboarding = async () => {
  const r = await api('/api/guide/onboarding');
  const p = r.progress || { done:0, total:0, percent:0 };
  const steps = r.steps || [];
  const tips = r.tips || [];
  const ringColor = p.percent >= 80 ? '#4ade80' : (p.percent >= 50 ? '#a78bfa' : '#fbbf24');

  return `
    ${viewHeader('рҹҡҖ мӢңмһ‘н•ҳкё°', 'мІҳмқҢ мӮ¬мҡ©мһҗлҘј мң„н•ң лӢЁкі„лі„ мІҙнҒ¬лҰ¬мҠӨнҠё вҖ” нҳ„мһ¬ ~/.claude мғҒнғңлҘј мӢӨмӢңк°„мңјлЎң к°җм§Җн•©лӢҲлӢӨ.', 'onboarding')}

    <div class="card p-5 mb-4 flex items-center gap-5 flex-wrap">
      <div style="--p:${p.percent}; width:84px; height:84px; border-radius:50%;
                  background: conic-gradient(${ringColor} calc(var(--p)*1%), rgba(255,255,255,0.08) 0);
                  display:flex;align-items:center;justify-content:center; position:relative;">
        <div style="position:absolute; inset:8px; border-radius:50%; background:var(--bg-soft);
                    display:flex; flex-direction:column; align-items:center; justify-content:center;">
          <div style="font-size:1.2rem; font-weight:700;">${p.percent}%</div>
          <div style="font-size:0.65rem; color:var(--text-dim);">${p.done}/${p.total}</div>
        </div>
      </div>
      <div class="flex-1 min-w-[220px]">
        <div class="text-lg font-semibold mb-1">${t('м…Ӣм—… м§„н–үлҘ ')}</div>
        <div class="text-sm text-[var(--text-mute)]">
          ${p.percent >= 100
            ? t('мҷ„лЈҢ рҹҺү вҖ” мқҙм ң AI мў…н•© нҸүк°Җ нғӯм—җм„ң н’Ҳм§Ҳ м җмҲҳлҘј л°ӣм•„ліҙм„ёмҡ”.')
            : t('лӮЁмқҖ лӢЁкі„лҘј н•ҳлӮҳм”© мІҙнҒ¬н•ҳл©ҙ Claude Code лҘј лҚ” м•Ҳм „н•ҳкі  мғқмӮ°м ҒмңјлЎң м“ё мҲҳ мһҲмҠөлӢҲлӢӨ.')}
        </div>
        ${tips.length ? `<ul class="mt-2 text-xs text-[var(--text-dim)] space-y-0.5">
          ${tips.map(x => `<li>вҖў ${escapeHtml(x)}</li>`).join('')}
        </ul>` : ''}
      </div>
      <button class="btn text-xs" onclick="renderView()">вҶ» ${t('мғҲлЎңкі м№Ё')}</button>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
      ${steps.map((s, i) => `
        <div class="card p-4 hover-lift ${s.done ? 'onboard-done' : ''}"
             style="border-left: 3px solid ${s.done ? '#4ade80' : 'rgba(167,139,250,0.45)'};">
          <div class="flex items-start justify-between gap-2 mb-2">
            <div class="flex items-center gap-2 min-w-0">
              <div style="width:28px;height:28px;border-radius:50%;display:flex;align-items:center;justify-content:center;
                          background:${s.done ? 'rgba(74,222,128,0.18)' : 'rgba(255,255,255,0.05)'};
                          color:${s.done ? '#4ade80' : 'var(--text-dim)'}; font-size:0.9rem; font-weight:600;">
                ${s.done ? 'вң“' : (i+1)}
              </div>
              <div class="min-w-0">
                <div class="font-semibold text-sm">${escapeHtml(s.title)}</div>
                ${s.detail ? `<div class="text-[10px] text-[var(--text-dim)] mt-0.5">${escapeHtml(s.detail)}</div>` : ''}
              </div>
            </div>
            <span class="chip text-[10px]" style="background:${s.done?'rgba(74,222,128,0.15)':'rgba(251,191,36,0.15)'};color:${s.done?'#4ade80':'#fbbf24'};">
              ${s.done ? t('мҷ„лЈҢ') : t('н•„мҡ”')}
            </span>
          </div>
          <div class="text-xs text-[var(--text-mute)] leading-relaxed mb-2">${escapeHtml(s.desc||'')}</div>
          ${s.hint ? `<div class="text-[11px] text-[var(--text-dim)] mb-2">рҹ’Ў ${escapeHtml(s.hint)}</div>` : ''}
          <div class="flex gap-2 flex-wrap">
            ${s.navigate ? `<button class="btn text-[11px]" onclick="go('${s.navigate}')">вҶ’ ${t('н•ҙлӢ№ нғӯмңјлЎң')}</button>` : ''}
            ${s.doc ? `<a class="btn text-[11px]" href="${s.doc}" target="_blank" rel="noopener">рҹ“– ${t('кіөмӢқ л¬ём„ң')}</a>` : ''}
          </div>
        </div>
      `).join('')}
    </div>
  `;
};

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// рҹ“ҡ GUIDE HUB вҖ” мҷёл¶Җ к°Җмқҙл“ң В· мң мҡ©н•ң нҲҙ В· лІ мҠӨнҠё н”„лһҷнӢ°мҠӨ В· м№ҳнҠёмӢңнҠё
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.guideHub = async () => {
  const r = await api('/api/guide/toolkit');
  state.data.guide = r;
  const sub = state.data.guideSub || 'toolkits';

  const subtabs = [
    { id: 'toolkits',       label: 'рҹ§° мң мҡ©н•ң нҲҙ' },
    { id: 'externalGuides', label: 'рҹ”— мҷёл¶Җ к°Җмқҙл“ң' },
    { id: 'bestPractices',  label: 'рҹ’Ў лІ мҠӨнҠё н”„лһҷнӢ°мҠӨ' },
    { id: 'cheatsheet',     label: 'вҢЁпёҸ м№ҳнҠёмӢңнҠё' },
  ];

  return `
    ${viewHeader('рҹ“ҡ к°Җмқҙл“ң & нҲҙ', 'м„ё лҰ¬мҶҢмҠӨ(everything-claude-code В· claude-code-best-practice В· мң„нӮӨлҸ…мҠӨ н•ңкөӯм–ҙ к°Җмқҙл“ң) лҘј н•ң кіім—җм„ң.', 'guideHub')}

    <div class="flex gap-2 flex-wrap mb-4">
      ${subtabs.map(s => `
        <button class="btn text-xs ${sub===s.id?'btn-active':''}"
                onclick="state.data.guideSub='${s.id}'; renderView();">
          ${t(s.label)}
        </button>`).join('')}
    </div>

    ${sub === 'toolkits'       ? _renderGuideToolkits(r.toolkits || []) : ''}
    ${sub === 'externalGuides' ? _renderGuideExternal(r.toolkits || []) : ''}
    ${sub === 'bestPractices'  ? _renderGuideBestPractices(r.bestPractices || []) : ''}
    ${sub === 'cheatsheet'     ? _renderGuideCheatsheet(r.cheatsheet || {}) : ''}
  `;
};
AFTER.guideHub = () => {
  if ((state.data.guideSub || 'toolkits') !== 'toolkits') return;
  _refreshToolkitManage();
};
async function _refreshToolkitManage() {
  const eccSlot = document.getElementById('tkManage-everything-claude-code');
  const ccbSlot = document.getElementById('tkManage-claude-code-best-practice');
  if (!eccSlot && !ccbSlot) return;
  try {
    const r = await api('/api/toolkit/status');
    if (!r || !r.ok) return;
    if (eccSlot) eccSlot.innerHTML = _renderEccManage(r);
    if (ccbSlot) ccbSlot.innerHTML = _renderCcbManage(r);
  } catch {}
}
function _renderEccManage(r) {
  const e = r.ecc || {};
  const cloned = !!e.marketplaceCloned;
  const nInstalled = (e.installedPlugins || []).length;
  const stateChip = cloned
    ? `<span class="chip chip-ok text-[10px]">вң“ ${t('л§Ҳмј“н”Ңл ҲмқҙмҠӨ м¶”к°ҖлҗЁ')}${e.commit ? ' В· ' + escapeHtml(e.commit) : ''}</span>`
    : `<span class="chip text-[10px]">${t('лҜём„Өм№ҳ')}</span>`;
  const pluginChip = nInstalled > 0
    ? `<span class="chip chip-ok text-[10px]">рҹ”Ң ${nInstalled} ${t('к°ң н”Ңлҹ¬к·ёмқё м„Өм№ҳлҗЁ')}</span>`
    : cloned ? `<span class="chip chip-warn text-[10px]">${t('н”Ңлҹ¬к·ёмқё м„Өм№ҳ н•„мҡ”')}</span>` : '';
  return `
    <div class="flex items-center gap-2 flex-wrap mb-2">
      <div class="text-xs font-semibold text-[var(--text-dim)] uppercase tracking-wider flex-1">${t('лҢҖмӢңліҙл“ңм—җм„ң кҙҖлҰ¬')}</div>
      ${stateChip} ${pluginChip}
    </div>
    <div class="flex items-center gap-2 flex-wrap">
      ${cloned
        ? `<button class="btn text-[12px]" onclick="_eccInstall(this)" ${!r.gitAvailable?'disabled':''}>рҹ”„ ${t('м—…лҚ°мқҙнҠё')}</button>
           ${nInstalled > 0
             ? `<button class="btn-danger btn text-[12px]" onclick="_eccInstallPlugin(this, 'uninstall')">рҹ—‘ ${t('н”Ңлҹ¬к·ёмқё м ңкұ°')}</button>`
             : `<button class="btn-primary btn text-[12px]" onclick="_eccInstallPlugin(this, 'install')">рҹ”Ң ${t('н”Ңлҹ¬к·ёмқё м„Өм№ҳ')}</button>`}
           <button class="btn-danger btn text-[12px]" onclick="_eccUninstall(this)">${t('л§Ҳмј“ м ңкұ°')}</button>`
        : `<button class="btn-primary btn text-[12px]" onclick="_eccInstall(this)" ${!r.gitAvailable?'disabled':''}>в¬ҮпёҺ ${t('л§Ҳмј“н”Ңл ҲмқҙмҠӨ м¶”к°Җ')}</button>`}
    </div>
    ${cloned ? `<div class="text-[11px] text-[var(--text-dim)] mt-1.5">рҹ“Ӯ ${escapeHtml(e.installDir || '')}</div>` : ''}`;
}
function _renderCcbManage(r) {
  const c = r.ccb || {};
  const cloned = !!c.cloned;
  const stateChip = cloned
    ? `<span class="chip chip-ok text-[10px]">вң“ ${t('м„Өм№ҳлҗЁ')}${c.commit ? ' В· ' + escapeHtml(c.commit) : ''}</span>`
    : `<span class="chip text-[10px]">${t('лҜём„Өм№ҳ')}</span>`;
  return `
    <div class="flex items-center gap-2 flex-wrap mb-2">
      <div class="text-xs font-semibold text-[var(--text-dim)] uppercase tracking-wider flex-1">${t('лҢҖмӢңліҙл“ңм—җм„ң кҙҖлҰ¬')}</div>
      ${stateChip}
    </div>
    <div class="flex items-center gap-2 flex-wrap">
      ${cloned
        ? `<button class="btn text-[12px]" onclick="_ccbInstall(this)" ${!r.gitAvailable?'disabled':''}>рҹ”„ ${t('м—…лҚ°мқҙнҠё')}</button>
           <button class="btn text-[12px]" onclick="_ccbOpen(this)">рҹ“Ӯ ${t('нҸҙлҚ” м—ҙкё°')}</button>
           <button class="btn-danger btn text-[12px]" onclick="_ccbUninstall(this)">рҹ—‘ ${t('м ңкұ°')}</button>`
        : `<button class="btn-primary btn text-[12px]" onclick="_ccbInstall(this)" ${!r.gitAvailable?'disabled':''}>в¬ҮпёҺ ${t('л ҲнҸ¬ лӮҙл Өл°ӣкё°')}</button>`}
    </div>
    <div class="text-[11px] text-[var(--text-dim)] mt-1.5">рҹ“Ӯ ${escapeHtml(c.defaultDir || '')}</div>`;
}
async function _eccInstall(btn) {
  btn.disabled = true; const orig = btn.textContent; btn.textContent = 'вҸі ' + t('м„Өм№ҳ мӨ‘...');
  try {
    const r = await api('/api/toolkit/ecc/install', { method: 'POST', body: {} });
    if (r.ok) { toast(r.updated ? t('ECC л§Ҳмј“ м—…лҚ°мқҙнҠё мҷ„лЈҢ') : t('ECC л§Ҳмј“ м¶”к°Җ мҷ„лЈҢ'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('м„Өм№ҳ мӢӨнҢЁ'), 'err'); btn.disabled = false; btn.textContent = orig; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _eccInstallPlugin(btn, action) {
  const url = action === 'install' ? '/api/toolkit/ecc/install-plugin' : '/api/toolkit/ecc/uninstall-plugin';
  const waitText = action === 'install' ? t('н”Ңлҹ¬к·ёмқё м„Өм№ҳ мӨ‘...') : t('н”Ңлҹ¬к·ёмқё м ңкұ° мӨ‘...');
  btn.disabled = true; const orig = btn.textContent; btn.textContent = 'вҸі ' + waitText;
  try {
    const r = await api(url, { method: 'POST', body: { scope: 'user' } });
    if (r.ok) {
      // v2.33.5 вҖ” Plugins / Marketplaces нғӯ мәҗмӢң л¬ҙнҡЁнҷ” вҶ’ мқҙлҸҷ мӢң мҰүмӢң мөңмӢ  н‘ңмӢң
      _apiCacheInvalidate('/api/plugins');
      _apiCacheInvalidate('/api/marketplaces');
      toast(action === 'install' ? t('н”Ңлҹ¬к·ёмқё м„Өм№ҳ мҷ„лЈҢ') + ' вҖ” ' + t('н”Ңлҹ¬к·ёмқё нғӯм—җм„ң нҷ•мқё') : t('н”Ңлҹ¬к·ёмқё м ңкұ° мҷ„лЈҢ'), 'ok');
      _refreshToolkitManage();
    } else {
      toast(r.error || t('мӢӨнҢЁ'), 'err');
      btn.disabled = false; btn.textContent = orig;
    }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _eccUninstall(btn) {
  if (!confirm(t('ECC л§Ҳмј“н”Ңл ҲмқҙмҠӨ л””л үн„°лҰ¬мҷҖ л Ҳм§ҖмҠӨнҠёлҰ¬ entry лҘј м ңкұ°н•©лӢҲлӢӨ. кі„мҶҚн• к№Ңмҡ”?'))) return;
  btn.disabled = true;
  try {
    const r = await api('/api/toolkit/ecc/uninstall', { method: 'POST', body: {} });
    if (r.ok) {
      _apiCacheInvalidate('/api/plugins');
      _apiCacheInvalidate('/api/marketplaces');
      toast(t('ECC л§Ҳмј“ м ңкұ° мҷ„лЈҢ') + (r.note ? ' В· ' + r.note : ''), 'ok');
      _refreshToolkitManage();
    }
    else { toast(r.error || t('м ңкұ° мӢӨнҢЁ'), 'err'); btn.disabled = false; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; }
}
async function _ccbInstall(btn) {
  btn.disabled = true; const orig = btn.textContent; btn.textContent = 'вҸі ' + t('лӮҙл Өл°ӣлҠ” мӨ‘...');
  try {
    const r = await api('/api/toolkit/ccb/install', { method: 'POST', body: {} });
    if (r.ok) { toast(r.updated ? t('CCB м—…лҚ°мқҙнҠё мҷ„лЈҢ') : t('CCB лӮҙл Өл°ӣкё° мҷ„лЈҢ'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('м„Өм№ҳ мӢӨнҢЁ'), 'err'); btn.disabled = false; btn.textContent = orig; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; btn.textContent = orig; }
}
async function _ccbUninstall(btn) {
  if (!confirm(t('CCB л””л үн„°лҰ¬лҘј мҷ„м „нһҲ м ңкұ°н•©лӢҲлӢӨ. кі„мҶҚн• к№Ңмҡ”?'))) return;
  btn.disabled = true;
  try {
    const r = await api('/api/toolkit/ccb/uninstall', { method: 'POST', body: {} });
    if (r.ok) { toast(t('CCB м ңкұ° мҷ„лЈҢ'), 'ok'); _refreshToolkitManage(); }
    else { toast(r.error || t('м ңкұ° мӢӨнҢЁ'), 'err'); btn.disabled = false; }
  } catch (e) { toast(String(e), 'err'); btn.disabled = false; }
}
async function _ccbOpen() {
  try {
    const r = await api('/api/toolkit/ccb/open', { method: 'POST', body: {} });
    if (!r.ok) toast(r.error || t('нҸҙлҚ” м—ҙкё° мӢӨнҢЁ'), 'err');
  } catch (e) { toast(String(e), 'err'); }
}

function _renderGuideToolkits(list) {
  if (!list.length) return `<div class="card p-8 empty">${t('лҚ°мқҙн„° м—ҶмқҢ')}</div>`;
  return `
    <div class="grid grid-cols-1 gap-4">
      ${list.map(tk => `
        <div class="card p-5">
          <div class="flex items-start justify-between gap-3 flex-wrap mb-3">
            <div class="min-w-0 flex-1">
              <div class="flex items-center gap-2 mb-1">
                <h3 class="text-lg font-semibold">${escapeHtml(tk.title)}</h3>
                ${tk.stars ? `<span class="chip text-[10px]" style="background:rgba(250,204,21,0.15);color:#fbbf24;">вӯҗ ${escapeHtml(tk.stars)}</span>` : ''}
                ${tk.license ? `<span class="chip text-[10px]">${escapeHtml(tk.license)}</span>` : ''}
              </div>
              <div class="text-sm text-[var(--text-mute)] mb-1">${escapeHtml(tk.subtitle||'')}</div>
              <div class="text-[11px] text-[var(--text-dim)]">${t('м ңмһ‘')}: ${escapeHtml(tk.author||'')}</div>
            </div>
            <a class="btn text-xs" href="${escapeHtml(tk.repo)}" target="_blank" rel="noopener">вҶ— ${t('лҰ¬нҸ¬ м—ҙкё°')}</a>
          </div>

          ${tk.highlights?.length ? `
            <div class="mb-3">
              <div class="text-xs font-semibold text-[var(--text-dim)] mb-1 uppercase tracking-wider">${t('н•ҳмқҙлқјмқҙнҠё')}</div>
              <ul class="text-sm text-[var(--text-mute)] space-y-1">
                ${tk.highlights.map(h => `<li>вҖў ${escapeHtml(h)}</li>`).join('')}
              </ul>
            </div>` : ''}

          <div id="tkManage-${escapeHtml(tk.id)}" class="mb-3"></div>

          ${tk.install?.length ? `
            <div class="mb-3">
              <div class="text-xs font-semibold text-[var(--text-dim)] mb-1 uppercase tracking-wider">${t('м„Өм№ҳ & мӮ¬мҡ©')}</div>
              <div class="space-y-2">
                ${tk.install.map(inst => `
                  <div>
                    <div class="text-[11px] text-[var(--text-dim)] mb-0.5">${escapeHtml(inst.label)}</div>
                    <div class="flex items-center gap-2">
                      <code class="code-terminal flex-1 min-w-0 px-2 py-1.5 rounded text-xs font-mono"
                            style="word-break:break-all;">${escapeHtml(inst.code)}</code>
                      <button class="btn text-[11px]" onclick="_copyToClipboard(this, ${JSON.stringify(inst.code).replace(/"/g,'&quot;')})">рҹ“Ӣ ${t('ліөмӮ¬')}</button>
                    </div>
                  </div>`).join('')}
              </div>
            </div>` : ''}

          ${tk.categories?.length ? `
            <div class="grid grid-cols-1 md:grid-cols-2 gap-3">
              ${tk.categories.map(c => `
                <div style="background:rgba(255,255,255,0.02); border:1px solid var(--border); border-radius:8px; padding:10px 12px;">
                  <div class="text-xs font-semibold mb-1.5">${escapeHtml(c.name)}</div>
                  <div class="flex flex-wrap gap-1">
                    ${(c.items||[]).map(it => `<span class="chip chip-violet text-[10px]" style="background:rgba(167,139,250,0.12); color:#c4b5fd;">${escapeHtml(it)}</span>`).join('')}
                  </div>
                </div>`).join('')}
            </div>` : ''}
        </div>`).join('')}
    </div>
  `;
}

function _renderGuideExternal(list) {
  return `
    <div class="grid grid-cols-1 md:grid-cols-3 gap-3">
      ${list.map(tk => `
        <a class="card p-4 hover-lift block no-underline" href="${escapeHtml(tk.repo)}" target="_blank" rel="noopener"
           style="text-decoration:none; color:inherit;">
          <div class="text-3xl mb-2">${tk.id==='wikidocs-claude-code-guide'?'рҹ“–':(tk.id==='claude-code-best-practice'?'рҹҺҜ':'рҹ§°')}</div>
          <div class="font-semibold text-sm mb-1">${escapeHtml(tk.title)}</div>
          <div class="text-xs text-[var(--text-mute)] mb-2 line-clamp-2">${escapeHtml(tk.subtitle||'')}</div>
          <div class="text-[11px] text-[var(--text-dim)]">${t('л°”лЎңк°Җкё°')} вҶ—</div>
        </a>`).join('')}
    </div>
    <div class="card p-4 mt-4">
      <div class="text-sm font-semibold mb-2">рҹҺ“ ${t('м¶”мІң н•ҷмҠө кІҪлЎң')}</div>
      <ol class="text-sm text-[var(--text-mute)] space-y-1 list-decimal pl-5">
        <li>${t('мң„нӮӨлҸ…мҠӨ н•ңкөӯм–ҙ к°Җмқҙл“ң кё°мҙҲ 7к°• вҶ’ к°ңл°ң 17к°• мҲңмңјлЎң н•ҷмҠө')}</li>
        <li>${t('best-practice л ҲнҸ¬м—җм„ң м°ҪмӢңмһҗ(Boris Cherny) мӣҢнҒ¬н”ҢлЎң мҳҒмғҒ мӢңмІӯ')}</li>
        <li>${t('everything-claude-code н”Ңлҹ¬к·ёмқё м„Өм№ҳ вҶ’ мӢӨм „ кё°лҠҘ нҷ•ліҙ')}</li>
        <li>${t('мӢңмһ‘н•ҳкё° нғӯмңјлЎң лҸҢм•„мҷҖ мІҙнҒ¬лҰ¬мҠӨнҠё мҷ„лЈҢ')}</li>
      </ol>
    </div>
  `;
}

function _renderGuideBestPractices(list) {
  if (!list.length) return `<div class="card p-8 empty">${t('лҚ°мқҙн„° м—ҶмқҢ')}</div>`;
  return `
    <div class="space-y-3">
      ${list.map(bp => `
        <div class="card p-5">
          <div class="flex items-start justify-between gap-3 mb-2">
            <div>
              <div class="text-lg font-semibold">${escapeHtml(bp.title)}</div>
              <div class="text-sm text-[var(--text-mute)] mt-1">${escapeHtml(bp.desc||'')}</div>
            </div>
          </div>
          <div class="grid grid-cols-1 md:grid-cols-2 gap-2 mt-3">
            ${(bp.steps||[]).map((st, i) => `
              <div style="background:rgba(255,255,255,0.02); border:1px solid var(--border); border-radius:8px; padding:10px 12px;">
                <div class="flex items-center gap-2 mb-1">
                  <span style="width:22px;height:22px;border-radius:50%;display:inline-flex;align-items:center;justify-content:center;
                               background:rgba(167,139,250,0.18);color:#c4b5fd; font-size:0.7rem; font-weight:700;">${i+1}</span>
                  <span class="text-sm font-semibold">${escapeHtml(st.label)}</span>
                </div>
                <div class="text-xs text-[var(--text-mute)] leading-relaxed">${escapeHtml(st.tip)}</div>
              </div>`).join('')}
          </div>
        </div>`).join('')}
    </div>
  `;
}

function _renderGuideCheatsheet(cs) {
  const cmds = cs.commands || [];
  const keys = cs.keys || [];
  return `
    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="card p-4">
        <div class="flex items-center justify-between mb-3">
          <div class="font-semibold">/ ${t('лӮҙмһҘ мҠ¬лһҳмӢң лӘ…л №м–ҙ')}</div>
          <div class="text-[11px] text-[var(--text-dim)]">${cmds.length} ${t('к°ң')}</div>
        </div>
        <div class="space-y-1.5">
          ${cmds.map(c => `
            <div class="flex items-start gap-3 py-1.5" style="border-bottom:1px dashed var(--border);">
              <code class="font-mono text-xs px-2 py-0.5 rounded flex-shrink-0"
                    style="background:rgba(167,139,250,0.12); color:#c4b5fd; min-width:130px;">${escapeHtml(c.cmd)}</code>
              <div class="text-xs text-[var(--text-mute)] flex-1">${escapeHtml(c.desc)}</div>
              <button class="btn text-[10px] flex-shrink-0" onclick="_copyToClipboard(this, ${JSON.stringify(c.cmd).replace(/"/g,'&quot;')})">рҹ“Ӣ</button>
            </div>`).join('')}
        </div>
      </div>

      <div class="card p-4">
        <div class="flex items-center justify-between mb-3">
          <div class="font-semibold">вҢЁпёҸ ${t('нӮӨліҙл“ң лӢЁм¶•нӮӨ')}</div>
          <div class="text-[11px] text-[var(--text-dim)]">${keys.length} ${t('к°ң')}</div>
        </div>
        <div class="space-y-1.5">
          ${keys.map(k => `
            <div class="flex items-start gap-3 py-1.5" style="border-bottom:1px dashed var(--border);">
              <kbd class="font-mono text-xs px-2 py-0.5 rounded flex-shrink-0"
                   style="background:rgba(74,222,128,0.12); color:#86efac; min-width:110px; border:1px solid rgba(74,222,128,0.25);">${escapeHtml(k.key)}</kbd>
              <div class="text-xs text-[var(--text-mute)] flex-1">${escapeHtml(k.desc)}</div>
            </div>`).join('')}
        </div>
      </div>
    </div>
  `;
}

function _copyToClipboard(btn, text) {
  try {
    navigator.clipboard.writeText(text).then(() => {
      const orig = btn.innerHTML;
      btn.innerHTML = 'вң“ ' + t('ліөмӮ¬лҗЁ');
      setTimeout(() => { btn.innerHTML = orig; }, 1400);
      toast(t('нҒҙлҰҪліҙл“ңм—җ ліөмӮ¬лҗЁ'), 'ok');
    });
  } catch (e) {
    toast(t('ліөмӮ¬ мӢӨнҢЁ'), 'err');
  }
}

