      <button class="btn text-xs" onclick="_wfQuickAction('deep-interview')" title="${t('мҶҢнҒ¬лқјн…ҢмҠӨмӢқ лӘ…нҷ•нҷ” вҶ’ м„Өкі„ л¬ём„ң')}">рҹ§җ Deep Interview</button>
