          <button class="btn text-xs" onclick="_wfExport()" title="${t('JSON нҢҢмқјлЎң лӮҙліҙлӮҙкё°')}" aria-label="${t('лӮҙліҙлӮҙкё°')}">рҹ“Ұ ${t('лӮҙліҙлӮҙкё°')}</button>
