// AA3 (v2.66.13) вҖ” debounced auto-save. Every keystroke schedules a
// silent save 800 ms later. Closing the window mid-edit no longer
// loses changes. Saves only when the editor is for an existing node;
// new-node drafts must still be explicitly saved (since adding a node
// is an explicit user intent).
function _wfDraftSet(winId, field, value) {
  const w = document.getElementById(winId);
  if (!w) return;
  w._wfDraft[field] = value;
  _wfScheduleAutoSave(winId);
}
function _wfDraftSetData(winId, field, value) {
  const w = document.getElementById(winId);
  if (!w) return;
  w._wfDraft.data = w._wfDraft.data || {};
  w._wfDraft.data[field] = value;
  _wfScheduleAutoSave(winId);
}

function _wfScheduleAutoSave(winId) {
  const w = document.getElementById(winId);
  if (!w || w._wfIsNew) return;            // explicit save for new nodes
  if (w._wfAutoSaveTimer) clearTimeout(w._wfAutoSaveTimer);
  w._wfAutoSaveTimer = setTimeout(() => {
    w._wfAutoSaveTimer = null;
    if (!document.body.contains(w)) return; // window closed in flight
    try {
      _wfSaveNodeEditorSilent(winId);
    } catch (e) { /* silent вҖ” explicit save will surface errors */ }
  }, 800);
}

// Variant of _wfSaveNodeEditor that skips the close + toast вҖ” used by
// auto-save so the user keeps typing without window flicker.
function _wfSaveNodeEditorSilent(winId) {
  const w = document.getElementById(winId);
  if (!w || !__wf.current) return;
  const draft = w._wfDraft;
  if (!draft.type) return;        // can't save a typeless node
  // Replace existing node in the workflow array
  const idx = __wf.current.nodes.findIndex(x => x.id === draft.id);
  if (idx < 0) return;             // not in canvas yet
  __wf.current.nodes[idx] = JSON.parse(JSON.stringify(draft));
  __wf.dirty = true;
  // Trigger re-render of just that node + workflow-level save.
  if (typeof _wfRenderCanvas === 'function') _wfRenderCanvas();
  if (typeof _wfSave === 'function') _wfSave({ silent: true }).catch(() => {});
}

function _wfSaveNodeEditor(winId) {
  const w = document.getElementById(winId);
  if (!w || !__wf.current) return;
  const draft = w._wfDraft;
  if (!draft.type) { toast(t('м№ҙн…Ңкі лҰ¬лҘј м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }
  if (w._wfIsNew) {
    // мә”лІ„мҠӨ мӨ‘м•ҷм—җ мўҢн‘ң кі„мӮ°
    const view = __wf.current.viewport || { panX:0, panY:0, zoom:1 };
    const host = document.getElementById('wfCanvasHost');
    const rect = host ? host.getBoundingClientRect() : { width:600, height:400 };
    draft.x = Math.round((rect.width/2 - (view.panX||0)) / (view.zoom||1) - WF_NODE_W/2);
    draft.y = Math.round((rect.height/2 - (view.panY||0)) / (view.zoom||1) - WF_NODE_H/2);
    __wf.current.nodes.push(draft);
    __wf.selectedNodeId = draft.id;
    toast(t('л…ёл“ң м¶”к°ҖлҗЁ'), 'ok');
  } else {
    const idx = __wf.current.nodes.findIndex(n => n.id === draft.id);
    if (idx >= 0) __wf.current.nodes[idx] = draft;
    toast(t('м ҖмһҘлҗЁ'), 'ok');
  }
  __wf.dirty = true;
  __wf._inspectorDirty = true;
  _wfRenderCanvas(); _wfRenderInspector(); _wfUpdateToolbar();
  _wfCloseNodeEditor(winId);
}

function _wfDeleteFromEditor(winId) {
  const w = document.getElementById(winId);
  if (!w || !__wf.current) return;
  const nid = w._wfDraft.id;
  __wf.current.nodes = __wf.current.nodes.filter(n => n.id !== nid);
  __wf.current.edges = __wf.current.edges.filter(e => e.from !== nid && e.to !== nid);
  if (__wf.selectedNodeId === nid) __wf.selectedNodeId = null;
  __wf.dirty = true;
  _wfRenderCanvas(); _wfRenderInspector(); _wfUpdateToolbar();
  _wfCloseNodeEditor(winId);
  toast(t('мӮӯм ңлҗЁ'), 'ok');
}

function _wfNodeSetData(nid, field, value) {
  if (!__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  n.data = n.data || {};
  n.data[field] = value;
  __wf.dirty = true;
  // v2.44.0 вҖ” inspector data changed; the early-exit guard must let the
  // next render through. Most _wfNodeSetData callers do NOT immediately
  // re-render the inspector (they mutate via oninput on an already-mounted
  // input), but a handful do вҖ” guard them by marking dirty here.
  __wf._inspectorDirty = true;
  _wfUpdateToolbar();
  if (field === 'assignee' || field === 'multiAssignee') _wfRenderCanvas();
}

// v2.44.1 вҖ” multi-assignee parallel fan-out helpers.
// Storage shape: node.data.multiAssignee = ['claude:opus', 'openai:gpt-4.1', вҖҰ]
// Back-compat: if the array has 0 or 1 entries, the single `assignee` field is
// authoritative. When length >= 2, ProviderRegistry.execute_parallel races them
// and returns the first ok response.
function _wfMultiAssigneeRows(n) {
  const d = n.data || {};
  const arr = Array.isArray(d.multiAssignee) ? d.multiAssignee.slice() : [];
  // Row 0 is always the canonical single-assignee dropdown so empty/legacy
  // workflows render exactly as before.
  if (arr.length === 0) return [d.assignee || 'sonnet-4.6'];
  return arr;
}
function _wfMultiAssigneeSet(nid, idx, val) {
  if (!__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  n.data = n.data || {};
  const rows = _wfMultiAssigneeRows(n);
  rows[idx] = val;
  // Drop empties + dedupe preserving order.
  const seen = new Set();
  const cleaned = [];
  for (const r of rows) {
    const v = (r || '').trim();
    if (!v || seen.has(v)) continue;
    seen.add(v);
    cleaned.push(v);
  }
  n.data.assignee = cleaned[0] || '';
  n.data.multiAssignee = cleaned.length >= 2 ? cleaned : [];
  __wf.dirty = true;
  __wf._inspectorDirty = true;
  _wfUpdateToolbar();
  _wfRenderCanvas();
  _wfRenderInspector();
}
function _wfMultiAssigneeAdd(nid) {
  if (!__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  n.data = n.data || {};
  const rows = _wfMultiAssigneeRows(n);
  if (rows.length >= 8) return; // matches execute_parallel pool cap
  // Pick a default that isn't already present so the new row is meaningful.
  const candidates = ['claude:opus', 'claude:sonnet', 'claude:haiku',
                       'openai:gpt-4.1', 'gemini:2.5-pro'];
  const already = new Set(rows);
  const pick = candidates.find(c => !already.has(c)) || 'claude:opus';
  rows.push(pick);
  n.data.assignee = rows[0] || '';
  n.data.multiAssignee = rows.length >= 2 ? rows : [];
  __wf.dirty = true;
  __wf._inspectorDirty = true;
  _wfUpdateToolbar();
  _wfRenderCanvas();
  _wfRenderInspector();
}
function _wfMultiAssigneeRemove(nid, idx) {
  if (!__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  n.data = n.data || {};
  const rows = _wfMultiAssigneeRows(n);
  if (rows.length <= 1) return; // never remove the last one
  rows.splice(idx, 1);
  n.data.assignee = rows[0] || '';
  n.data.multiAssignee = rows.length >= 2 ? rows : [];
  __wf.dirty = true;
  __wf._inspectorDirty = true;
  _wfUpdateToolbar();
  _wfRenderCanvas();
  _wfRenderInspector();
}
function _wfMultiAssigneeRowHtml(nid, idx, val, removable) {
  // The inline `__custom__` handler mirrors the existing single-assignee
  // dropdown вҖ” picking "м§Ғм ‘ мһ…л Ҙ..." prompts for a custom provider:model.
  const safe = escapeHtml(val || 'sonnet-4.6');
  const removeBtn = removable
    ? `<button class="btn text-xs px-2" title="${t('н–ү м ңкұ°')}" onclick="_wfMultiAssigneeRemove('${nid}', ${idx})">вҲ’</button>`
    : '';
  return `
    <div class="flex gap-1 items-center mt-1">
      <select class="input flex-1" onchange="if(this.value==='__custom__'){const v=prompt('provider:model мһ…л Ҙ (мҳҲ: openai:gpt-4.1)');if(v){_wfMultiAssigneeSet('${nid}', ${idx}, v);}else{this.value='${safe}';}}else{_wfMultiAssigneeSet('${nid}', ${idx}, this.value);}">
        ${_wfAssigneeOptions(val || 'sonnet-4.6')}
      </select>
      ${removeBtn}
    </div>
  `;
}

// в”Җв”Җв”Җ м ҖмһҘ / мӢӨн–ү / spawn в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _wfSave() {
  if (!__wf.current) return;
  const body = {
    id: __wf.current.id,
    name: __wf.current.name,
    description: __wf.current.description,
    nodes: __wf.current.nodes,
    edges: __wf.current.edges,
    viewport: __wf.current.viewport,
  };
  const r = await api('/api/workflows/save', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify(body),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  __wf.dirty = false;
  // v2.44.0 вҖ” invalidate cached webhook secret for this wf so the next
  // inspector render fetches a fresh value if it was rotated server-side.
  if (__wf._webhookSecretCache && __wf.current && __wf.current.id) {
    delete __wf._webhookSecretCache[__wf.current.id];
  }
  toast(t('м ҖмһҘлҗЁ'), 'ok');
  // лӘ©лЎқ refresh
  const list = await api('/api/workflows/list');
  __wf.workflows = list.workflows || [];
  _wfRenderList();
  _wfUpdateToolbar();
}

async function _wfExport() {
  if (!__wf.current) { toast(t('мӣҢнҒ¬н”ҢлЎңмҡ°лҘј лЁјм Җ м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }
  try {
    const r = await api('/api/workflows/export', {
      method: 'POST', headers: { 'Content-Type':'application/json' },
      body: JSON.stringify({ id: __wf.current.id }),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    const payload = r.export || r;
    const blob = new Blob([JSON.stringify(payload, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = (__wf.current.name || 'workflow').replace(/[^a-zA-Z0-9к°Җ-нһЈ_-]/g, '_') + '.json';
    document.body.appendChild(a);
    a.click();
    a.remove();
    URL.revokeObjectURL(url);
    toast(t('лӮҙліҙлӮҙкё° мҷ„лЈҢ'), 'ok');
  } catch (e) { toast(t('лӮҙліҙлӮҙкё° мӢӨнҢЁ'), 'err'); }
}

async function _wfImport(event) {
  const file = event.target.files && event.target.files[0];
  event.target.value = '';
  if (!file) return;
  try {
    const text = await file.text();
    const json = JSON.parse(text);
    const r = await api('/api/workflows/import', {
      method: 'POST', headers: { 'Content-Type':'application/json' },
      body: JSON.stringify(json),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    toast(t('к°Җм ёмҳӨкё° мҷ„лЈҢ'), 'ok');
    const list = await api('/api/workflows/list');
    __wf.workflows = list.workflows || [];
    if (r.id) await _wfOpen(r.id);
    _wfRenderList();
    _wfUpdateToolbar();
  } catch (e) { toast(t('JSON нҢҢмӢұ мӢӨнҢЁ'), 'err'); }
}

// v2.33.7 вҖ” мӢӨм ң LLM/HTTP нҳём¶ң м—Ҷмқҙ DAG кІҖмҰқ + мӢӨн–ү мҲңм„ң + лҜён•ҙкІ° ліҖмҲҳл§Ң кі„мӮ°
async function _wfDryRun() {
  if (!__wf.current) { toast(t('мӣҢнҒ¬н”ҢлЎңмҡ°лҘј м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }
  if (__wf.dirty) await _wfSave();
  const r = await api('/api/workflows/dry-run', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify({ id: __wf.current.id }),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  const levels = (r.levels || []).map((lv, i) => `<div class="text-[11px]"><span class="chip text-[9px]">L${i}</span> ${lv.map(id=>`<span class="chip text-[10px] mono">${escapeHtml(id)}</span>`).join(' ')}</div>`).join('');
  const planRows = (r.plan || []).map(p => `
    <tr>
      <td class="mono text-[11px]">${escapeHtml(p.id)}</td>
      <td class="text-[11px]">${escapeHtml(p.kind)}</td>
      <td class="text-[11px]">${escapeHtml(p.label)}</td>
      <td class="text-[11px] mono">${escapeHtml(p.assignee||'')}</td>
      <td class="text-[11px]">${p.willRun ? '<span class="chip chip-ok text-[9px]">run</span>' : '<span class="chip text-[9px]">skip</span>'}</td>
    </tr>`).join('');
  const unresolvedRows = (r.unresolved || []).map(u => `<li class="text-[11px]"><span class="chip chip-warn text-[9px]">${t('лҜён•ҙкІ°')}</span> <code class="mono">${escapeHtml(u.nodeId)}</code> вҶ’ <code class="mono">{{${escapeHtml(u.key)}}}</code></li>`).join('');
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">${t('л“ңлқјмқҙлҹ°')}</div>
        <h2 class="text-lg font-bold">рҹ§Ә ${t('мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨн–ү кі„нҡҚ')}</h2>
        <div class="text-[11px] text-[var(--text-mute)] mt-1">${r.nodeCount} ${t('л…ёл“ң')} В· ${r.edgeCount} ${t('м—Јм§Җ')} В· ${(r.levels||[]).length} ${t('лі‘л ¬ л ҲлІЁ')}</div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div class="p-5" style="max-height:72vh;overflow-y:auto;">
      <div class="mb-4">
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('лі‘л ¬ л ҲлІЁ')}</div>
        ${levels || '<div class="text-[11px] text-[var(--text-dim)]">вҖ”</div>'}
      </div>
      ${unresolvedRows ? `
        <div class="mb-4">
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">вҡ пёҸ ${t('лҜён•ҙкІ° ліҖмҲҳ')} (${(r.unresolved||[]).length})</div>
          <ul class="list-disc pl-5 space-y-1">${unresolvedRows}</ul>
        </div>` : `<div class="chip chip-ok text-[10px] mb-4">${t('ліҖмҲҳ м „л¶Җ н•ҙкІ°лҗЁ')}</div>`}
      <div class="mb-2">
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('мӢӨн–ү мҲңм„ң')}</div>
        <table class="data text-xs">
          <thead><tr><th>id</th><th>kind</th><th>label</th><th>assignee</th><th>вҖ”</th></tr></thead>
          <tbody>${planRows}</tbody>
        </table>
      </div>
    </div>
  `);
}
window._wfDryRun = _wfDryRun;

// CC3 (v2.66.14) вҖ” n8n-style toggle. The same primary button starts an
// execution when idle, or sends a cooperative cancel when a run is in
// flight. The button label / class flips in `_wfSetRunButtonState`.
async function _wfRunOrCancel() {
  if (__wf.runId) {
    await _wfCancelRun();
  } else {
    await _wfRun();
  }
}

async function _wfCancelRun() {
  if (!__wf.runId) return;
  const rid = __wf.runId;
  const r = await api('/api/workflows/run-cancel', {
    method: 'POST', headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ runId: rid }),
  });
  if (r.ok) {
    toast(t('мӢӨн–ү м·ЁмҶҢ мҡ”мІӯлҗЁ'), 'warn');
  } else {
    toast(errMsg(r) || t('м·ЁмҶҢ мӢӨнҢЁ'), 'err');
  }
}

function _wfSetRunButtonState(running) {
  const btn = document.getElementById('wfRunBtn');
  if (!btn) return;
  if (running) {
    btn.innerHTML = 'в–  ' + t('мӢӨн–ү мӨ‘лӢЁ');
    btn.title = t('нҳ„мһ¬ мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨн–үмқ„ м•Ҳм „н•ҳкІҢ мӨ‘лӢЁн•©лӢҲлӢӨ (м§„н–ү мӨ‘мқё л…ёл“ңлҠ” л§Ҳл¬ҙлҰ¬)');
    btn.setAttribute('aria-label', t('мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨн–ү мӨ‘лӢЁ'));
    btn.classList.remove('btn-primary');
    btn.classList.add('btn-danger');
  } else {
    btn.innerHTML = 'в–¶ ' + t('мӢӨн–ү');
    btn.title = t('мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨн–ү');
    btn.setAttribute('aria-label', t('мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨн–ү'));
    btn.classList.remove('btn-danger');
    btn.classList.add('btn-primary');
  }
}

async function _wfRun() {
  if (!__wf.current) return;
  // м ҖмһҘ лЁјм Җ
  if (__wf.dirty) await _wfSave();
  const r = await api('/api/workflows/run', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify({ id: __wf.current.id }),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  toast(t('мӢӨн–ү мӢңмһ‘лҗЁ'), 'ok');
  __wf.runId = r.runId;
  _wfSetRunButtonState(true);
  // л…ёл“ң мғҒнғң мҙҲкё°нҷ”
  document.querySelectorAll('.wf-node').forEach(el => el.removeAttribute('data-status'));
  // нҸҙл§Ғ мӢңмһ‘
  _wfStartPolling();
}

function _wfApplyRunStatus(run) {
  const results = run.nodeResults || {};
  // FF3 (v2.66.18) вҖ” defensive: if every workflow node has reached a
  // terminal status (ok/err/skipped) but the run.status is still
  // 'running' (server-side post-run hook hung вҖ” SQLite lock, persistence
  // race, etc.), promote the banner state client-side so the user isn't
  // stuck staring at a 100%-progress "мӢӨн–ү мӨ‘" banner.
  const nodes = (__wf.current && __wf.current.nodes) || [];
  if (run && run.status === 'running' && nodes.length > 0) {
    const allTerminal = nodes.every(n => {
      const r = results[n.id];
      return r && (r.status === 'ok' || r.status === 'err' || r.status === 'skipped');
    });
    if (allTerminal) {
      const anyErr = nodes.some(n => (results[n.id] || {}).status === 'err');
      run = Object.assign({}, run, {
        status: anyErr ? 'err' : 'ok',
        finishedAt: run.finishedAt || Date.now(),
        currentNodeId: null,
      });
      // Mark the runId as locally-completed so polling loops exit too.
      if (__wf.runId) {
        __wf.runId = null;
        _wfSetRunButtonState(false);
        _wfStopSSE && _wfStopSSE();
        if (__wf.pollTimer) { clearInterval(__wf.pollTimer); __wf.pollTimer = null; }
      }
    }
  }
  __wf.lastRunResults = results;
  __wf.lastRun = run;
  // CC2 (v2.66.14) вҖ” start the independent elapsed-time ticker. SSE only
  // pushes when *server-side* status changes, but elapsed seconds change
  // every wall-clock second. The ticker patches just the elapsed labels
  // (banner + per-node) directly from cached state, so the timer never
  // freezes when the run is mid-flight and the server is quiet.
  _wfStartElapsedTicker();
  // DD2 вҖ” refresh sessions panel (badge always; body only if open)
  _wfRenderSessionsPanel(false);
  // Y2 (v2.66.11) вҖ” diff-only DOM scan. Build a lightweight signature
  // (nodeId вҶ’ status mapping) and compare to last applied; only
  // re-attribute when the per-node status actually changed. Cuts the
  // O(N) querySelectorAll scan from "every tick" to "only when needed".
  // Always re-paint the running node's elapsed-seconds label since that
  // changes by definition each tick.
  const sig = Object.entries(results)
    .map(([nid, r]) => `${nid}:${(r && r.status) || '_'}`)
    .sort().join('|');
  const changed = sig !== __wf._lastResultsSig;
  __wf._lastResultsSig = sig;
  // Cache node element map once per canvas render (built at _wfRenderCanvas)
  // so we skip the querySelectorAll on every tick. Lazy-build if missing.
  if (!__wf._nodeElsMap) {
    __wf._nodeElsMap = new Map();
    document.querySelectorAll('.wf-node').forEach(el => {
      const nid = el.getAttribute('data-node');
      if (nid) __wf._nodeElsMap.set(nid, el);
    });
  }
  for (const [nid, r] of Object.entries(results)) {
    const el = __wf._nodeElsMap.get(nid);
    if (!el) continue;
    if (changed && r) {
      const cur = el.getAttribute('data-status');
      if (cur !== r.status) el.setAttribute('data-status', r.status);
    }
    if (r && r.status === 'running' && r.startedAt) {
      const secs = Math.max(0, Math.floor((Date.now() - r.startedAt) / 1000));
      const el2 = el.querySelector('.wf-node-elapsed');
      if (el2) {
        const txt = 'вҸұ ' + secs + 's';
        if (el2.textContent !== txt) el2.textContent = txt;
      }
    }
  }
  _wfRenderRunBanner(run);
  // DD3 (v2.66.15) вҖ” only re-render the inspector if the *selected*
  // node's status actually changed. Previously fired on every tick and
  // rebuilt the entire side-panel вҖ” biggest remaining lag source during
  // multi-node parallel runs.
  const sel = __wf.selectedNodeId;
  if (sel) {
    const selRes = results[sel];
    const selSig = selRes ? `${selRes.status}:${selRes.startedAt || 0}:${selRes.finishedAt || 0}` : '_';
    if (__wf._lastInspSig !== selSig) {
      __wf._lastInspSig = selSig;
      _wfRenderInspector();
    }
  }
  // DD3 вҖ” minimap only repaints when the level-status signature changes.
  // The rAF-coalesced repaint still runs each tick today; that's wasted
  // work when nothing in the topology view changed.
  if (changed) {
    if (_wfMinimapTimer) cancelAnimationFrame(_wfMinimapTimer);
    _wfMinimapTimer = requestAnimationFrame(() => { _wfMinimapTimer = null; _wfRenderMinimap(); });
  }
  // Task 3: лёҢлқјмҡ°м Җ Notification вҖ” мӢӨн–ү мҷ„лЈҢ/мӢӨнҢЁ м•ҢлҰј
  if (run.status === 'ok') {
    const wfName = (__wf.current && __wf.current.name) || t('мӣҢнҒ¬н”ҢлЎңмҡ°');
    _sendBrowserNotification(t('мӣҢнҒ¬н”ҢлЎңмҡ° мҷ„лЈҢ'), wfName + ' вҖ” ' + t('мӢӨн–үмқҙ м„ұкіөм ҒмңјлЎң мҷ„лЈҢлҗҳм—ҲмҠөлӢҲлӢӨ'));
  } else if (run.status === 'err') {
    const wfName = (__wf.current && __wf.current.name) || t('мӣҢнҒ¬н”ҢлЎңмҡ°');
    _sendBrowserNotification(t('мӣҢнҒ¬н”ҢлЎңмҡ° мӢӨнҢЁ'), wfName + ' вҖ” ' + (run.error || t('мӢӨн–ү мӨ‘ мҳӨлҘҳк°Җ л°ңмғқн–ҲмҠөлӢҲлӢӨ')));
  }
}

// мӢӨн–ү л°°л„Ҳ вҖ” workflows нғӯ мә”лІ„мҠӨ мғҒлӢЁ н”ҢлЎңнҢ…
function _wfRenderRunBanner(run) {
  const host = document.getElementById('wfCanvasHost');
  if (!host) return;
  let el = document.getElementById('wfRunBanner');
  const status = run && run.status;
  const results = (run && run.nodeResults) || {};
  const nodes = (__wf.current && __wf.current.nodes) || [];
  const total = nodes.length;
  const done = Object.values(results).filter(r => r && (r.status === 'ok' || r.status === 'err' || r.status === 'skipped')).length;
  const runningNid = run && run.currentNodeId;
  const runningNode = nodes.find(n => n.id === runningNid);
  const subject = (runningNode && ((runningNode.data && runningNode.data.subject) || runningNode.id)) || t('лҢҖкё° мӨ‘');
  const startedAt = (run && run.startedAt) || 0;
  const now = Date.now();
  const finishedAt = (run && run.finishedAt) || 0;
  const elapsedMs = status === 'running' ? (startedAt ? now - startedAt : 0) : Math.max(0, finishedAt - startedAt);
  const elapsedStr = (elapsedMs / 1000).toFixed(1) + 's';
  const pct = total ? Math.min(100, Math.round((done / total) * 100)) : 0;

  if (!status || status === 'idle') {
    if (el) el.classList.remove('visible');
    return;
  }

  // Y2 (v2.66.11) вҖ” Build banner DOM once, then patch only the values
  // that actually change on each tick. Cuts the per-tick layout/paint
  // cost (which fired every 0.5 s SSE / 1.2 s poll) вҖ” was the second-
  // biggest cause of reported workflow-run lag.
  if (!el) {
    el = document.createElement('div');
    el.id = 'wfRunBanner';
    el.innerHTML = `
      <div class="wfrb-row">
        <span class="wfrb-icon" style="font-size:16px;"></span>
        <span class="wfrb-title-text"></span>
        <span class="wfrb-subject" style="color:var(--accent)"></span>
        <span class="wfrb-meta wfrb-meta-text"></span>
        <button class="wfrb-focus" style="display:none;">рҹ“Қ ${t('мң„м№ҳлЎң мқҙлҸҷ')}</button>
        <button class="wfrb-close" onclick="_wfHideRunBanner()" title="${t('лӢ«кё°')}">Г—</button>
      </div>
      <div class="wfrb-row">
        <div class="wfrb-bar"><div class="wfrb-bar-fill"></div></div>
        <span class="wfrb-meta wfrb-pct"></span>
      </div>`;
    host.appendChild(el);
    // Cache refs.
    el._refs = {
      icon:    el.querySelector('.wfrb-icon'),
      titleT:  el.querySelector('.wfrb-title-text'),
      subject: el.querySelector('.wfrb-subject'),
      meta:    el.querySelector('.wfrb-meta-text'),
      focus:   el.querySelector('.wfrb-focus'),
      barFill: el.querySelector('.wfrb-bar-fill'),
      pct:     el.querySelector('.wfrb-pct'),
    };
  }

  let icon = 'вҸі', stateClass = '', title = t('мӢӨн–ү мӨ‘');
  if (status === 'ok') { icon = 'вң…'; stateClass = 'state-ok'; title = t('мҷ„лЈҢ'); }
  else if (status === 'err') { icon = 'вқҢ'; stateClass = 'state-err'; title = t('мӢӨнҢЁ'); }

  // Diff-patch вҖ” only writes that actually changed, no innerHTML reset.
  if (el.className !== 'visible ' + stateClass) {
    el.className = 'visible ' + stateClass;
  }
  const r = el._refs;
  if (r.icon.textContent    !== icon)         r.icon.textContent = icon;
  if (r.titleT.textContent  !== title + ': ') r.titleT.textContent = title + ': ';
  if (r.subject.textContent !== subject)      r.subject.textContent = subject;
  const metaStr = `${done}/${total} В· ${elapsedStr}`;
  if (r.meta.textContent !== metaStr)         r.meta.textContent = metaStr;
  // Focus button toggles based on running state
  const showFocus = (status === 'running' && runningNid);
  r.focus.style.display = showFocus ? '' : 'none';
  if (showFocus) {
    r.focus.onclick = () => _wfFocusNode(runningNid);
  }
  const widthStr = pct + '%';
  if (r.barFill.style.width !== widthStr)     r.barFill.style.width = widthStr;
  const pctStr = pct + '%';
  if (r.pct.textContent !== pctStr)           r.pct.textContent = pctStr;

  // мҷ„лЈҢ/мӢӨнҢЁ 3.5мҙҲ нӣ„ мһҗлҸҷ мҲЁк№Җ
  if (status === 'ok' || status === 'err') {
    if (__wf._bannerTimer) clearTimeout(__wf._bannerTimer);
    __wf._bannerTimer = setTimeout(() => _wfHideRunBanner(), 3500);
  }
}

function _wfHideRunBanner() {
  const el = document.getElementById('wfRunBanner');
  if (el) el.classList.remove('visible');
  _wfStopElapsedTicker();
}

// CC2 (v2.66.14) вҖ” wall-clock elapsed-time ticker. Runs at 1Hz while a run
// is in-flight; patches text content of already-mounted DOM nodes only вҖ”
// no layout, no paint cascade. Stops itself when the run is done.
function _wfStartElapsedTicker() {
  if (__wf._elapsedTicker) return; // already running
  __wf._elapsedTicker = setInterval(() => {
    // JJ1 (v2.66.26) вҖ” skip ticking when the tab is hidden; the
    // browser already throttles setInterval in background tabs but
    // an explicit guard avoids any DOM mutation on an offscreen
    // canvas the user can't see. The ticker resumes naturally when
    // the user comes back (next interval fire).
    if (document.hidden) return;
    const run = __wf.lastRun;
    if (!run || (run.status !== 'running' && run.status !== 'queued')) {
      _wfStopElapsedTicker();
      return;
    }
    // Banner elapsed
    const banner = document.getElementById('wfRunBanner');
    if (banner && banner._refs) {
      const startedAt = run.startedAt || 0;
      if (startedAt) {
        const ms = Date.now() - startedAt;
        const elapsedStr = (ms / 1000).toFixed(1) + 's';
        const results = run.nodeResults || {};
        const total = (__wf.current && __wf.current.nodes || []).length;
        const done = Object.values(results).filter(r => r && (r.status === 'ok' || r.status === 'err' || r.status === 'skipped')).length;
        const metaStr = `${done}/${total} В· ${elapsedStr}`;
        if (banner._refs.meta && banner._refs.meta.textContent !== metaStr) {
          banner._refs.meta.textContent = metaStr;
        }
      }
    }
    // Per-node elapsed
    const results = run.nodeResults || {};
    if (__wf._nodeElsMap) {
      for (const [nid, r] of Object.entries(results)) {
        if (!(r && r.status === 'running' && r.startedAt)) continue;
        const el = __wf._nodeElsMap.get(nid);
        if (!el) continue;
        const el2 = el.querySelector('.wf-node-elapsed');
        if (!el2) continue;
        const secs = Math.max(0, Math.floor((Date.now() - r.startedAt) / 1000));
        const txt = 'вҸұ ' + secs + 's';
        if (el2.textContent !== txt) el2.textContent = txt;
      }
    }
  }, 1000);
}

function _wfStopElapsedTicker() {
  if (__wf._elapsedTicker) {
    clearInterval(__wf._elapsedTicker);
    __wf._elapsedTicker = null;
  }
}

// DD2 (v2.66.15) вҖ” нҷңм„ұ м„ём…ҳ нҢЁл„җ. мӣҢнҒ¬н”ҢлЎңмҡ° мә”лІ„мҠӨ мҡ°мёЎ н•ҳлӢЁм—җ л– мһҲлҠ”
// м№ҙл“ң. мӢӨн–ү мӨ‘/мҷ„лЈҢлҗң л…ёл“ңмқҳ sessionId, assignee, status лҘј н•ң лҲҲм—җ
// ліҙм—¬мЈјкі , мқёлқјмқё mac-term viewer м—ҙкё° / sessionId ліөмӮ¬ / лӢӨлҘё л…ёл“ңмқҳ
// resume н•„л“ңм—җ л¶ҷм—¬л„Јкё° м•Ўм…ҳмқ„ м ңкіөн•ңлӢӨ.
// GG1 (v2.66.19) вҖ” terminate the workflow session associated with a node.
// At backend granularity we cancel the whole run (level boundary kill),
// since per-node subprocess kill isn't wired up. The user sees an
// immediate "м·ЁмҶҢ мҡ”мІӯлҗЁ" toast and the banner flips on the next tick.
async function _wfTerminateNodeSession(nid, sid) {
  if (!confirm(t('мқҙ л…ёл“ңмқҳ мӢӨн–үмқ„ мӨ‘лӢЁн•ҳмӢңкІ мҠөлӢҲк№Ң? (мӣҢнҒ¬н”ҢлЎңмҡ° м „мІҙ мӢӨн–үмқҙ лӢӨмқҢ л ҲлІЁм—җм„ң л©Ҳм¶ҘлӢҲлӢӨ)'))) return;
  if (__wf.runId) {
    const r = await api('/api/workflows/run-cancel', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ runId: __wf.runId }),
    });
    if (r.ok) {
      toast(`${t('м„ём…ҳ мў…лЈҢ мҡ”мІӯлҗЁ')} вҖ” ${nid}${sid ? ' (' + sid.slice(0, 8) + 'вҖҰ)' : ''}`, 'warn');
    } else {
      toast(errMsg(r) || t('м·ЁмҶҢ мӢӨнҢЁ'), 'err');
    }
  } else {
    toast(t('м§„н–ү мӨ‘мқё мӢӨн–үмқҙ м—ҶмҠөлӢҲлӢӨ'), 'warn');
  }
}

function _wfToggleSessionsPanel() {
  const open = document.getElementById('wfSessionsPanel');
  if (open) { open.remove(); return; }
  _wfRenderSessionsPanel(true);
}

function _wfRenderSessionsPanel(forceShow) {
  const host = document.getElementById('wfCanvasHost');
  if (!host) return;
  let panel = document.getElementById('wfSessionsPanel');
  const results = __wf.lastRunResults || {};
  const nodes = (__wf.current && __wf.current.nodes) || [];
  const rows = [];
  for (const n of nodes) {
    const r = results[n.id];
    if (!r) continue;
    const sid = r.sessionId || '';
    const assignee = (n.data && n.data.assignee) || '';
    const status = r.status || '';
    rows.push({ nid: n.id, title: n.title || n.id, assignee, status, sid, output: r.output || '', error: r.error || '' });
  }
  // Update badge regardless of panel state
  const badge = document.getElementById('wfSessionsBadge');
  if (badge) {
    const live = rows.filter(r => r.status === 'running').length;
    const total = rows.length;
    if (total > 0) {
      badge.style.display = '';
      badge.textContent = live > 0 ? (live + '/' + total) : String(total);
      badge.style.background = live > 0 ? '#ef4444' : 'var(--accent)';
    } else {
      badge.style.display = 'none';
    }
  }
  if (!forceShow && !panel) return; // нҶ кёҖлЎң лӢ«нҳ”мңјл©ҙ лӢӨмӢң л§Ңл“Өм§Җ м•ҠмқҢ
  // DD3 вҖ” skip innerHTML rebuild if the visible signature didn't change
  const sig = rows.map(r => `${r.nid}:${r.status}:${r.sid.slice(0,8)}`).join('|');
  if (panel && panel._lastSig === sig) return;
  if (!panel) {
    panel = document.createElement('div');
    panel.id = 'wfSessionsPanel';
    panel.style.cssText = 'position:absolute;right:14px;bottom:14px;width:340px;max-height:60vh;'
      + 'background:var(--surface,#1c1c1e);border:1px solid var(--border);border-radius:10px;'
      + 'box-shadow:0 10px 30px rgba(0,0,0,0.4);z-index:50;display:flex;flex-direction:column;'
      + 'font-size:12px;overflow:hidden;';
    host.appendChild(panel);
  }
  const STATUS_BADGE = {
    running: '<span style="color:#fbbf24">в—Ҹ ' + t('мӢӨн–ү мӨ‘') + '</span>',
    ok:      '<span style="color:#4ade80">вң“ ' + t('мҷ„лЈҢ') + '</span>',
    err:     '<span style="color:#f87171">вң— ' + t('мӢӨнҢЁ') + '</span>',
    skipped: '<span style="color:#6b6b6f">вҖ” ' + t('кұҙл„ҲлңҖ') + '</span>',
  };
  const list = rows.length ? rows.map(r => {
    const sidShort = r.sid ? r.sid.slice(0, 12) + 'вҖҰ' : '<span style="opacity:0.5">' + t('м„ём…ҳ м—ҶмқҢ') + '</span>';
    const sidEsc = r.sid ? r.sid.replace(/'/g, '&#39;') : '';
    const isLive = r.status === 'running';
    const sidActions = r.sid ? `
      <button class="btn text-[10px]" title="${t('Session ID ліөмӮ¬')}" onclick="_copyToClipboard(this, '${sidEsc}')">рҹ“Ӣ</button>
      <button class="btn text-[10px]" title="${t('лӢӨлҘё л…ёл“ңмқҳ resume н•„л“ңм—җ л¶ҷм—¬л„Јкё°')}" onclick="_wfUseAsResume('${r.nid}','${sidEsc}')">вҶӘ</button>
      ${isLive ? `<button class="btn text-[10px]" style="color:#f87171;" title="${t('мқҙ л…ёл“ңмқҳ мӢӨн–ү м„ём…ҳ мў…лЈҢ')}" onclick="_wfTerminateNodeSession('${r.nid}','${sidEsc}')">вҸ№</button>` : ''}
    ` : (isLive ? `
      <button class="btn text-[10px]" style="color:#f87171;" title="${t('мқҙ л…ёл“ңмқҳ мӢӨн–ү м„ём…ҳ мў…лЈҢ')}" onclick="_wfTerminateNodeSession('${r.nid}','')">вҸ№</button>
    ` : '');
    const errLine = r.error ? `<div style="color:#f87171;font-size:10px;margin-top:2px;">вҡ  ${escapeHtml(r.error.slice(0,140))}</div>` : '';
    return `<div style="padding:8px 10px;border-bottom:1px solid var(--border);">
      <div style="display:flex;align-items:center;gap:6px;">
        <span style="flex:1;font-weight:600;">${escapeHtml(r.title)}</span>
        ${STATUS_BADGE[r.status] || escapeHtml(r.status)}
      </div>
      <div style="display:flex;align-items:center;gap:6px;margin-top:3px;color:var(--text-dim);font-size:10px;">
        <span>${escapeHtml(r.assignee || 'вҖ”')}</span>
        <span style="flex:1;font-family:ui-monospace,monospace;">${sidShort}</span>
        <button class="btn text-[10px]" title="${t('мқёлқјмқё н„°лҜёл„җ ліҙкё°')}" onclick="_wfSpawnSession('${r.nid}')">рҹӘҹ</button>
        ${sidActions}
      </div>
      ${errLine}
    </div>`;
  }).join('') : `<div style="padding:14px;color:var(--text-dim);text-align:center;">${t('м•„м§Ғ мӢӨн–үлҗң л…ёл“ңк°Җ м—ҶмҠөлӢҲлӢӨ')}</div>`;
  panel.innerHTML = `
    <div style="display:flex;align-items:center;gap:6px;padding:8px 10px;border-bottom:1px solid var(--border);background:rgba(255,255,255,0.02);">
      <span style="flex:1;font-weight:700;">рҹӘҹ ${t('мӢӨн–ү м„ём…ҳ')}</span>
      <span style="font-size:10px;color:var(--text-dim);">${rows.length}</span>
      <button class="btn text-[10px]" onclick="_wfToggleSessionsPanel()" title="${t('лӢ«кё°')}">Г—</button>
    </div>
    <div style="overflow-y:auto;flex:1;">${list}</div>`;
  panel._lastSig = sig;
  _translateDOM(panel);
}

// v2.10.2 вҖ” л…ёл“ң hover кІ°кіј tooltip
let _wfTooltipTimer = null;
function _wfShowNodeTooltip(nid, evt) {
  const results = __wf.lastRunResults || {};
  const r = results[nid];
  if (!r) return; // мӢӨн–ү мқҙл Ҙ м—Ҷмңјл©ҙ н‘ңмӢң м•Ҳ н•Ё
  let el = document.getElementById('wfNodeTooltip');
  if (!el) {
    el = document.createElement('div');
    el.id = 'wfNodeTooltip';
    document.body.appendChild(el);
  }
  const status = r.status || 'idle';
  const icons = { ok: 'вң…', err: 'вқҢ', running: 'вҸі', skipped: 'вҸӯпёҸ', idle: 'вҖў' };
  const labels = { ok: t('мҷ„лЈҢ'), err: t('мӢӨнҢЁ'), running: t('мӢӨн–ү мӨ‘'), skipped: t('кұҙл„ҲлңҖ'), idle: t('лҢҖкё° мӨ‘') };
  const wfNodes = (__wf.current && __wf.current.nodes) || [];
  const node = wfNodes.find(n => n.id === nid);
  const title = (node && ((node.data && node.data.subject) || node.title)) || nid;
  const duration = r.durationMs != null
    ? (status === 'running' && r.startedAt ? Math.max(0, Date.now() - r.startedAt) : r.durationMs)
    : 0;
  const dText = (duration / 1000).toFixed(1) + 's';
  const usage = r.usage || {};
  const tokens = (usage.input_tokens || r.inputTokens || 0) + ' / ' + (usage.output_tokens || r.outputTokens || 0);
  const output = (r.output || '').slice(0, 160);
  const more = (r.output || '').length > 160 ? 'вҖҰ' : '';

  el.className = 'visible state-' + status;
  el.innerHTML = `
    <div class="wfnt-head">
      <span>${icons[status] || 'вҖў'}</span>
      <span>${escapeHtml(title)}</span>
      <span class="wfnt-meta" style="margin-left:auto;">${labels[status] || status}</span>
    </div>
    <div class="wfnt-row wfnt-meta">
      <span>вҸұ ${t('мҶҢмҡ” мӢңк°„')}</span><span>${dText}</span>
    </div>
    ${r.provider ? `<div class="wfnt-row wfnt-meta"><span>${t('м ңкіөмһҗ')}</span><span>${escapeHtml(r.provider)}${r.model ? ' В· ' + escapeHtml(r.model) : ''}</span></div>` : ''}
    ${(usage.input_tokens || r.inputTokens || usage.output_tokens || r.outputTokens)
      ? `<div class="wfnt-row wfnt-meta"><span>${t('нҶ нҒ°')}</span><span>${tokens}</span></div>` : ''}
    ${r.cached === true
      ? `<div class="wfnt-row wfnt-meta"><span>рҹ—„</span><span>${t('мәҗмӢң м ҒмӨ‘')} ${r.cachedAgeS!=null?'В· '+r.cachedAgeS+'s':''}</span></div>` : ''}
    ${r.image
      ? `<div class="wfnt-row wfnt-meta"><span>рҹҗі</span><span class="font-mono">${escapeHtml(r.image)}</span></div>` : ''}
    ${r.ralphRunId
      ? `<div class="wfnt-row wfnt-meta"><span>рҹҰһ</span><span>${escapeHtml(r.ralphRunId)} В· ${r.ralphIters||0} iter В· $${(r.ralphCostUsd||0).toFixed(4)}</span></div>` : ''}
    ${status === 'err' && r.error
      ? `<div class="wfnt-out wfnt-err">${escapeHtml(String(r.error).slice(0, 260))}</div>`
      : (output ? `<div class="wfnt-out">${escapeHtml(output)}${more}</div>` : '')}
  `;

  // мң„м№ҳ: л§Ҳмҡ°мҠӨ к·јмІҳ (нҷ”л©ҙ кІҪкі„ кі л Ө)
  const w = el.offsetWidth || 260;
  const h = el.offsetHeight || 120;
  let x = (evt.clientX || 0) + 14;
  let y = (evt.clientY || 0) + 14;
  if (x + w > window.innerWidth - 8) x = (evt.clientX || 0) - w - 14;
  if (y + h > window.innerHeight - 8) y = (evt.clientY || 0) - h - 14;
  el.style.left = Math.max(8, x) + 'px';
  el.style.top = Math.max(8, y) + 'px';
}
function _wfHideNodeTooltip() {
  const el = document.getElementById('wfNodeTooltip');
  if (el) el.classList.remove('visible');
}
// delegation (canvas к°Җ н•ңлІҲл§Ң л¶ҷмқҙлҸ„лЎқ IIFE)
(function _wfNodeTooltipBindOnce() {
  document.addEventListener('mouseover', (e) => {
    const nodeEl = e.target.closest && e.target.closest('.wf-node');
    if (!nodeEl) return;
    if (!document.getElementById('wfRoot')) return;
    const nid = nodeEl.getAttribute('data-node');
    if (!nid) return;
    if (_wfTooltipTimer) clearTimeout(_wfTooltipTimer);
    _wfTooltipTimer = setTimeout(() => _wfShowNodeTooltip(nid, e), 280);
  }, true);
  document.addEventListener('mousemove', (e) => {
    const el = document.getElementById('wfNodeTooltip');
    if (!el || !el.classList.contains('visible')) return;
    const nodeEl = e.target.closest && e.target.closest('.wf-node');
    if (!nodeEl) return;
    // мң„м№ҳл§Ң м—…лҚ°мқҙнҠё (лӘЁм–‘ мң м§Җ)
    const w = el.offsetWidth, h = el.offsetHeight;
    let x = e.clientX + 14, y = e.clientY + 14;
    if (x + w > window.innerWidth - 8) x = e.clientX - w - 14;
    if (y + h > window.innerHeight - 8) y = e.clientY - h - 14;
    el.style.left = Math.max(8, x) + 'px';
    el.style.top = Math.max(8, y) + 'px';
  }, true);
  document.addEventListener('mouseout', (e) => {
    const nodeEl = e.target.closest && e.target.closest('.wf-node');
    if (!nodeEl) return;
    if (_wfTooltipTimer) { clearTimeout(_wfTooltipTimer); _wfTooltipTimer = null; }
    // related target лҸ„ wf-node лӮҙл¶Җл©ҙ мң м§Җ
    const rel = e.relatedTarget;
    if (rel && rel.closest && rel.closest('.wf-node')) return;
    _wfHideNodeTooltip();
  }, true);
})();

// running л…ёл“ңлҘј л·°нҸ¬нҠё мӨ‘м•ҷмңјлЎң pan (zoom мң м§Җ)
function _wfFocusNode(nid) {
  const wf = __wf.current;
  if (!wf) return;
  const n = (wf.nodes || []).find(x => x.id === nid);
  if (!n) return;
  const host = document.getElementById('wfCanvasHost');
  if (!host) return;
  const rect = host.getBoundingClientRect();
  const zoom = (wf.viewport && wf.viewport.zoom) || 1;
  const cx = n.x + WF_NODE_W / 2;
  const cy = n.y + WF_NODE_H / 2;
  const panX = rect.width / 2 - cx * zoom;
  const panY = rect.height / 2 - cy * zoom;
  wf.viewport = { panX, panY, zoom };
  const vp = document.getElementById('wfViewport');
  if (vp) vp.setAttribute('transform', `translate(${panX},${panY}) scale(${zoom})`);
  _wfSchedulePatch && _wfSchedulePatch();
  // лҜёлӢҲл§ө л·°нҸ¬нҠё мӮ¬к°Ғнҳ•лҸ„ м—…лҚ°мқҙнҠё
  if (_wfMinimapTimer) cancelAnimationFrame(_wfMinimapTimer);
  _wfMinimapTimer = requestAnimationFrame(() => { _wfMinimapTimer = null; _wfRenderMinimap(); });
}

function _wfStopSSE() {
  if (__wf._sse) { try { __wf._sse.close(); } catch(e){} __wf._sse = null; }
}

function _wfStartPolling() {
  // лЁјм Җ SSE мӢңлҸ„, мӢӨнҢЁ мӢң нҸҙл§Ғ fallback
  _wfStopSSE();
  if (__wf.pollTimer) { clearInterval(__wf.pollTimer); __wf.pollTimer = null; }

  if (!__wf.runId) return;

  // AA2 (v2.66.13) вҖ” Prefer SSE; only fall back to polling if SSE
  // genuinely gives up (CLOSED state after one or more reconnection
  // attempts), never on the first transient onerror. Browser-native
  // EventSource auto-reconnects internally; we just need not to race
  // with that by spawning a parallel poller.
  let _sseEverOpen = false;
  let _sseErrorStrikes = 0;
  try {
    const sse = new EventSource('/api/workflows/run-stream?runId=' + encodeURIComponent(__wf.runId));
    __wf._sse = sse;

    sse.addEventListener('open', () => {
      _sseEverOpen = true;
      _sseErrorStrikes = 0;
    });

    sse.addEventListener('status', (e) => {
      try {
        const data = JSON.parse(e.data);
        const run = data.run || data;
        _wfApplyRunStatus(run);
      } catch(ex) { /* silent */ }
    });

    sse.addEventListener('done', (e) => {
      try {
        const data = JSON.parse(e.data);
        const run = data.run || data;
        _wfApplyRunStatus(run);
        _wfShowRunResult(run);
      } catch(ex) { /* silent */ }
      __wf.runId = null;
      _wfSetRunButtonState(false);
      _wfStopSSE();
    });

    sse.addEventListener('error', (e) => {
      // Custom server-emitted error event (has .data with details)
      if (e.data) {
        try {
          const data = JSON.parse(e.data);
          toast(errMsg(data), 'err');
        } catch(ex) { toast(t('мӢӨн–ү мҳӨлҘҳ'), 'err'); }
        __wf.runId = null;
        _wfStopSSE();
      }
    });

    sse.addEventListener('timeout', (e) => {
      toast(t('мӢӨн–ү мӢңк°„ мҙҲкіј'), 'warn');
      __wf.runId = null;
      _wfSetRunButtonState(false);
      _wfStopSSE();
    });

    sse.onerror = () => {
      // The browser's EventSource auto-retries on transient errors. Only
      // fall back to polling once we've seen вүҘ3 strikes AND the source is
      // CLOSED. CONNECTING is normal for the first ~1s of life.
      _sseErrorStrikes++;
      if (sse.readyState === EventSource.CLOSED && _sseErrorStrikes >= 3) {
        _wfStopSSE();
        if (__wf.runId) _wfStartPollingFallback();
      }
    };
  } catch(e) {
    // EventSource constructor itself threw вҖ” fall back immediately
    _wfStartPollingFallback();
  }
}

function _wfStartPollingFallback() {
  if (__wf.pollTimer) { clearInterval(__wf.pollTimer); __wf.pollTimer = null; }
  __wf.pollTimer = setInterval(async () => {
    // v2.46.0 perf вҖ” skip network round-trips while the tab is hidden.
    if (document.hidden) return;
    if (!__wf.runId) { clearInterval(__wf.pollTimer); __wf.pollTimer = null; return; }
    try {
      const s = await api('/api/workflows/run-status?runId=' + __wf.runId);
      if (!s.ok) return;
      const run = s.run || {};
      _wfApplyRunStatus(run);
      if (run.status === 'ok' || run.status === 'err') {
        clearInterval(__wf.pollTimer); __wf.pollTimer = null;
        _wfShowRunResult(run);
        __wf.runId = null;
        _wfSetRunButtonState(false);
      }
    } catch (e) { /* silent */ }
  }, 1200);
}

async function _wfShowRunResult(run) {
  const ok = run.status === 'ok';
  const results = run.nodeResults || {};
  const iterInfo = (typeof run.iteration === 'number' && run.iteration > 0)
    ? `<div class="text-xs text-[var(--text-dim)] mb-2">рҹ”Ғ ${t('мөңмў… л°ҳліө')}: ${run.iteration + 1}</div>` : '';
  // EE2 (v2.66.16) вҖ” when a node fails, fetch the list of currently
  // available providers and offer a one-click switch dropdown. This is
  // the recovery path after a `timeout after 300s` / `unavailable` error.
  let availableProviders = [];
  const hasErr = Object.values(results).some(r => r && r.status === 'err');
  if (hasErr) {
    try {
      const pr = await api('/api/ai-providers/list');
      availableProviders = (pr.providers || []).filter(p => p.available);
    } catch (e) { /* silent */ }
  }
  const _switchSelectFor = (nid, currentAssignee) => {
    if (!availableProviders.length) return '';
    const opts = availableProviders.flatMap(p => {
      const provLabel = p.name || p.id;
      const models = (p.models || []).slice(0, 8);
      if (!models.length) return [`<option value="${escapeHtml(p.id)}">${escapeHtml(provLabel)}</option>`];
      return models.map(m => {
        const v = `${p.id}:${m.id || m.name}`;
        return `<option value="${escapeHtml(v)}">${escapeHtml(provLabel)} В· ${escapeHtml(m.id || m.name)}</option>`;
      });
    }).join('');
    return `
      <div class="mt-2 pt-2 border-t border-[var(--border)] flex items-center gap-2 flex-wrap">
        <span class="text-[10px] text-[var(--text-dim)] whitespace-nowrap">${t('н”„лЎңл°”мқҙлҚ” ліҖкІҪ')}:</span>
        <span class="text-[10px] text-[var(--text-dim)] truncate" title="${escapeHtml(currentAssignee || '')}">вҶӘ ${escapeHtml(currentAssignee || 'вҖ”')}</span>
        <select id="wfSw-${nid}" class="input text-[10px]" style="flex:1;min-width:160px;"><option value="">${t('м„ нғқвҖҰ')}</option>${opts}</select>
        <button class="btn text-[10px] btn-primary" onclick="_wfSwitchProvider('${nid}')">${t('м Ғмҡ© + мһ¬мӢӨн–ү')}</button>
      </div>`;
  };
  const rows = Object.entries(results).map(([nid, r]) => {
    const node = (__wf.current.nodes || []).find(n => n.id === nid) || {};
    const icon = (WF_TYPE_MAP[node.type]||{}).icon || 'вҖў';
    const preview = (r.output||'').slice(0, 500);
    const err = r.error ? `<div class="text-[11px] text-red-400 mt-1">вҡ  ${escapeHtml(r.error)}</div>` : '';
    const switchUI = (r.status === 'err' && (node.type === 'session' || node.type === 'subagent'))
      ? _switchSelectFor(nid, (node.data || {}).assignee || '') : '';
    const sid = r.sessionId || '';
    const sidRow = sid ? `
      <div class="mt-2 pt-2 border-t border-[var(--border)] flex items-center gap-2">
        <span class="text-[10px] text-[var(--text-dim)]">session_id</span>
        <code class="text-[10px] flex-1 truncate" style="color:#c4b5fd;">${escapeHtml(sid)}</code>
        <button class="btn text-[10px]" onclick="_copyToClipboard(this, ${JSON.stringify(sid).replace(/"/g,'&quot;')})">рҹ“Ӣ</button>
        <button class="btn text-[10px]" onclick="_wfUseAsResume('${nid}', ${JSON.stringify(sid).replace(/"/g,'&quot;')})" title="${t('лӢӨлҘё л…ёл“ңмқҳ resume н•„л“ңм—җ л¶ҷм—¬л„Јкё°')}">вҶӘ ${t('мқҙм–ҙм“°кё°')}</button>
      </div>` : '';
    return `<div class="card p-3">
      <div class="flex items-center justify-between mb-1">
        <div class="text-xs font-semibold">${icon} ${escapeHtml(node.title||nid)} <span class="text-[10px] text-[var(--text-dim)]">(${r.status})</span></div>
        <div class="text-[10px] text-[var(--text-dim)]">${r.durationMs||0}ms</div>
      </div>
      ${preview ? `<pre class="text-[11px] whitespace-pre-wrap break-words" style="max-height:160px;overflow-y:auto;">${escapeHtml(preview)}</pre>` : ''}
      ${err}
      ${switchUI}
      ${sidRow}
    </div>`;
  }).join('');
  showModal(`
    <div class="modal p-5" style="max-width:720px;">
      <div class="flex items-center justify-between mb-3">
        <h2 class="text-lg font-semibold">${ok ? 'вң…' : 'вқҢ'} ${t('мӢӨн–ү кІ°кіј')}</h2>
        <button class="btn text-xs" onclick="closeModal()">${t('лӢ«кё°')}</button>
      </div>
      ${run.error ? `<div class="text-sm text-red-400 mb-2">вҡ  ${escapeHtml(run.error)}</div>` : ''}
      ${iterInfo}
      <div class="flex flex-col gap-2 max-h-[60vh] overflow-y-auto">${rows || '<div class="empty card p-4">'+t('кІ°кіј м—ҶмқҢ')+'</div>'}</div>
    </div>
  `);
}

// EE2 (v2.66.16) вҖ” apply a new assignee to a failed node and re-run the
// workflow. Saves the workflow first so the change persists.
async function _wfSwitchProvider(nid) {
  if (!__wf.current) return;
  const sel = document.getElementById('wfSw-' + nid);
  if (!sel || !sel.value) { toast(t('н”„лЎңл°”мқҙлҚ”лҘј м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }
  const newAssignee = sel.value;
  const node = __wf.current.nodes.find(n => n.id === nid);
  if (!node) return;
  node.data = node.data || {};
  const prev = node.data.assignee || '';
  node.data.assignee = newAssignee;
  __wf.dirty = true;
  // Persist the change before re-running so the registry sees it.
  try {
    await api('/api/workflows/save', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ workflow: __wf.current }),
    });
  } catch(e) { /* silent вҖ” re-run still works against in-memory copy */ }
  toast(`${prev || '(none)'} вҶ’ ${newAssignee} ${t('м Ғмҡ©лҗЁ, мһ¬мӢӨн–үн•©лӢҲлӢӨ')}`, 'ok');
  closeModal();
  await _wfRun();
}

async function _wfUseAsResume(sourceNid, sessionId) {
  if (!__wf.current) return;
  // лӢӨлҘё м„ём…ҳ/м„ңлёҢм—җмқҙм „нҠё л…ёл“ң лӘ©лЎқ м ңмӢң
  const candidates = (__wf.current.nodes || []).filter(n =>
    (n.type === 'session' || n.type === 'subagent') && n.id !== sourceNid);
  if (!candidates.length) { toast(t('м Ғмҡ©н•  л…ёл“ңк°Җ м—ҶмҠөлӢҲлӢӨ'), 'warn'); return; }
  const optionsText = candidates.map((n, i) =>
    `${i+1}. ${n.title || n.type} (${n.id})`).join('\n');
  const pick = await promptModal({
    title: t('resume лҢҖмғҒ л…ёл“ң'),
    message: t('мқҙ session_id лҘј м–ҙл–Ө л…ёл“ңмқҳ resume н•„л“ңм—җ л„Јмқ„к№Ңмҡ”? лІҲнҳё мһ…л Ҙ:') + '\n' + optionsText,
    placeholder: '1',
  });
  if (!pick) return;
  const idx = parseInt(pick, 10) - 1;
  if (isNaN(idx) || idx < 0 || idx >= candidates.length) { toast(t('мһҳлӘ»лҗң лІҲнҳё'), 'err'); return; }
  const target = candidates[idx];
  target.data = target.data || {};
  target.data.resumeSessionId = sessionId;
  __wf.dirty = true;
  toast(`'${target.title}' ` + t('м—җ session_id м Ғмҡ©лҗЁ'), 'ok');
  _wfUpdateToolbar();
  closeModal();
  // мқёмҠӨнҺҷн„° мҳӨн”Ҳ
  __wf.selectedNodeId = target.id;
  __wf._inspectorDirty = true;
  _wfRenderInspector();
}

// CC1 (v2.66.14) вҖ” clicking the screen icon on a workflow node opens the
// inline mac-style viewer (NOT a real Terminal.app window). Shows the
// node's prompt + the latest run's per-node output if any. A
// "вҶ— Real terminal" button keeps the old escape hatch one click away.
async function _wfSpawnSession(nid) {
  if (!__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  const d = n.data || {};
  const cwd = d.cwd || '~';
  const subject = d.subject || n.title || n.id;
  const description = d.description || '';
  const assignee = d.assignee || '';
  const lastResults = (__wf.lastRunResults && __wf.lastRunResults[nid]) || null;

  const lines = [];
  lines.push(`<div class="mac-term-line meta">$ ${escapeHtml(assignee || 'session')} вҖ” ${escapeHtml(subject)}</div>`);
  lines.push(`<div class="mac-term-line meta">cwd: ${escapeHtml(cwd)}</div>`);
  if (n.type)        lines.push(`<div class="mac-term-line meta">type: ${escapeHtml(n.type)}</div>`);
  if (lastResults) {
    lines.push(`<div class="mac-term-line meta">status: ${escapeHtml(lastResults.status || '')}${lastResults.startedAt ? ' В· ' + new Date(lastResults.startedAt).toLocaleTimeString() : ''}</div>`);
  }
  lines.push(`<div class="mac-term-line meta">в”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғв”Ғ</div>`);
  if (subject)     lines.push(`<div class="mac-term-line user"><span class="mac-prompt">в–ё</span> ${escapeHtml(subject)}</div>`);
  if (description) lines.push(`<div class="mac-term-line assist">${escapeHtml(description)}</div>`);
  if (lastResults && lastResults.output) {
    lines.push(`<div class="mac-term-line meta">в”Җв”Җв”Җ ${t('м¶ңл Ҙ')} в”Җв”Җв”Җ</div>`);
    const out = String(lastResults.output).slice(0, 8000);
    out.split('\n').forEach(ln => lines.push(`<div class="mac-term-line assist">${escapeHtml(ln)}</div>`));
  } else if (lastResults && lastResults.error) {
    lines.push(`<div class="mac-term-line meta" style="color:#f87171">вҡ  ${escapeHtml(lastResults.error)}</div>`);
  } else {
    lines.push(`<div class="mac-term-line meta">${t('(м•„м§Ғ мӢӨн–ү кІ°кіј м—ҶмқҢ вҖ” мӣҢнҒ¬н”ҢлЎңмҡ°лҘј мӢӨн–үн•ҳл©ҙ м—¬кё°м—җ н‘ңмӢңлҗЁ)')}</div>`);
  }

  // Stash node id so the "real terminal" button can pick the spawn body.
  window.__wfMacTermNid = nid;

  showModal(`
    <div class="mac-term">
      <div class="mac-term-titlebar">
        <span class="mac-term-dot mac-dot-red" onclick="closeModal()"></span>
        <span class="mac-term-dot mac-dot-yellow"></span>
        <span class="mac-term-dot mac-dot-green"></span>
        <span class="mac-term-title">${t('л…ёл“ң')} В· ${escapeHtml(n.id)}${assignee ? ' В· ' + escapeHtml(assignee) : ''}</span>
        <button class="mac-term-spawn" onclick="_wfMacTermSpawnReal()" title="${t('мӢӨм ң н„°лҜёл„җм—җм„ң мқҙм–ҙм„ң м—ҙкё°')}">вҶ— ${t('мӢӨм ң н„°лҜёл„җ')}</button>
      </div>
      <div class="mac-term-body">
        ${lines.join('')}
      </div>
    </div>
  `, { wide: true });
  setTimeout(() => {
    const b = document.querySelector('.mac-term-body');
    if (b) b.scrollTop = b.scrollHeight;
  }, 80);
}

window._wfMacTermSpawnReal = async function() {
  const nid = window.__wfMacTermNid;
  if (!nid || !__wf.current) return;
  const n = __wf.current.nodes.find(x => x.id === nid);
  if (!n) return;
  const d = n.data || {};
  const r = await api('/api/session/spawn', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify({
      cwd: d.cwd || '~',
      prompt: [d.subject, d.description].filter(Boolean).join('\n\n'),
      assignee:            d.assignee || '',
      systemPrompt:        d.systemPrompt || '',
      appendSystemPrompt:  d.appendSystemPrompt || '',
      allowedTools:        d.allowedTools || '',
      disallowedTools:     d.disallowedTools || '',
      resumeSessionId:     d.resumeSessionId || '',
    }),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  const PROVIDER_LABELS = { 'claude-cli':'Claude', 'gemini-cli':'Gemini', 'ollama':'Ollama', 'codex':'Codex' };
  const label = PROVIDER_LABELS[r.provider] || 'Claude';
  toast(`${label} ${t('м„ём…ҳ мӢңмһ‘лҗЁ')}${r.model ? ' (' + r.model + ')' : ''}`, 'ok');
};

