const WF_TPL_CATEGORIES = [
  { id: 'all',      label: 'м „мІҙ' },
  { id: 'analysis', label: 'л¶„м„қ' },
  { id: 'ai',       label: 'AI' },
  { id: 'dev',      label: 'к°ңл°ң' },
  { id: 'data',     label: 'лҚ°мқҙн„°' },
  { id: 'pattern',  label: 'нҢЁн„ҙ' },
  { id: 'custom',   label: 'м»ӨмҠӨн…Җ' },
];

let __wfTplFilter = 'all';

function _wfFilterTemplates(cat) {
  __wfTplFilter = cat;
  document.querySelectorAll('.wf-tpl-cat-btn').forEach(btn => {
    btn.classList.toggle('btn-active', btn.dataset.cat === cat);
  });
  document.querySelectorAll('.wf-tpl-card').forEach(card => {
    const cardCat = card.dataset.category || '';
    card.style.display = (cat === 'all' || cardCat === cat) ? '' : 'none';
  });
}

async function _wfShowTemplates() {
  const customList = await api('/api/workflows/templates/list');
  const customTemplates = (customList && customList.templates) || [];

  // Merge server-side builtin flag
  const allTemplates = [
    ...WF_TEMPLATES.map(tpl => ({ ...tpl, source: 'builtin' })),
    ...customTemplates.map(tpl => ({
      ...tpl,
      source: tpl.builtin ? 'builtin' : 'custom',
      category: tpl.category || 'custom',
    })),
  ];

  const builtInCards = WF_TEMPLATES.map(tpl => `
    <div class="card p-4 hover-lift wf-tpl-card" data-category="${escapeHtml(tpl.category || 'pattern')}" style="cursor:pointer;position:relative;" onclick="_wfUseTemplate('${tpl.id}')">
      <div class="flex items-center gap-2 mb-2">
        <span style="font-size:1.5rem;">${tpl.icon}</span>
        <span class="text-sm font-semibold">${escapeHtml(t(tpl.title))}</span>
        <span class="chip chip-ok text-[9px]" style="font-weight:600;">BUILT-IN</span>
      </div>
      <div class="text-[11px] text-[var(--text-mute)] leading-relaxed mb-2">${escapeHtml(t(tpl.desc))}</div>
      <div class="flex items-center gap-2">
        <span class="chip text-[9px]">${escapeHtml(t(WF_TPL_CATEGORIES.find(c=>c.id===tpl.category)?.label || tpl.category || ''))}</span>
        <button class="btn-primary btn text-[10px]" onclick="event.stopPropagation();_wfUseTemplate('${tpl.id}')">+ ${t('мқҙ н…ңн”ҢлҰҝмңјлЎң мғҲ мӣҢнҒ¬н”ҢлЎңмҡ° мғқм„ұ')}</button>
      </div>
    </div>
  `).join('');

  const customCards = customTemplates.length ? customTemplates.map(tpl => {
    const isBuiltin = !!tpl.builtin;
    const cat = tpl.category || 'custom';
    return `
    <div class="card p-4 hover-lift wf-tpl-card" data-category="${escapeHtml(cat)}" style="cursor:pointer;position:relative;" onclick="_wfUseCustomTemplate('${tpl.id}')">
      <div style="position:absolute;top:8px;right:8px;display:flex;gap:4px;">
        ${isBuiltin
          ? `<span class="chip chip-ok text-[9px]" style="font-weight:600;">BUILT-IN</span>`
          : `<button class="btn text-[10px]" style="color:#fca5a5;" onclick="event.stopPropagation();_wfDeleteCustomTemplate('${tpl.id}')">рҹ—‘пёҸ</button>`
        }
      </div>
      <div class="flex items-center gap-2 mb-2">
        <span style="font-size:1.5rem;">${escapeHtml(tpl.icon||'рҹ’ҫ')}</span>
        <span class="text-sm font-semibold">${escapeHtml(tpl.name)}</span>
      </div>
      <div class="text-[11px] text-[var(--text-mute)] leading-relaxed mb-1">${escapeHtml(tpl.description || '')}</div>
      <div class="flex items-center justify-between mt-2">
        <div class="flex items-center gap-2">
          <span class="text-[10px] text-[var(--text-dim)]">${tpl.nodeCount || 0} ${t('л…ёл“ң')} В· ${tpl.edgeCount || 0} ${t('м—°кІ°')}</span>
          <span class="chip text-[9px]">${escapeHtml(t(WF_TPL_CATEGORIES.find(c=>c.id===cat)?.label || cat))}</span>
        </div>
        <button class="btn-primary btn text-[10px]" onclick="event.stopPropagation();_wfUseCustomTemplate('${tpl.id}')">+ ${t('мқҙ н…ңн”ҢлҰҝмңјлЎң мғҲ мӣҢнҒ¬н”ҢлЎңмҡ° мғқм„ұ')}</button>
      </div>
    </div>`;
  }).join('') : `<div class="card p-4 text-xs text-[var(--text-dim)] text-center">${t('м ҖмһҘлҗң м»ӨмҠӨн…Җ н…ңн”ҢлҰҝмқҙ м—ҶмҠөлӢҲлӢӨ')}</div>`;

  const canSaveCurrent = !!(__wf.current && (__wf.current.nodes||[]).length);

  const catFilterBtns = WF_TPL_CATEGORIES.map(c =>
    `<button class="btn text-[10px] wf-tpl-cat-btn ${__wfTplFilter === c.id ? 'btn-active' : ''}" data-cat="${c.id}" onclick="_wfFilterTemplates('${c.id}')">${escapeHtml(t(c.label))}</button>`
  ).join('');

  showModal(`
    <div class="p-5">
      <div class="flex items-center justify-between mb-3">
        <h3 class="text-base font-semibold">рҹ“Ӣ ${t('мӣҢнҒ¬н”ҢлЎңмҡ° н…ңн”ҢлҰҝ')}</h3>
        <button class="btn text-xs" onclick="closeModal()">${t('лӢ«кё°')}</button>
      </div>
      <div class="text-xs text-[var(--text-mute)] mb-3">
        ${t('мһҗмЈј м“°лҠ” DAG нҢЁн„ҙмқ„ мӣҗнҒҙлҰӯмңјлЎң л§Ңл“ӯлӢҲлӢӨ. мғқм„ұ нӣ„ л…ёл“ңлі„ м—…л¬ҙ лӮҙмҡ©мқ„ мһҗмң лЎӯкІҢ мҲҳм •н•ҳм„ёмҡ”.')}
      </div>

      <div class="flex flex-wrap gap-2 mb-4">${catFilterBtns}</div>

      <div class="text-[11px] uppercase tracking-wider text-[var(--text-dim)] mb-2">${t('кё°ліё н…ңн”ҢлҰҝ')}</div>
      <div class="flex flex-col gap-2 mb-4">${builtInCards}</div>

      <div class="flex items-center justify-between mt-4 mb-2">
        <div class="text-[11px] uppercase tracking-wider text-[var(--text-dim)]">${t('лӮҙ м»ӨмҠӨн…Җ н…ңн”ҢлҰҝ')}</div>
        <button class="btn-primary btn text-xs" ${canSaveCurrent?'':'disabled style="opacity:0.5;pointer-events:none;"'}
                onclick="_wfSaveCurrentAsTemplate()">+ ${t('нҳ„мһ¬ мӣҢнҒ¬н”ҢлЎңмҡ°лҘј н…ңн”ҢлҰҝмңјлЎң м ҖмһҘ')}</button>
      </div>
      <div class="flex flex-col gap-2">${customCards}</div>
    </div>
  `, { narrow: true });

  // Apply current filter after modal is rendered
  setTimeout(() => _wfFilterTemplates(__wfTplFilter), 10);
}

async function _wfUseTemplate(tplId) {
  const tpl = WF_TEMPLATES.find(x => x.id === tplId);
  if (!tpl) return;
  closeModal();
  const body = tpl.build();
  const r = await api('/api/workflows/save', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify(body),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  toast(t('н…ңн”ҢлҰҝм—җм„ң мғқм„ұлҗЁ'), 'ok');
  const list = await api('/api/workflows/list');
  __wf.workflows = list.workflows || [];
  await _wfOpen(r.id);
  _wfRenderList();
  setTimeout(() => _wfFitView(), 150);
}

async function _wfUseCustomTemplate(tplId) {
  const r = await api('/api/workflows/templates/' + encodeURIComponent(tplId));
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  closeModal();
  const tpl = r.template;
  // н…ңн”ҢлҰҝмқ„ л°”нғ•мңјлЎң мғҲ мӣҢнҒ¬н”ҢлЎңмҡ° мғқм„ұ (id м ңкұ°н•ҙм„ң мӢ к·ң ID н• лӢ№)
  const body = {
    name: tpl.name + ' (' + t('ліөм ң') + ')',
    description: tpl.description,
    nodes: tpl.nodes,
    edges: tpl.edges,
    viewport: tpl.viewport,
  };
  const s = await api('/api/workflows/save', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify(body),
  });
  if (!s.ok) { toast(errMsg(s), 'err'); return; }
  toast(t('н…ңн”ҢлҰҝм—җм„ң мғқм„ұлҗЁ'), 'ok');
  const list = await api('/api/workflows/list');
  __wf.workflows = list.workflows || [];
  await _wfOpen(s.id);
  _wfRenderList();
  setTimeout(() => _wfFitView(), 150);
}

async function _wfSaveCurrentAsTemplate() {
  if (!__wf.current) { toast(t('мӣҢнҒ¬н”ҢлЎңмҡ°лҘј лЁјм Җ м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }
  const name = await promptModal({
    title: t('н…ңн”ҢлҰҝмңјлЎң м ҖмһҘ'),
    message: t('н…ңн”ҢлҰҝ мқҙлҰ„мқ„ мһ…л Ҙн•ҳм„ёмҡ”'),
    placeholder: t('мҳҲ: лӮҙ лҰ¬л·° н”ҢлЎңмҡ°'),
    defaultValue: __wf.current.name || '',
    confirmLabel: t('м ҖмһҘ'),
  });
  if (!name || !name.trim()) return;
  const desc = await promptModal({
    title: t('н…ңн”ҢлҰҝ м„ӨлӘ… (м„ нғқ)'),
    message: t('мқҙ н…ңн”ҢлҰҝмқҙ л¬ҙм—Үмқём§Җ н•ңл‘җ мӨ„лЎң м Ғм–ҙмЈјм„ёмҡ”. л№„мӣҢлҸ„ лҗ©лӢҲлӢӨ.'),
    placeholder: '',
    defaultValue: __wf.current.description || '',
    confirmLabel: t('м ҖмһҘ'),
  });
  const body = {
    name: name.trim(),
    description: (desc || '').trim(),
    icon: 'рҹ’ҫ',
    nodes: __wf.current.nodes,
    edges: __wf.current.edges,
    viewport: __wf.current.viewport,
  };
  const r = await api('/api/workflows/templates/save', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify(body),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  toast(t('м»ӨмҠӨн…Җ н…ңн”ҢлҰҝ м ҖмһҘлҗЁ'), 'ok');
  // лӘЁлӢ¬ лӢӨмӢң м—ҙм–ҙ лӘ©лЎқ к°ұмӢ 
  closeModal();
  setTimeout(() => _wfShowTemplates(), 100);
}

async function _wfDeleteCustomTemplate(tplId) {
  const ok = await confirmModal({
    title: t('м»ӨмҠӨн…Җ н…ңн”ҢлҰҝ мӮӯм ң'),
    message: t('мқҙ м»ӨмҠӨн…Җ н…ңн”ҢлҰҝмқ„ мӮӯм ңн• к№Ңмҡ”?'),
    confirmLabel: t('мӮӯм ң'), danger: true,
  });
  if (!ok) return;
  const r = await api('/api/workflows/templates/delete', {
    method: 'POST', headers: { 'Content-Type':'application/json' },
    body: JSON.stringify({ id: tplId }),
  });
  if (!r.ok) { toast(errMsg(r), 'err'); return; }
  toast(t('мӮӯм ңлҗЁ'), 'ok');
  closeModal();
  setTimeout(() => _wfShowTemplates(), 100);
}

// в”Җв”Җв”Җ мӣҢнҒ¬н”ҢлЎңмҡ° лІ„м „ нһҲмҠӨнҶ лҰ¬ в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
async function _wfLoadVersionHistory() {
  if (!__wf.current) return;
  const body = document.getElementById('wfVersionHistoryBody');
  if (!body) return;
  body.innerHTML = `<div class="text-[10px]" style="color:var(--text-dim)">${t('лЎңл”© мӨ‘...')}</div>`;
  try {
    const r = await api('/api/workflows/history?id=' + encodeURIComponent(__wf.current.id));
    const versions = (r && r.versions) || [];
    if (!versions.length) {
      body.innerHTML = `<div class="text-[10px]" style="color:var(--text-dim)">${t('м ҖмһҘлҗң лІ„м „мқҙ м—ҶмҠөлӢҲлӢӨ')}</div>`;
      return;
    }
    body.innerHTML = `
      <div class="flex items-center gap-2 mb-2">
        <span class="text-[10px] text-[var(--text-dim)]">${t('л№„көҗн•  л‘җ лІ„м „мқ„ м„ нғқн•ҳм„ёмҡ”')}:</span>
        <button class="btn text-[10px]" onclick="_wfDiffVersions()" aria-label="${t('м„ нғқлҗң лІ„м „ л№„көҗ')}">рҹ”Қ ${t('л№„көҗ')}</button>
      </div>
    ` + versions.map((v, idx) => `
      <div class="flex items-center justify-between py-2 border-b border-[var(--border)]" style="gap:6px;">
        <label class="flex items-center gap-1 flex-shrink-0">
          <input type="checkbox" class="wf-version-compare-cb" data-saved-at="${escapeHtml(v.savedAt)}" data-name="${escapeHtml(v.name||t('мқҙлҰ„ м—ҶмқҢ'))}" data-node-count="${v.nodeCount||0}" style="accent-color:var(--accent);" />
        </label>
        <div class="flex-1 min-w-0">
          <div class="text-[11px] font-semibold truncate" style="color:var(--text)">${escapeHtml(v.name || t('мқҙлҰ„ м—ҶмқҢ'))}</div>
          <div class="text-[10px]" style="color:var(--text-dim)">
            ${new Date(v.savedAt).toLocaleString()} В· ${v.nodeCount || 0} ${t('л…ёл“ң')}
          </div>
        </div>
        <button class="btn text-[10px] flex-shrink-0" onclick="_wfRestoreVersion('${escapeHtml(__wf.current.id)}','${escapeHtml(v.savedAt)}')">
          вҶ© ${t('ліөмӣҗ')}
        </button>
      </div>
    `).join('');
  } catch (e) {
    body.innerHTML = `<div class="text-[10px]" style="color:var(--err)">${t('нһҲмҠӨнҶ лҰ¬ лЎңл“ң мӢӨнҢЁ')}: ${escapeHtml(String(e))}</div>`;
  }
}

async function _wfRestoreVersion(wfId, savedAt) {
  const ok = await confirmModal({
    title: t('лІ„м „ ліөмӣҗ'),
    message: t('мқҙ лІ„м „мңјлЎң ліөмӣҗн•ҳмӢңкІ мҠөлӢҲк№Ң? нҳ„мһ¬ м ҖмһҘлҗҳм§Җ м•ҠмқҖ ліҖкІҪ мӮ¬н•ӯмқҖ мӮ¬лқјм§‘лӢҲлӢӨ.'),
    confirmLabel: t('ліөмӣҗ'), danger: true,
  });
  if (!ok) return;
  try {
    const r = await api('/api/workflows/restore', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: wfId, savedAt }),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    toast(t('лІ„м „мқҙ ліөмӣҗлҗҳм—ҲмҠөлӢҲлӢӨ'), 'ok');
    await _wfOpen(wfId);
    _wfRenderList();
    _wfRenderCanvas();
    _wfRenderInspector();
  } catch (e) {
    toast(t('ліөмӣҗ мӢӨнҢЁ') + ': ' + String(e), 'err');
  }
}

