  const scopeLabel = { global: 'рҹ”§ м „м—ӯ (~/.claude/agents)', builtin: 'вҡЎ л№ҢнҠёмқё (Claude Code)', plugin: 'рҹ”Ң н”Ңлҹ¬к·ёмқё' };
