// v2.40.2 вҖ” Panic button. Walks every user + plugin hook entry whose matcher
// matches the danger pattern (PreToolUse + Edit/Write/Bash) and deletes them
// in place. User hooks are removed from settings.json; plugin hooks call
// /api/hooks/plugin/update with op:'delete'. The user confirms the count
// first, then sees a toast per phase.
async function _panicDisableRiskyHooks() {
  const all = (await api('/api/hooks')).hooks || [];
  const settings = await api('/api/settings');
  const targets = all.filter(h => {
    if (h.event !== 'PreToolUse') return false;
    return h.matcher && /\b(Edit|Write|Bash|MultiEdit|NotebookEdit)\b/.test(h.matcher);
  });
  if (!targets.length) { toast(t('мң„н—ҳ нӣ… м—ҶмқҢ'), 'ok'); return; }
  if (!confirm(t('PreToolUse + Edit/Write/Bash л§ӨмІҳлҘј к°Җм§„ ') + targets.length + t('к°ң нӣ…мқ„ лӘЁл‘җ мӮӯм ңн• к№Ңмҡ”? мқҙ мһ‘м—…мқҖ мҰүмӢң м Ғмҡ©лҗ©лӢҲлӢӨ.'))) return;

  let userRemoved = 0, pluginRemoved = 0, errs = 0;
  // 1) Remove user hooks: filter out matching entries in settings.hooks.PreToolUse
  try {
    const newSettings = JSON.parse(JSON.stringify(settings || {}));
    const ev = (newSettings.hooks || {}).PreToolUse;
    if (Array.isArray(ev)) {
      const before = ev.length;
      newSettings.hooks.PreToolUse = ev.filter(item => {
        const m = item && item.matcher;
        return !(m && /\b(Edit|Write|Bash|MultiEdit|NotebookEdit)\b/.test(m));
      });
      userRemoved = before - newSettings.hooks.PreToolUse.length;
      if (!newSettings.hooks.PreToolUse.length) delete newSettings.hooks.PreToolUse;
      if (userRemoved > 0) {
        await api('/api/settings', {
          method: 'PUT', headers: {'Content-Type':'application/json'},
          body: JSON.stringify(newSettings),
        });
      }
    }
  } catch (e) { errs++; console.warn('panic user-hooks remove failed', e); }

  // 2) Plugin hooks: call /api/hooks/plugin/update op:delete for each. Walk
  //    by descending (groupIdx, subIdx) so removing earlier entries doesn't
  //    shift later indices.
  const pluginTargets = targets.filter(h => h.scope === 'plugin');
  pluginTargets.sort((a,b) => (b.groupIdx-a.groupIdx) || (b.subIdx-a.subIdx));
  for (const h of pluginTargets) {
    try {
      const r = await api('/api/hooks/plugin/update', {
        method: 'POST', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ op:'delete', pluginKey: h.pluginKey, event: h.event, groupIdx: h.groupIdx, subIdx: h.subIdx }),
      });
      if (r.ok) pluginRemoved++; else errs++;
    } catch (e) { errs++; console.warn('panic plugin-hook delete failed', e); }
  }

  toast(t('мң„н—ҳ нӣ… л№„нҷңм„ұнҷ” мҷ„лЈҢ') + ` вҖ” ${t('мӮ¬мҡ©мһҗ')} ${userRemoved} В· ${t('н”Ңлҹ¬к·ёмқё')} ${pluginRemoved}` + (errs?` В· ${t('мӢӨнҢЁ')} ${errs}`:''), errs?'warn':'ok');
  renderView();
}

