AFTER.mcp = () => {
  const el = document.getElementById('mcpQ');
  if (!el) return;
  let d;
  el.addEventListener('input', e => {
    clearTimeout(d);
    d = setTimeout(() => { state.data.mcpFilter = e.target.value; renderView(); }, 200);
  });
};

async function installMcp(id) {
  // 1) prepare вҖ” н•„мҡ”н•ң env/к°’ мЎ°нҡҢ
  const prep = await api('/api/mcp/install/prepare', {
    method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id })
  });
  if (prep.error) { toast(errMsg(prep), 'err'); return; }
  const placeholders = prep.placeholders || [];

  // 2) лӘЁлӢ¬лЎң мқҙлҰ„ + к°Ғ env к°’ мһ…л Ҙ
  const fieldHtml = placeholders.map(p => {
    const hint = p.hint || '';
    const example = {
      GITHUB_TOKEN: 'ghp_xxxxxxxxxxxxxxxxxxxx',
      GITHUB_PERSONAL_ACCESS_TOKEN: 'ghp_xxxxxxxxxxxxxxxxxxxx',
      PATH: '/Users/yoo/projects',
      PROJECT_ROOT: '/Users/yoo/my-project',
    }[p.key] || '';
    const isSecret = /TOKEN|KEY|SECRET|PASSWORD/i.test(p.key);
    return `
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">${escapeHtml(p.key)} ${isSecret?'<span class="chip chip-warn text-[9px]">secret</span>':''}</div>
        <input class="input mcp-ph-input" data-key="${escapeHtml(p.key)}" type="${isSecret?'password':'text'}" placeholder="${escapeHtml(example)}" />
        ${hint ? `<div class="text-[10px] text-[var(--text-dim)] mt-1">${escapeHtml(hint)}</div>` : ''}
        <div class="text-[10px] text-[var(--text-mute)] mt-1 mono truncate">where: ${escapeHtml(p.where)} В· мӣҗліё: ${escapeHtml(p.raw||'')}</div>
      </div>`;
  }).join('');

  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <div>
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">пјӢ MCP м„Өм№ҳ</div>
        <h2 class="text-lg font-bold">${escapeHtml(prep.name || id)}</h2>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div class="p-5 space-y-3">
      <div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">л“ұлЎқн•  мқҙлҰ„</div>
        <input id="mcpAsName" class="input" value="${escapeHtml(id)}" />
      </div>
      ${placeholders.length ? `
        <div class="card p-3" style="background:rgba(251,191,36,0.08);">
          <div class="text-sm font-semibold mb-2">вҡ пёҸ н•„мҲҳ к°’ ${placeholders.length}к°ң мһ…л Ҙ</div>
          <div class="space-y-3">${fieldHtml}</div>
        </div>` : '<div class="text-xs text-[var(--text-dim)]">м¶”к°Җ м„Өм • м—Ҷмқҙ л°”лЎң м„Өм№ҳ к°ҖлҠҘн•©лӢҲлӢӨ.</div>'}
      <details class="text-[11px]">
        <summary class="cursor-pointer text-[var(--text-dim)]">рҹ“Ӣ м„Өм№ҳ spec лҜёлҰ¬ліҙкё°</summary>
        <pre class="mono text-[10px] whitespace-pre-wrap bg-[var(--code-bg)] p-2 rounded mt-2">${escapeHtml(JSON.stringify(prep.preview, null, 2))}</pre>
      </details>
    </div>
    <div class="p-4 border-t border-[var(--border)] flex justify-end gap-2">
      <button class="btn" onclick="closeModal()">м·ЁмҶҢ</button>
      <button class="btn-primary btn" id="mcpInstallBtn">м„Өм№ҳ</button>
    </div>
  `);
  document.getElementById('mcpInstallBtn').onclick = async () => {
    const asName = document.getElementById('mcpAsName').value.trim() || id;
    const values = {};
    document.querySelectorAll('.mcp-ph-input').forEach(el => {
      const k = el.dataset.key; const v = el.value.trim();
      if (v) values[k] = v;
    });
    const missing = placeholders.filter(p => !values[p.key]).map(p => p.key);
    if (missing.length) { toast('н•„мҲҳ к°’ лҲ„лқҪ: ' + missing.join(', '), 'warn'); return; }
    const r = await api('/api/mcp/install', {
      method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ id, as: asName, values }),
    });
    if (r.ok) {
      toast(`'${r.name}' м„Өм№ҳлҗЁ`, 'ok');
      closeModal();
    } else {
      toast(errMsg(r), 'err');
    }
  };
}

async function removeMcp(name) {
  const ok = await confirmModal({
    title: t('MCP м„ңлІ„ м ңкұ°'),
    message: `'${name}' вҖ” ~/.claude.json ` + t('м—җм„ң м ңкұ°лҗ©лӢҲлӢӨ.'),
    confirmLabel: t('м ңкұ°'), danger: true,
  });
  if (!ok) return;
  const r = await api('/api/mcp/remove', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ name }) });
  if (r.ok) toast(`'${name}' м ңкұ°лҗЁ`, 'ok');
  else toast(errMsg(r), 'err');
}

async function removeProjectMcp(cwd, name) {
  const ok = await confirmModal({
    title: t('н”„лЎңм қнҠё MCP м ңкұ°'),
    message: `'${name}' вҖ” ${cwd}/.mcp.json ` + t('м—җм„ң мӮӯм ңлҗ©лӢҲлӢӨ.'),
    confirmLabel: t('м ңкұ°'), danger: true,
  });
  if (!ok) return;
  const r = await api('/api/mcp/project/remove', {
    method:'POST', headers:{'Content-Type':'application/json'},
    body: JSON.stringify({ cwd, name }),
  });
  if (r.ok) toast(`'${name}' м ңкұ°лҗЁ (${r.configPath})`, 'ok');
  else toast(errMsg(r), 'err');
}

AFTER.mcp = () => {
  // v2.33.7 вҖ” м»Өл„Ҙн„° health probe (л№„лҸҷкё°)
  api('/api/mcp/health').then(r => {
    if (!r || !r.ok) return;
    const h = r.health || {};
    document.querySelectorAll('.mcp-health-chip').forEach(el => {
      const id = el.dataset.mcpId;
      const row = h[id];
      if (!row) return;
      const { status, note } = row;
      const cls = status === 'ok' ? 'chip-ok' : status === 'offline' ? 'chip-err' : '';
      const label = status === 'ok' ? t('probe ok') : status === 'offline' ? t('probe мӢӨнҢЁ') : t('probe лҜёмғҒ');
      el.innerHTML = `<span class="chip ${cls} text-[9px]" title="${escapeHtml(note || '')}">${label}</span>`;
    });
  }).catch(() => {});
};
function renderConnectorGroup(title, list, allowRemove) {
  const statusBadge = (m) => {
    if (m.connected === true) return '<span class="chip chip-ok text-[9px]" style="white-space:nowrap;">вң“ м—°кІ°лҗЁ</span>';
    if (m.needsAuth) return '<span class="chip chip-warn text-[9px]" style="white-space:nowrap;">рҹ”җ мқёмҰқ н•„мҡ”</span>';
    if (m.connected === false) return '<span class="chip chip-err text-[9px]" style="white-space:nowrap;">вң— мӢӨнҢЁ</span>';
    return '';
  };
  return `
    <div class="card p-5 mb-4">
      <h3 class="font-semibold text-sm mb-3">${title} В· ${list.length}</h3>
      <div class="grid-list">
        ${list.map(m => `
          <div class="card p-3 hover-lift" style="overflow:hidden;">
            <div class="flex items-center justify-between mb-2 gap-2">
              <div class="flex items-center gap-2 min-w-0 flex-1">
                <span class="pulse-dot ${m.connected===false?'off':''}"></span>
                <div class="font-semibold text-sm truncate" title="${escapeHtml(m.name)}">${escapeHtml(m.name)}</div>
              </div>
              <div class="flex items-center gap-1 flex-shrink-0">
                ${statusBadge(m)}
                <span class="mcp-health-chip" data-mcp-id="${escapeHtml(m.id || m.name)}"></span>
                ${m.scope === 'project' && m.projectCwd
                  ? `<button class="btn text-[10px]" style="color:#fca5a5" onclick="removeProjectMcp(JSON.parse(this.dataset.cwd), JSON.parse(this.dataset.name))" data-cwd="${jsonAttr(m.projectCwd)}" data-name="${jsonAttr(m.name)}">м ңкұ°</button>`
                  : (allowRemove ? `<button class="btn text-[10px]" style="color:#fca5a5" onclick="removeMcp(JSON.parse(this.dataset.payload))" data-payload="${jsonAttr(m.name)}">м ңкұ°</button>` : '')}
              </div>
            </div>
            ${m.endpoint ? `<div class="text-[10px] mono text-[var(--text-dim)] truncate" title="${escapeHtml(m.endpoint)}">${escapeHtml(m.endpoint)}</div>` : ''}
            ${(m.type || m.command) ? `<div class="text-[10px] mono text-[var(--text-dim)] truncate">${escapeHtml(m.type||'')} В· ${escapeHtml(m.command||'')}</div>`:''}
            ${m.args && m.args.length ? `<div class="text-[10px] mono text-[var(--text-mute)] truncate mt-1">${escapeHtml(m.args.join(' '))}</div>`: ''}
            ${m.missingEnv && m.missingEnv.length ? `<div class="text-[10px] mt-2 p-1.5 rounded" style="background:rgba(248,113,113,0.1); color:#fca5a5;">вҡ пёҸ нҷҳкІҪліҖмҲҳ лҲ„лқҪ: ${m.missingEnv.map(k=>`<code class="mono">${escapeHtml(k)}</code>`).join(', ')}</div>` : ''}
            ${m.projectCwd ? `<div class="text-[10px] text-[var(--text-dim)] mt-1 truncate">рҹ“Ғ ${escapeHtml(m.projectCwd)}</div>` : ''}
            ${m.description ? `<div class="text-[10px] text-[var(--text-mute)] mt-1 line-clamp-2">${escapeHtml(m.description)}</div>` : ''}
          </div>
        `).join('') || `<div class="empty text-xs" style="grid-column:1/-1;">м—ҶмқҢ</div>`}
      </div>
    </div>
  `;
}

VIEWS.plugins = async () => {
  const [browse, markets] = await Promise.all([api('/api/plugins/browse'), api('/api/marketplaces')]);
  state.data.pluginsBrowse = browse.plugins;
  const q = (state.data.pluginFilter || '').toLowerCase();
  const selMkt = state.data.pluginMkt || '';
  const onlyEnabled = !!state.data.pluginOnlyEnabled;

  const filtered = browse.plugins.filter(p => {
    if (q && !(p.name+' '+p.description+' '+(p.tags||[]).join(' ')+' '+p.marketplace).toLowerCase().includes(q)) return false;
    if (selMkt && p.marketplace !== selMkt) return false;
    if (onlyEnabled && !p.enabled) return false;
    return true;
  });

  const enabledCount = browse.plugins.filter(p => p.enabled).length;
  const mktCounts = {};
  browse.plugins.forEach(p => { mktCounts[p.marketplace] = (mktCounts[p.marketplace]||0)+1; });

  return `
    <div class="mb-4 flex items-center justify-between gap-2 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">н”Ңлҹ¬к·ёмқё</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${browse.plugins.length}к°ң м „мІҙ В· ${enabledCount}к°ң нҷңм„ұ В· ${browse.marketplaces}к°ң л§Ҳмј“н”Ңл ҲмқҙмҠӨ В· ${_localizedDescStatusText(browse.plugins)}</p>
      </div>
      <div class="flex gap-2">
        <button class="btn-primary btn text-xs" onclick="aiRecommendList('plugins')">рҹӨ– AI м¶”мІң</button>
        ${_localizeBtnHtml('plugin', browse.plugins)}
        <a class="btn text-xs" href="${DOCS_BASE}plugins" target="_blank" rel="noopener">рҹ“– кіөмӢқ л¬ём„ң вҶ—</a>
      </div>
    </div>

    <div class="card p-3 mb-4 flex flex-wrap items-center gap-2">
      <input id="pluginQ" class="input max-w-[260px] text-xs" placeholder="кІҖмғү: kotlin, security, django..." value="${escapeHtml(state.data.pluginFilter||'')}" />
      <button class="chip ${!selMkt?'chip-accent':''}" onclick="setPluginMkt('')">м „мІҙ ${browse.plugins.length}</button>
      ${Object.entries(mktCounts).map(([m,n]) => `<button class="chip ${m===selMkt?'chip-accent':''}" onclick="setPluginMkt('${escapeHtml(m)}')">${escapeHtml(m)} ${n}</button>`).join('')}
      <label class="flex items-center gap-1 text-xs text-[var(--text-mute)] ml-auto">
        <input type="checkbox" id="pluginOnlyEnabled" ${onlyEnabled?'checked':''}/> нҷңм„ұл§Ң
      </label>
    </div>

    <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
      ${filtered.map(p => `
        <div class="card p-4 hover-lift">
          <div class="flex items-start justify-between gap-2 mb-1">
            <div class="min-w-0 flex-1">
              <div class="font-semibold text-sm truncate">${escapeHtml(p.name)}</div>
              <div class="text-[10px] mono text-[var(--text-dim)] truncate">${escapeHtml(p.marketplace)}${p.version?' В· v'+escapeHtml(p.version):''}</div>
            </div>
            <label class="switch inline-flex items-center cursor-pointer gap-1 text-xs">
              <input type="checkbox" ${p.enabled?'checked':''} onchange="togglePlugin('${escapeHtml(p.id)}', this.checked)"/>
              <span>${p.enabled?'нҷңм„ұ':'л№„нҷңм„ұ'}</span>
            </label>
          </div>
          <div class="text-xs text-[var(--text-mute)] line-clamp-3 mb-2" style="min-height:3.2em;">${escapeHtml(_localDesc(p) || 'вҖ”')}</div>
          <div class="flex gap-1 flex-wrap mb-2">
            ${(p.tags||[]).slice(0,4).map(t => `<span class="chip text-[9px]">${escapeHtml(t)}</span>`).join('')}
          </div>
          <div class="text-[10px] text-[var(--text-dim)] flex gap-2">
            ${p.counts.agents?`<span>рҹӨқ${p.counts.agents}</span>`:''}
            ${p.counts.skills?`<span>вңЁ${p.counts.skills}</span>`:''}
            ${p.counts.commands?`<span>/${p.counts.commands}</span>`:''}
            ${p.counts.hooks?`<span>рҹӘқ${p.counts.hooks}</span>`:''}
            ${!p.installed?'<span class="ml-auto" style="color:#fbbf24">лҜём„Өм№ҳ (CLI)</span>':''}
          </div>
        </div>`).join('') || `<div class="card empty" style="grid-column:1/-1;">н•„н„° кІ°кіј м—ҶмқҢ</div>`}
    </div>

    <div class="mt-5 card p-4 text-xs text-[var(--text-mute)]">
      рҹ’Ў мғҲ л§Ҳмј“н”Ңл ҲмқҙмҠӨ м¶”к°ҖлҠ” н„°лҜёл„җм—җм„ң <code class="mono">claude marketplace add &lt;git-url&gt;</code>. м„Өм№ҳ нӣ„ м—¬кё°м—җ лӮҳнғҖлӮ©лӢҲлӢӨ. нҷңм„ұнҷ” нҶ кёҖмқҖ <code class="mono">~/.claude/settings.json</code> мқҳ <code class="mono">enabledPlugins</code> м—җ мҰүмӢң л°ҳмҳҒлҗ©лӢҲлӢӨ.
    </div>
  `;
};
AFTER.plugins = () => {
  const el = document.getElementById('pluginQ');
  if (el) {
    let d;
    el.addEventListener('input', e => {
      clearTimeout(d);
      d = setTimeout(() => { state.data.pluginFilter = e.target.value; renderView(); }, 200);
    });
  }
  const chk = document.getElementById('pluginOnlyEnabled');
  if (chk) chk.onchange = e => { state.data.pluginOnlyEnabled = e.target.checked; renderView(); };
};
function setPluginMkt(m) { state.data.pluginMkt = m; renderView(); }

async function togglePlugin(id, enable) {
  const r = await api('/api/plugins/toggle', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ id, enable }) });
  toast(r.ok ? (enable?'нҷңм„ұнҷ”лҗЁ':'л№„нҷңм„ұнҷ”лҗЁ') : ('мӢӨнҢЁ: '+(r.error||'unknown')), r.ok?'ok':'err');
  if (r.ok) {
    // нҳ„мһ¬ view мғҒнғң мң м§Җн•ҳл©° мһ¬л ҢлҚ”
    renderView();
  }
}

