// SETTINGS EDITOR
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.settings = async () => {
  const projects = await _ensureProjectsCache();
  const scope = state.data.cfgScope || 'global';
  const cwd = state.data.cfgCwd || (projects[0]?.path || '');
  // v2.43.0 вҖ” when scope=project, settings.json (committed) and
  // settings.local.json (gitignored personal overrides) are two separate
  // files; the user picks which one to edit via `cfgSettingsKind`.
  const settingsKind = state.data.cfgSettingsKind || 'project';  // 'project' | 'project-local'
  const isProject = scope === 'project' && cwd;
  let raw, pathLabel, fixedNote = '', exists = true;
  if (isProject) {
    const ep = settingsKind === 'project-local' ? 'settings-local' : 'settings';
    const r = await api('/api/project/' + ep + '?cwd=' + encodeURIComponent(cwd));
    raw = r.raw || '{}';
    pathLabel = r.path || '';
    exists = !!r.exists;
  } else {
    const settings = await api('/api/settings');
    raw = JSON.stringify(settings || {}, null, 2);
    pathLabel = '~/.claude/settings.json';
  }
  // recommended profiles only apply to global scope.
  let rec = {profiles: []};
  if (!isProject) {
    rec = await api('/api/guide/recommended-settings').catch(() => ({profiles: []}));
    window.__recProfiles = rec.profiles;
  }
  return `
    ${_renderConfigScopeToggle({scope, cwd, projects, label: t('Settings мҠӨмҪ”н”„')})}
    ${isProject ? `
      <div class="card p-3 mb-3" style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;">
        <span class="text-[11px] uppercase tracking-wider text-[var(--text-dim)]">${t('нҢҢмқј')}</span>
        <button class="chip text-[11px] cursor-pointer" style="${settingsKind==='project'?'background:var(--accent);color:#fff;':''}" onclick="state.data.cfgSettingsKind='project';renderView();">settings.json <span class="text-[10px] opacity-70">${t('(м»Өл°ӢлҗЁ)')}</span></button>
        <button class="chip text-[11px] cursor-pointer" style="${settingsKind==='project-local'?'background:var(--accent);color:#fff;':''}" onclick="state.data.cfgSettingsKind='project-local';renderView();">settings.local.json <span class="text-[10px] opacity-70">${t('(к°ңмқё, gitignore)')}</span></button>
        ${!exists ? `<span class="chip chip-warn text-[10px]">${t('нҢҢмқј м—ҶмқҢ вҖ” м ҖмһҘ мӢң мғқм„ұлҗЁ')}</span>` : ''}
      </div>
    ` : ''}
    <div class="mb-4 flex items-center justify-between gap-2 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">${t('Settings нҺём§‘')}</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${escapeHtml(pathLabel)} вҖ” ${t("нҺём§‘ нӣ„ 'м ҖмһҘ' н•ҳл©ҙ нҢҢмқјм—җ мҰүмӢң л°ҳмҳҒлҗ©лӢҲлӢӨ.")}</p>
      </div>
      <div class="flex gap-2">
        <button class="btn" onclick="copySettings()">рҹ“Ӣ ${t('ліөмӮ¬')}</button>
        <button class="btn-primary btn" onclick="saveSettings()">рҹ’ҫ ${t('м ҖмһҘ')}</button>
        <a class="btn text-xs" href="${DOCS_BASE}settings" target="_blank" rel="noopener">рҹ“– ${t('кіөмӢқ л¬ём„ң')} вҶ—</a>
      </div>
    </div>
    <div class="grid grid-cols-1 lg:grid-cols-3 gap-4">
      <div class="lg:col-span-2 card p-4">
        <textarea id="settingsEditor" class="input" style="min-height: 520px;">${escapeHtml(raw)}</textarea>
        <div class="text-xs text-[var(--text-mute)] mt-2">вҡ пёҸ ${t('мң нҡЁн•ң JSON мқҙм–ҙм•ј м ҖмһҘлҗ©лӢҲлӢӨ.')}</div>
      </div>
      <div class="space-y-3">
        ${isProject ? `
          <div class="card p-4 text-xs text-[var(--text-mute)]">
            <div class="font-semibold text-[var(--text)] mb-2">рҹ“Ғ ${t('н”„лЎңм қнҠё мҠӨмҪ”н”„')}</div>
            <ul class="space-y-1">
              <li>вҖў <code>settings.json</code>: ${t('нҢҖкіј кіөмң  вҖ” gitм—җ м»Өл°Ӣ')}</li>
              <li>вҖў <code>settings.local.json</code>: ${t('к°ңмқё мҳӨлІ„лқјмқҙл“ң вҖ” gitignore к¶ҢмһҘ')}</li>
              <li>вҖў ${t('Claude CodeлҠ” н”„лЎңм қнҠё в–¶ кёҖлЎңлІҢ мҲңм„ңлЎң лЁём§Җн•©лӢҲлӢӨ.')}</li>
            </ul>
          </div>
        ` : `
          <div class="text-[11px] uppercase text-[var(--text-dim)]">${t('м¶”мІң н”„лЎңнҢҢмқј')}</div>
          <div class="text-xs text-[var(--text-mute)]">${t('нҒҙлҰӯ мӢң Auth нҷ•мқё вҶ’ ліҖкІҪ лҜёлҰ¬ліҙкё° вҶ’ м Ғмҡ©к№Ңм§Җ м•ҲлӮҙлҗ©лӢҲлӢӨ.')}</div>
          ${(rec.profiles||[]).map((p,i) => `
            <div class="card p-4 hover-lift cursor-pointer" onclick="startProfileFlow(${i})">
              <div class="flex items-center justify-between mb-1">
                <div class="font-semibold text-sm">${escapeHtml(p.name)}</div>
                <span class="text-[10px] text-[var(--text-dim)]">вҶ’ ${t('м Ғмҡ©н•ҳкё°')}</span>
              </div>
              <div class="text-xs text-[var(--text-mute)]">${escapeHtml(p.description)}</div>
            </div>
          `).join('')}
        `}
        <div class="card p-4 text-xs text-[var(--text-mute)]">
          <div class="font-semibold text-[var(--text)] mb-2">рҹ’Ў ${t('нҢҒ')}</div>
          <ul class="space-y-1">
            <li>вҖў <code>permissions.allow</code>: ${t('мһҗлҸҷ мҠ№мқё к·ңм№ҷ')}</li>
            <li>вҖў <code>permissions.deny</code>: ${t('м ҲлҢҖ кёҲм§Җ к·ңм№ҷ')}</li>
            <li>вҖў <code>hooks</code>: ${t('мқҙлІӨнҠё кё°л°ҳ мһҗлҸҷ мҠӨнҒ¬лҰҪнҠё')}</li>
            <li>вҖў <code>enabledPlugins</code>: ${t('нҷңм„ұнҷ” н”Ңлҹ¬к·ёмқё')}</li>
          </ul>
        </div>
      </div>
    </div>
  `;
};
function copySettings() {
  const t = document.getElementById('settingsEditor').value;
  navigator.clipboard.writeText(t).then(() => toast('ліөмӮ¬лҗЁ', 'ok'));
}
async function saveSettings() {
  const txt = document.getElementById('settingsEditor').value;
  let parsed;
  try { parsed = JSON.parse(txt); } catch (e) { toast(t('JSON мҳӨлҘҳ') + ': ' + e.message, 'err'); return; }
  const scope = state.data.cfgScope || 'global';
  const cwd = state.data.cfgCwd || '';
  const kind = state.data.cfgSettingsKind || 'project';
  let r;
  if (scope === 'project' && cwd) {
    const ep = kind === 'project-local' ? '/api/project/settings-local' : '/api/project/settings';
    r = await api(ep, {
      method: 'PUT', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ cwd, data: parsed }),
    });
  } else {
    r = await api('/api/settings', {
      method: 'PUT', headers: {'Content-Type':'application/json'},
      body: JSON.stringify(parsed),
    });
  }
  toast(r.ok ? t('м ҖмһҘлҗЁ') : (t('м ҖмһҘ мӢӨнҢЁ') + (r.error ? ': ' + r.error : '')), r.ok ? 'ok' : 'err');
}
function applyProfile(i) {
  // кө¬ лІ„м „ нҳёнҷҳмҡ© вҖ” editorм—җ м§Ғм ‘ лЁём§Җл§Ң (м ҖмһҘ нҒҙлҰӯ н•„мҡ”)
  const prof = (window.__recProfiles||[])[i];
  if (!prof) return;
  const cur = document.getElementById('settingsEditor');
  try {
    const existing = JSON.parse(cur.value || '{}');
    const merged = { ...existing, ...prof.settings, permissions: { ...(existing.permissions||{}), ...prof.settings.permissions } };
    cur.value = JSON.stringify(merged, null, 2);
    toast(`"${prof.name}" н”„лЎңнҢҢмқј м Ғмҡ©лҗЁ вҖ” м ҖмһҘмқ„ лҲҢлҹ¬ л°ҳмҳҒ`, 'info');
  } catch {
    cur.value = JSON.stringify(prof.settings, null, 2);
  }
}

// в”Җв”Җ м¶”мІң н”„лЎңнҢҢмқј 3лӢЁкі„ м Ғмҡ© н”ҢлЎңмҡ° в”Җв”Җ
async function startProfileFlow(i) {
  const prof = (window.__recProfiles||[])[i];
  if (!prof) return;

  // мҠӨн…қ 1: Auth нҷ•мқё нҷ”л©ҙ (лЎңл”©)
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <h2 class="font-semibold">м¶”мІң м Ғмҡ©: ${escapeHtml(prof.name)}</h2>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div id="profileFlowBody" class="p-5 flex-1 overflow-y-auto space-y-5">
      <div class="flex items-center gap-3">
        <div class="shimmer w-5 h-5 rounded-full"></div>
        <span class="text-sm">Claude кі„м • м—°кІ° нҷ•мқё мӨ‘вҖҰ</span>
      </div>
    </div>
  `);

  let auth, preview;
  try {
    [auth, preview] = await Promise.all([
      api('/api/auth/status'),
      api('/api/settings/preview', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ patch: prof.settings }) }),
    ]);
  } catch (e) {
    document.getElementById('profileFlowBody').innerHTML = `<div class="empty text-sm">л¶Ҳлҹ¬мҳӨкё° мӢӨнҢЁ: ${escapeHtml(e.message)}</div>`;
    return;
  }

  const step1 = auth.connected
    ? `<div class="card p-4 flex items-center gap-3" style="border-color: rgba(74,222,128,0.35);">
         <div class="text-2xl">вң…</div>
         <div class="flex-1">
           <div class="text-xs uppercase tracking-widest text-[var(--text-dim)]">1. кі„м • м—°кІ°</div>
           <div class="font-semibold text-sm">${escapeHtml(auth.displayName) || _renderEmail(auth.email)} В· ${escapeHtml(auth.planLabel)}</div>
           <div class="text-xs text-[var(--text-mute)] mt-0.5">${_renderEmail(auth.email)} В· мЎ°м§Ғ м—ӯн• : ${escapeHtml(auth.organizationRole||'вҖ”')}</div>
         </div>
         <span class="chip chip-ok">м—°кІ°лҗЁ</span>
       </div>`
    : `<div class="card p-4 flex items-center gap-3" style="border-color: rgba(248,113,113,0.35);">
         <div class="text-2xl">вқҢ</div>
         <div class="flex-1">
           <div class="text-xs uppercase tracking-widest text-[var(--text-dim)]">1. кі„м • м—°кІ°</div>
           <div class="font-semibold text-sm">м—°кІ°лҗҳм§Җ м•ҠмқҢ</div>
           <div class="text-xs text-[var(--text-mute)] mt-0.5">${escapeHtml(auth.reason||'Claudeм—җ лЎңк·ёмқёлҗҳм§Җ м•ҠмқҢ')}</div>
           <div class="text-xs mt-2 mono">н„°лҜёл„җм—җм„ң <code>claude login</code> мӢӨн–ү нӣ„ лӢӨмӢң мӢңлҸ„н•ҳм„ёмҡ”.</div>
         </div>
       </div>`;

  const diff = preview.diff || {};
  const diffList = (arr, color) => arr.length
    ? `<ul class="text-xs space-y-0.5 mono">${arr.map(x=>`<li style="color:${color}">+ ${escapeHtml(x)}</li>`).join('')}</ul>`
    : '<div class="text-xs text-[var(--text-dim)]">м—ҶмқҢ</div>';

  const step2 = `
    <div class="card p-4">
      <div class="text-xs uppercase tracking-widest text-[var(--text-dim)] mb-3">2. ліҖкІҪ лҜёлҰ¬ліҙкё°</div>
      <div class="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <div class="text-[11px] font-semibold text-[var(--ok)] mb-1.5">вң… м¶”к°Җлҗ  н—Ҳмҡ© (${diff.addedAllow.length})</div>
          ${diffList(diff.addedAllow, '#86efac')}
        </div>
        <div>
          <div class="text-[11px] font-semibold text-[var(--err)] mb-1.5">рҹҡ« м¶”к°Җлҗ  м°ЁлӢЁ (${diff.addedDeny.length})</div>
          ${diffList(diff.addedDeny, '#fca5a5')}
        </div>
      </div>
      ${diff.topChanged.length ? `<div class="mt-3 text-xs"><span class="text-[var(--text-mute)]">лӢӨлҘё ліҖкІҪ нӮӨ:</span> ${diff.topChanged.map(k=>`<code class="mono">${escapeHtml(k)}</code>`).join(', ')}</div>` : ''}
      <details class="mt-4">
        <summary class="cursor-pointer text-xs text-[var(--text-mute)]">м „мІҙ лі‘н•© кІ°кіј ліҙкё° (raw JSON)</summary>
        <pre class="mono text-[10px] whitespace-pre-wrap bg-[var(--code-bg)] p-3 rounded mt-2 max-h-[240px] overflow-y-auto">${escapeHtml(JSON.stringify(preview.merged, null, 2))}</pre>
      </details>
    </div>`;

  const step3 = `
    <div class="card p-4 flex items-center justify-between gap-3">
      <div>
        <div class="text-xs uppercase tracking-widest text-[var(--text-dim)] mb-1">3. м Ғмҡ©</div>
        <div class="text-sm">${diff.addedAllow.length + diff.addedDeny.length === 0 ? 'мқҙлҜё лҸҷмқјн•ң к·ңм№ҷмқҙ мЎҙмһ¬н•©лӢҲлӢӨ вҖ” ліҖкІҪ м—ҶмқҢ.' : 'нҷ•мқён•ҳкі  settings.json м—җ мҰүмӢң м ҖмһҘн•©лӢҲлӢӨ.'}</div>
      </div>
      <div class="flex gap-2">
        <button class="btn" onclick="closeModal()">м·ЁмҶҢ</button>
        <button id="profileApplyBtn" class="btn-primary btn" ${!auth.connected ? 'disabled style="opacity:0.4;cursor:not-allowed;"' : ''}>рҹ’ҫ м Ғмҡ©</button>
      </div>
    </div>`;

  document.getElementById('profileFlowBody').innerHTML = step1 + step2 + step3;

  const applyBtn = document.getElementById('profileApplyBtn');
  if (applyBtn && auth.connected) {
    applyBtn.onclick = async () => {
      applyBtn.disabled = true;
      applyBtn.textContent = 'м Ғмҡ© мӨ‘вҖҰ';
      try {
        const r = await api('/api/settings', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(preview.merged),
        });
        if (r.ok) {
          toast(`"${prof.name}" м Ғмҡ©лҗЁ`, 'ok');
          closeModal();
          renderView();
        } else {
          toast('м ҖмһҘ мӢӨнҢЁ: ' + (r.error||'м•Ң мҲҳ м—ҶмқҢ'), 'err');
          applyBtn.disabled = false;
          applyBtn.textContent = 'рҹ’ҫ м Ғмҡ©';
        }
      } catch (e) {
        toast('мӢӨнҢЁ: ' + e.message, 'err');
        applyBtn.disabled = false;
        applyBtn.textContent = 'рҹ’ҫ м Ғмҡ©';
      }
    };
  }
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// CLAUDE.md EDITOR
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// v2.43.0 вҖ” global вҶ” project scope toggle for setup helpers (CLAUDE.md /
// settings / settings.local / skills / commands / hooks). One shared state
// (`state.data.cfgScope`, `state.data.cfgCwd`) keeps the user's pick across
// tabs so they don't re-pick a project on every navigation.
async function _ensureProjectsCache() {
  if (window.__cfgProjects) return window.__cfgProjects;
  const r = await cachedApi('/api/projects', 30000).catch(() => ({projects: []}));
  window.__cfgProjects = (r.projects || []).filter(p => p.cwdResolved && p.path);
  return window.__cfgProjects;
}
function _renderConfigScopeToggle({scope, cwd, projects, label}) {
  const opts = projects.map(p => `<option value="${escapeHtml(p.path)}" ${p.path===cwd?'selected':''}>${escapeHtml(p.name)} вҖ” ${escapeHtml(p.path)}</option>`).join('');
  const noProjects = projects.length === 0;
  return `
    <div class="card p-3 mb-3" style="display:flex;align-items:center;gap:12px;flex-wrap:wrap;">
      <span class="text-[11px] uppercase tracking-wider text-[var(--text-dim)]">${escapeHtml(label || t('мҠӨмҪ”н”„'))}</span>
      <div class="flex gap-1">
        <button class="chip text-[11px] cursor-pointer" style="${scope==='global'?'background:var(--accent);color:#fff;':''}" onclick="setConfigScope('global')">рҹҢҗ ${t('кёҖлЎңлІҢ')}</button>
        <button class="chip text-[11px] cursor-pointer" style="${scope==='project'?'background:var(--accent);color:#fff;':''}" onclick="setConfigScope('project')" ${noProjects?'disabled':''}>рҹ“Ғ ${t('н”„лЎңм қнҠё')}</button>
      </div>
      ${scope==='project' ? `
        <select class="input text-xs" style="min-width:280px;" onchange="setConfigScope('project', this.value)">
          ${noProjects ? `<option value="">${t('мқёлҚұмҠӨлҗң н”„лЎңм қнҠё м—ҶмқҢ')}</option>` : opts}
        </select>
      ` : `<span class="text-[11px] text-[var(--text-dim)]">~/.claude/</span>`}
    </div>`;
}
function setConfigScope(scope, cwd) {
  state.data.cfgScope = scope;
  if (scope === 'project') {
    if (cwd) {
      state.data.cfgCwd = cwd;
    } else if (!state.data.cfgCwd && window.__cfgProjects?.length) {
      state.data.cfgCwd = window.__cfgProjects[0].path;
    }
  }
  renderView();
}

VIEWS.claudemd = async () => {
  const projects = await _ensureProjectsCache();
  const scope = state.data.cfgScope || 'global';
  const cwd = state.data.cfgCwd || (projects[0]?.path || '');
  const isProject = scope === 'project' && cwd;
  const d = isProject
    ? await api('/api/project/claude-md?cwd=' + encodeURIComponent(cwd))
    : await api('/api/claude-md');
  const raw = d.raw || '';
  const isEmpty = !raw.trim();
  const pathLabel = isProject ? (cwd + '/CLAUDE.md') : '~/.claude/CLAUDE.md';
  const blurb = isProject
    ? t('мқҙ н”„лЎңм қнҠём—җм„ң мһ‘м—…н•  л•Ңл§Ң лЎңл“ңлҗҳлҠ” м§Җм№Ё.')
    : t('лӘЁл“  м„ём…ҳм—җ лЎңл“ңлҗҳлҠ” кёҖлЎңлІҢ м§Җм№Ё.');
  return `
    ${_renderConfigScopeToggle({scope, cwd, projects, label: t('CLAUDE.md мҠӨмҪ”н”„')})}
    <div class="mb-4 flex items-center justify-between flex-wrap gap-2">
      <div>
        <h1 class="text-2xl font-bold">CLAUDE.md</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${escapeHtml(pathLabel)} вҖ” ${blurb}${isEmpty?' <span class="chip chip-warn ml-2">'+t('нҢҢмқј м—ҶмқҢ')+'</span>':''}</p>
      </div>
      <div class="flex gap-2">
        ${isProject ? '' : '<button class="btn" onclick="startGlobalClaudeMdRecommend()">рҹӨ– AI м—җкІҢ м¶”мІң</button>'}
        <button class="btn-primary btn" onclick="saveClaudeMd()">рҹ’ҫ ${t('м ҖмһҘ')}</button>
        <a class="btn text-xs" href="${DOCS_BASE}memory" target="_blank" rel="noopener">рҹ“–</a>
      </div>
    </div>
    ${isEmpty ? `
      <div class="card p-5 mb-4" style="background: linear-gradient(135deg, rgba(217,119,87,0.08), transparent);">
        <div class="font-semibold text-sm mb-1">${isProject ? t('м•„м§Ғ н”„лЎңм қнҠё CLAUDE.md к°Җ м—ҶмҠөлӢҲлӢӨ') : t('м•„м§Ғ кёҖлЎңлІҢ CLAUDE.md к°Җ м—ҶмҠөлӢҲлӢӨ')}</div>
        <div class="text-xs text-[var(--text-mute)]">${isProject ? t('мқҙ н”„лЎңм қнҠём—җм„ң мһ‘м—…н•  л•Ңл§Ң лЎңл“ңлҗҳлҠ” м§Җм№Ёмқ„ мһ‘м„ұн•ҳм„ёмҡ”. м ҖмһҘн•ҳл©ҙ мҰүмӢң ' + cwd + '/CLAUDE.md лЎң кё°лЎқлҗ©лӢҲлӢӨ.') : t('м—¬кё°м—җ м ҒмқҖ м§Җм№Ё(кё°м–өВ·к·ңм№ҷВ·м„ нҳё)мқҖ лӘЁл“  м„ём…ҳ мӢңмһ‘ мӢң мһҗлҸҷ лЎңл“ңлҗ©лӢҲлӢӨ. м§Ғм ‘ м“°кұ°лӮҳ, мң„мқҳ "AI м—җкІҢ м¶”мІң л°ӣкё°"лЎң нҳ„мһ¬ мһ‘м—… нҢЁн„ҙ кё°л°ҳ мҙҲм•Ҳмқ„ л°ӣм•„ліҙм„ёмҡ”.')}</div>
      </div>` : ''}
    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4">
      <div class="card p-4">
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('мҶҢмҠӨ')}</div>
        <textarea id="claudeMdEditor" class="input" style="min-height: 560px;">${escapeHtml(raw)}</textarea>
      </div>
      <div class="card p-5 overflow-y-auto" style="max-height: 620px;">
        <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('лҜёлҰ¬ліҙкё°')}</div>
        <div id="claudeMdPreview" class="prose-claude">${isEmpty ? '<div class="empty">'+t('мҶҢмҠӨк°Җ л№„м–ҙмһҲмҠөлӢҲлӢӨ')+'</div>' : marked.parse(raw)}</div>
      </div>
    </div>
  `;
};
async function startGlobalClaudeMdRecommend() {
  showModalLoading(t('Claude м—җкІҢ мҙҲм•Ҳ мҡ”мІӯ мӨ‘ (30~90мҙҲ)вҖҰ'));
  try {
    const r = await api('/api/global/claude-md-recommend', {
      method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({ lang: _curLang }),
    });
    if (r.error) { closeModal(); toast(errMsg(r), 'err'); return; }
    closeModal();
    openDiffApplyModal({
      title: 'кёҖлЎңлІҢ CLAUDE.md мҙҲм•Ҳ',
      relpath: '~/.claude/CLAUDE.md',
      reason: `л№„мҡ© $${(r.costInfo?.costUsd||0).toFixed(4)} В· ${Math.round((r.costInfo?.durationMs||0)/1000)}мҙҲ мҶҢмҡ”. мўҢмёЎмқҖ нҳ„мһ¬ нҢҢмқј, мҡ°мёЎмқҖ AI м ңм•Ҳ. нҺём§‘ нӣ„ мӣҗн•ҳлҠ” мӘҪ м ҖмһҘ.`,
      cwd: '',
      currentRaw: r.existing || '',
      proposedRaw: r.content || '',
      badge: 'рҹӨ– кёҖлЎңлІҢ CLAUDE.md м¶”мІң',
      saveFn: async (newRaw) => api('/api/claude-md', {
        method:'PUT', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ raw: newRaw }),
      }),
    });
  } catch (e) { closeModal(); toast(e.message, 'err'); }
}
AFTER.claudemd = () => {
  const e = document.getElementById('claudeMdEditor');
  const p = document.getElementById('claudeMdPreview');
  if (e && p) {
    e.addEventListener('input', () => { p.innerHTML = marked.parse(e.value); });
  }
};
async function saveClaudeMd() {
  const raw = document.getElementById('claudeMdEditor').value;
  const scope = state.data.cfgScope || 'global';
  const cwd = state.data.cfgCwd || '';
  const r = (scope === 'project' && cwd)
    ? await api('/api/project/claude-md', {
        method: 'PUT', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ cwd, raw }),
      })
    : await api('/api/claude-md', {
        method: 'PUT', headers: {'Content-Type':'application/json'},
        body: JSON.stringify({ raw }),
      });
  toast(r.ok ? t('м ҖмһҘлҗЁ') : (t('м ҖмһҘ мӢӨнҢЁ') + (r.error ? ': ' + r.error : '')), r.ok ? 'ok' : 'err');
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// PROJECTS
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.projects = async () => {
  const [p, summary] = await Promise.all([cachedApi('/api/projects', 30000), cachedApi('/api/briefing/projects-summary', 30000)]);
  const summaryMap = {};
  (summary.summaries||[]).forEach(s => { summaryMap[s.cwd] = s; });
  return `
    ${viewHeader('н”„лЎңм қнҠё', `${p.projects.length}к°ң мқёлҚұмҠӨ н”„лЎңм қнҠё. м№ҙл“ңлҘј нҒҙлҰӯн•ҳл©ҙ мӢӨм ң м„Өм • мҠӨлғ…мғ·мқҙ м—ҙлҰҪлӢҲлӢӨ.`, 'projects')}
    <div class="grid-list">
      ${p.projects.map(pr => {
        const cwd = pr.path || '';
        const s = summaryMap[cwd] || {};
        const canOpen = pr.cwdResolved && cwd;
        return `
          <div class="card p-4 hover-lift ${canOpen?'cursor-pointer':'opacity-60'}"
               onclick='${canOpen ? `openProjectDetail(${JSON.stringify(cwd)})` : `toast("мӢӨм ң кІҪлЎң нҷ•мқё л¶Ҳк°Җ вҖ” мһ¬мқёлҚұмҠӨ н•ҙліҙм„ёмҡ”","warn")`}'>
            <div class="flex items-center justify-between mb-1">
              <div class="font-semibold text-sm truncate">${escapeHtml(pr.name)}</div>
              ${pr.hasClaudeMd ? '<span class="chip chip-ok text-[10px]">CLAUDE.md</span>' : ''}
              ${!canOpen ? '<span class="chip chip-warn text-[10px]">кІҪлЎң лҜёнҷ•мқё</span>' : ''}
            </div>
            <div class="text-[10px] mono text-[var(--text-dim)] truncate">${escapeHtml(cwd || pr.metaDir || 'вҖ”')}</div>
            ${pr.slug !== pr.name ? `<div class="text-[9px] mono text-[var(--text-dim)] truncate">slug: ${escapeHtml(pr.slug)}</div>` : ''}
            <div class="text-[11px] text-[var(--text-mute)] mt-2 flex gap-2 flex-wrap">
              <span>м„ём…ҳ ${pr.sessionCount||0}</span>
              ${s.lastActivity ? `<span>В· мөңк·ј ${fmtRel(s.lastActivity)}</span>` : ''}
            </div>
            <div class="flex gap-1 mt-3">
              <button class="btn flex-1 justify-center text-xs" ${canOpen?'':'disabled style="opacity:0.4;cursor:not-allowed;"'}
                      onclick='event.stopPropagation();${canOpen ? `openProjectDetail(${JSON.stringify(cwd)})` : ''}'>рҹ“Ӣ мғҒм„ё</button>
              <button class="btn flex-1 justify-center text-xs" ${canOpen?'':'disabled style="opacity:0.4;cursor:not-allowed;"'}
                      onclick='event.stopPropagation();${canOpen ? `openFolder(${JSON.stringify(cwd)})` : ''}'>рҹ“Ӯ нҸҙлҚ”</button>
              <button class="btn justify-center text-xs" title="${t('Ralph м¶”мІң PROMPT.md мғқм„ұ')}" ${canOpen?'':'disabled style="opacity:0.4;cursor:not-allowed;"'}
                      onclick='event.stopPropagation();${canOpen ? `openRalphRecommend(${JSON.stringify(cwd)})` : ''}'>рҹҰһ</button>
            </div>
          </div>`;
      }).join('') || `<div class="card empty" style="grid-column:1/-1;">н”„лЎңм қнҠё м—ҶмқҢ</div>`}
    </div>
  `;
};

async function openRalphRecommend(cwd) {
  showModalLoading(t('Ralph н”„лЎ¬н”„нҠё мғқм„ұ мӨ‘вҖҰ'));
  try {
    const url = '/api/ralph/recommend' + (state.data._ralphPolish ? '' : '');
    const r = await api('/api/ralph/recommend', {
      method: 'POST',
      body: { project: cwd, polish: !!state.data._ralphPolish },
    });
    closeModal();
    if (!r.ok) { toast(r.error || t('мӢӨнҢЁ'), 'err'); return; }
    const rec = r.recommendation || {};
    const sources = rec.sources || {};
    state.data._ralphRec = rec;
    showModal(`
      <div class="text-[12px] font-semibold mb-2">рҹҰһ ${t('Ralph м¶”мІң')} вҖ” ${escapeHtml(cwd)}</div>
      <div class="text-[10px] mb-2" style="color:var(--text-dim)">
        ${t('rationale')}: ${escapeHtml(rec.rationale || '')}
        <span class="ml-2">CLAUDE.md ${sources.hasClaudeMd?'вң“':'В·'} В· git ${sources.gitLogLines||0} commits В· dirty ${sources.dirtyFiles||0} В· TODOs ${sources.todoCount||0}</span>
      </div>
      <textarea id="ralphRecPrompt" rows="14" class="input text-xs" style="font-family:ui-monospace,monospace;">${escapeHtml(rec.promptMd || '')}</textarea>
      <div class="flex items-center gap-2 mt-3">
        <label class="text-[11px]"><input type="checkbox" id="ralphRecPolish" ${state.data._ralphPolish?'checked':''} onclick="state.data._ralphPolish=this.checked;openRalphRecommend(${JSON.stringify(cwd)})"> ${t('LLM лӢӨл“¬кё°')}</label>
        <label class="text-[11px] flex-1">${t('Max iter')}
          <input id="ralphRecMax" type="number" value="25" min="1" max="200" class="input text-xs" style="width:72px;">
        </label>
        <label class="text-[11px] flex-1">${t('мҳҲмӮ° USD')}
          <input id="ralphRecBudget" type="number" value="5" min="0.01" max="100" step="0.5" class="input text-xs" style="width:72px;">
        </label>
        <button class="chip text-[10px]" onclick="closeModal()">${t('м·ЁмҶҢ')}</button>
        <button class="chip text-[10px]" onclick="_ralphRecStart(${JSON.stringify(cwd)})">рҹҡҖ ${t('Ralph мӢңмһ‘')}</button>
      </div>
    `, { title: '' });
  } catch (e) {
    closeModal(); toast(e.message, 'err');
  }
}

async function _ralphRecStart(cwd) {
  const prompt = (document.getElementById('ralphRecPrompt') || {}).value || '';
  const max = parseInt((document.getElementById('ralphRecMax') || {}).value || '25', 10);
  const budget = parseFloat((document.getElementById('ralphRecBudget') || {}).value || '5');
  if (!prompt.trim()) { toast(t('н”„лЎ¬н”„нҠёк°Җ л№„м–ҙ мһҲмқҢ')); return; }
  const r = await api('/api/ralph/start', { method: 'POST', body: {
    prompt, maxIterations: max, budgetUsd: budget,
    completion: (state.data._ralphRec && state.data._ralphRec.completion) || '<promise>DONE</promise>',
    cwd: cwd,
  }});
  closeModal();
  if (!r.ok) { toast(r.error || t('мӢӨнҢЁ'), 'err'); return; }
  toast(`рҹҰһ ${t('мӢңмһ‘лҗЁ')}: ${r.runId}`);
  navigate('ralph');
  setTimeout(() => _ralphSelect(r.runId), 200);
}

async function openProjectDetail(cwd) {
  showModalLoading(t('н”„лЎңм қнҠё м„Өм • л¶Ҳлҹ¬мҳӨлҠ” мӨ‘вҖҰ'));
  try {
    const [d, tb] = await Promise.all([
      api('/api/project/detail?cwd=' + encodeURIComponent(cwd)),
      api('/api/project/tool-breakdown?cwd=' + encodeURIComponent(cwd)),
    ]);
    if (d.error) { toast(errMsg(d), 'err'); closeModal(); return; }
    renderProjectDetail(d);
    renderProjectAgentsSection(tb, d.cwd);
  } catch (e) {
    closeModal(); toast(e.message, 'err');
  }
}

function renderProjectAgentsSection(tb, cwd) {
  const slot = document.getElementById('projectAgentsSlot');
  if (!slot) return;
  const subs = tb.subagents || [];
  const total = subs.reduce((a,b)=>a+b.n,0);
  // н”„лЎңм қнҠём—җ м •мқҳлҗң м—җмқҙм „нҠё (.claude/agents/*.md) вҖ” лі„лҸ„лЎң к°Җм ёмҳҙ
  const definedAgents = (window.__projectDetailData && window.__projectDetailData.repo && window.__projectDetailData.repo.agents) || [];
  const definedHtml = definedAgents.length ? `
    <div class="mb-3">
      <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)] mb-2">рҹ“Ӯ н”„лЎңм қнҠём—җ м •мқҳлҗң м—җмқҙм „нҠё (${definedAgents.length})</div>
      <div class="flex flex-wrap gap-1">
        ${definedAgents.map(a => {
          const cnt = (subs.find(s => s.name === a.name) || {}).n || 0;
          return `<span class="chip ${cnt>0?'chip-accent':''}" title="${escapeHtml(a.description||a.id||'')}">${escapeHtml(a.name)} ${cnt?`<span class="ml-1">Г—${cnt}</span>`:'<span class="ml-1 text-[var(--text-dim)]">лҜёмӮ¬мҡ©</span>'}</span>`;
        }).join('')}
      </div>
    </div>` : '';
  if (!subs.length) {
    slot.innerHTML = `
      <div class="card p-4 mb-4" style="background: rgba(217,119,87,0.03);">
        ${definedHtml}
        <div class="flex items-center justify-between mb-1">
          <div class="font-semibold text-sm">рҹӨқ м„ём…ҳм—җм„ң мң„мһ„лҗң м„ңлёҢм—җмқҙм „нҠё (Agent лҸ„кө¬ нҳём¶ң)</div>
          <span class="chip">0нҡҢ</span>
        </div>
        <div class="text-xs text-[var(--text-mute)]">${definedAgents.length ? `м •мқҳлҗң м—җмқҙм „нҠё ${definedAgents.length}к°ңк°Җ мһҲм§Җл§Ң м„ём…ҳм—җм„ң н•ң лІҲлҸ„ мң„мһ„лҗҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ. AI м¶”мІңмңјлЎң нҷңмҡ© мӢңлӮҳлҰ¬мҳӨлҘј л°ӣм•„ліҙм„ёмҡ”.` : 'мқҙ н”„лЎңм қнҠё м„ём…ҳл“Өм—җм„ңлҠ” м„ңлёҢм—җмқҙм „нҠё мң„мһ„мқҙ м—Ҷм—ҲмҠөлӢҲлӢӨ. мң„мқҳ рҹӨ– AI м¶”мІңмңјлЎң н”„лЎңм қнҠё м „мҡ© м—җмқҙм „нҠёлҘј л§Ңл“Өл©ҙ delegation м җмҲҳк°Җ мҳӨлҰ…лӢҲлӢӨ.'}</div>
      </div>`;
    _translateDOM(slot);
    return;
  }
  slot.innerHTML = `
    <div class="card p-4 mb-4">
      ${definedHtml}
      <div class="flex items-center justify-between mb-3">
        <div class="font-semibold text-sm">рҹӨқ м„ём…ҳм—җм„ң мң„мһ„лҗң м„ңлёҢм—җмқҙм „нҠё (Agent лҸ„кө¬ нҳём¶ң)</div>
        <span class="text-xs text-[var(--text-dim)]">мҙқ ${total}нҡҢ мң„мһ„ В· ${subs.length}мў…</span>
      </div>
      <div class="grid grid-cols-1 md:grid-cols-2 gap-2">
        ${subs.map(a => `
          <div class="rounded bg-white/5 border border-[var(--border)] p-2.5 flex items-center justify-between cursor-pointer hover:bg-white/10"
               onclick="closeModal();viewAgent('${escapeHtml(a.name)}')">
            <div class="min-w-0">
              <div class="text-sm font-semibold truncate">${escapeHtml(a.name)}</div>
              <div class="text-[10px] text-[var(--text-dim)]">нҒҙлҰӯ вҶ’ м—җмқҙм „нҠё м •мқҳ ліҙкё°</div>
            </div>
            <div class="text-right">
              <div class="mono font-bold text-sm" style="color:var(--accent)">${a.n}</div>
              <div class="text-[9px] text-[var(--text-dim)]">нҳём¶ң</div>
            </div>
          </div>`).join('')}
      </div>
    </div>`;
  _translateDOM(slot);
}

function renderProjectDetail(d) {
  const r = d.repo || {};
  const st = d.stats || {};
  const e = d.claudeJsonEntry || {};
  const sessions = d.sessions || [];

  const section = (title, body, count) => `
    <div class="mb-4">
      <div class="flex items-center gap-2 mb-2">
        <h3 class="text-xs uppercase tracking-widest text-[var(--text-dim)]">${title}</h3>
        ${count != null ? `<span class="badge-n">${count}</span>` : ''}
      </div>
      ${body}
    </div>`;

  const agentsHtml = r.agents.length ? r.agents.map(a => `
    <div class="card p-3">
      <div class="flex justify-between mb-1 gap-2"><b class="text-sm truncate">${escapeHtml(a.name)}</b><span class="chip text-[10px]">${escapeHtml(a.model)}</span></div>
      <div class="text-[10px] mono text-[var(--text-dim)] mb-1 truncate">${escapeHtml(a.id)}</div>
      <div class="text-xs text-[var(--text-mute)] line-clamp-3">${escapeHtml(a.description||'вҖ”')}</div>
      <div class="mt-1">${(a.tools||[]).slice(0,6).map(t=>`<span class="tag-tool">${escapeHtml(t)}</span>`).join('')}</div>
    </div>`).join('') : '<div class="text-xs text-[var(--text-dim)]">.claude/agents л№„м–ҙмһҲмқҢ</div>';

  const cmdsHtml = r.commands.length ? r.commands.map(c => `
    <div class="card p-2 text-xs"><span class="mono">/${escapeHtml(c.name||c.id)}</span><div class="text-[var(--text-mute)] line-clamp-2 mt-0.5">${escapeHtml(c.description||'вҖ”')}</div></div>
  `).join('') : '<div class="text-xs text-[var(--text-dim)]">вҖ”</div>';

  const skillsHtml = r.skills.length ? r.skills.map(s => `
    <div class="card p-2"><b class="text-sm">${escapeHtml(s.name)}</b><div class="text-xs text-[var(--text-mute)] line-clamp-2 mt-0.5">${escapeHtml(s.description||'вҖ”')}</div></div>
  `).join('') : '<div class="text-xs text-[var(--text-dim)]">вҖ”</div>';

  const hooksHtml = r.hooks.length ? r.hooks.map(h => `<div class="mono text-xs text-[var(--text-mute)]">${escapeHtml(h.name)}</div>`).join('') : '<div class="text-xs text-[var(--text-dim)]">вҖ”</div>';

  const settingsLocalHtml = r.settingsLocal
    ? `<pre class="mono text-[10px] whitespace-pre-wrap bg-[var(--code-bg)] p-3 rounded max-h-[220px] overflow-y-auto">${escapeHtml(JSON.stringify(r.settingsLocal, null, 2))}</pre>`
    : '<div class="text-xs text-[var(--text-dim)]">.claude/settings.local.json м—ҶмқҢ</div>';

  const cjEntryHtml = Object.keys(e).length
    ? `<div class="card p-3 text-xs space-y-1">
        ${Object.entries(e).map(([k,v]) => `<div class="flex justify-between gap-2"><span class="text-[var(--text-mute)]">${k}</span><span class="mono truncate max-w-[240px]">${escapeHtml(JSON.stringify(v))}</span></div>`).join('')}
      </div>` : '<div class="text-xs text-[var(--text-dim)]">вҖ”</div>';

  const claudeMdHtml = r.claudeMd
    ? `<div class="card p-3 max-h-[260px] overflow-y-auto prose-claude text-xs">${marked.parse(r.claudeMd)}</div>`
    : '<div class="text-xs text-[var(--text-dim)]">н”„лЎңм қнҠё лЈЁнҠём—җ CLAUDE.md м—ҶмқҢ</div>';

  const sessionsHtml = sessions.length ? `
    <table class="data">
      <thead><tr><th>м җмҲҳ</th><th>мІ« мҡ”мІӯ</th><th class="text-right">лҸ„кө¬</th><th class="text-right">м—җмқҙм „нҠё</th><th class="text-right">мҳӨлҘҳ</th><th class="text-right">мӢңмһ‘</th></tr></thead>
      <tbody>
        ${sessions.slice(0,20).map(s => `
          <tr class="link-row" onclick="closeModal();openSessionDetail('${s.session_id}')">
            <td><div class="inline-flex items-center justify-center w-9 h-7 rounded mono font-bold text-xs"
              style="background:${scoreColor(s.score)}22;color:${scoreColor(s.score)}">${s.score}</div></td>
            <td class="text-xs max-w-[320px] truncate">${escapeHtml((s.first_user_prompt||'').slice(0,120)||'вҖ”')}</td>
            <td class="text-right text-xs">${s.tool_use_count}</td>
            <td class="text-right text-xs">${s.agent_call_count || 0}</td>
            <td class="text-right text-xs">${s.error_count || 0}</td>
            <td class="text-right text-xs text-[var(--text-mute)]">${fmtRel(s.started_at)}</td>
          </tr>`).join('')}
      </tbody>
    </table>` : '<div class="empty text-xs">мқҙ н”„лЎңм қнҠём—җм„ң мӢӨн–үлҗң м„ём…ҳ м—ҶмқҢ</div>';

  window.__projectDetailData = d;
  showModal(`
    <!-- v2.36.3 вҖ” Project snapshot scroll fix.
         The header + aiRecSlot + projectAgentsSlot all sit above the
         body in the same flex-column .modal (max-height: 92vh, overflow:
         hidden). Without flex-shrink-0 on the leading regions and
         min-h-0 on the body, a long aiRec result or a tall header (chips
         wrapping over multiple rows) pushed the body out of the modal
         and the inner overflow-y-auto silently stopped working.
         Fixes: lock the leading regions to their content height, allow
         the body to shrink + scroll, and give the body wrapper a
         dedicated scroll container so children don't have to opt in. -->
    <div class="p-5 border-b border-[var(--border)] flex items-start gap-4 flex-shrink-0">
      <div class="flex-1 min-w-0">
        <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">н”„лЎңм қнҠё мҠӨлғ…мғ·</div>
        <h2 class="text-xl font-bold truncate">${escapeHtml(d.name)}</h2>
        <div class="text-xs mono text-[var(--text-mute)] truncate mt-1">${escapeHtml(d.cwd)}</div>
        <div class="flex flex-wrap gap-2 mt-3">
          <button class="chip cursor-pointer hover:brightness-125" style="background:${scoreColor(st.avgScore)}22; color:${scoreColor(st.avgScore)}" onclick="openScoreDetail({cwd: ${JSON.stringify(d.cwd)}})" title="м җмҲҳ кі„мӮ°мӢқ мғҒм„ё">вҳ… нҸүк·  ${st.avgScore}</button>
          <button class="chip cursor-pointer hover:brightness-125" onclick="scrollToSessions()" title="м„ём…ҳ лҰ¬мҠӨнҠёлЎң мҠӨнҒ¬лЎӨ">рҹ“Ҡ м„ём…ҳ ${st.sessionCount}</button>
          <button class="chip cursor-pointer hover:brightness-125" onclick='openToolBreakdown(${JSON.stringify(d.cwd)})' title="лҸ„кө¬ мӮ¬мҡ© л“ңлҰҙлӢӨмҡҙ">рҹӣ  лҸ„кө¬ ${st.totalTools}</button>
          <span class="chip" title="н”„лЎңм қнҠём—җ м •мқҳлҗң .claude/agents/*.md нҢҢмқј мҲҳ">рҹ“Ӯ м •мқҳ м—җмқҙм „нҠё ${(r.agents||[]).length}</span>
          <button class="chip chip-accent cursor-pointer hover:brightness-125" onclick='openAgentBreakdown(${JSON.stringify(d.cwd)})' title="м„ём…ҳм—җм„ң Agent лҸ„кө¬лЎң мң„мһ„лҗң мҙқ нҡҹмҲҳ (нҶөкі„ нғӯ м°ёкі )">рҹӨқ мң„мһ„ нҳём¶ң ${st.totalAgents}</button>
          ${st.totalErrors ? `<span class="chip chip-err">вқҢ ${st.totalErrors}</span>`:''}
          ${r.exists ? '<span class="chip chip-ok">.claude мЎҙмһ¬</span>' : '<span class="chip">.claude м—ҶмқҢ</span>'}
        </div>
        <div class="mt-3">
          <button class="btn-primary btn text-xs" onclick='startAiRecommend(${JSON.stringify(d.cwd)})'>
            рҹӨ– Claude кё°л°ҳ AI м¶”мІң л°ӣкё° (30~120мҙҲ)
          </button>
          <span class="text-[10px] text-[var(--text-dim)] ml-2">мқҙ н”„лЎңм қнҠё м»Ён…ҚмҠӨнҠёлЎң мӢӨм ң claude CLI нҳём¶ң</span>
        </div>
      </div>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div id="projectSnapshotBody" class="flex-1 min-h-0 overflow-y-auto" style="overscroll-behavior: contain;">
      <div id="aiRecSlot"></div>
      <div id="projectAgentsSlot" class="px-5"></div>
      <div class="p-5 grid grid-cols-1 lg:grid-cols-2 gap-5">
        <div class="min-w-0">
          ${section('рҹ“ң н”„лЎңм қнҠё CLAUDE.md', claudeMdHtml)}
          ${section('рҹӨқ н”„лЎңм қнҠё м—җмқҙм „нҠё', `<div class="grid grid-cols-1 gap-2">${agentsHtml}</div>`, r.agents.length)}
          ${section('вңЁ н”„лЎңм қнҠё мҠӨнӮ¬', `<div class="grid grid-cols-1 gap-2">${skillsHtml}</div>`, r.skills.length)}
          ${section('/ н”„лЎңм қнҠё лӘ…л №м–ҙ', `<div class="grid grid-cols-1 gap-2">${cmdsHtml}</div>`, r.commands.length)}
          ${section('рҹӘқ .claude/hooks нҢҢмқј', hooksHtml, r.hooks.length)}
        </div>
        <div class="min-w-0">
          ${section('вҡҷпёҸ .claude/settings.local.json', settingsLocalHtml)}
          ${section('рҹ—Ӯ ~/.claude.json н”„лЎңм қнҠё м—”нҠёлҰ¬', cjEntryHtml)}
          ${section('рҹ•’ м„ём…ҳ нһҲмҠӨнҶ лҰ¬ (м җмҲҳ нҸ¬н•Ё)', sessionsHtml, sessions.length)}
          ${section('рҹӨқ ' + t('мөңк·ј м„ңлёҢм—җмқҙм „нҠё нҷңлҸҷ'),
            _renderSubagentActivity(d.subagentActivity || [], d.cwd),
            (d.subagentActivity || []).length
          )}
        </div>
      </div>
    </div>
  `, { wide: true });
}

// v2.41.0 вҖ” render the "Recent sub-agent activity" timeline inside the
// project detail modal. Each row groups by source session id so the user
// sees "session A delegated to {Explore, code-reviewer, ...}" at a glance.
// Clicking a row spawns a Terminal.app on the source session in this cwd
// (claude --resume <sessionId>). Clicking a session header expands all of
// that session's delegations.
function _renderSubagentActivity(activity, cwd) {
  if (!activity || !activity.length) {
    return `<div class="empty text-xs">${escapeHtml(t('мқҙ н”„лЎңм қнҠём—җм„ң м„ңлёҢм—җмқҙм „нҠё мң„мһ„ кё°лЎқ м—ҶмқҢ'))}</div>`;
  }
  // Group by sessionId, preserving the time-desc order from the server.
  const bySession = {};
  const sessionOrder = [];
  for (const e of activity) {
    if (!bySession[e.sessionId]) {
      bySession[e.sessionId] = [];
      sessionOrder.push(e.sessionId);
    }
    bySession[e.sessionId].push(e);
  }
  const rows = sessionOrder.map(sid => {
    const items = bySession[sid];
    const agents = [...new Set(items.map(it => it.agent))];
    const errCount = items.filter(it => it.hadError).length;
    const tokSum = items.reduce((s, it) => s + (it.turnTokens || 0), 0);
    const lastTs = items[0].ts;
    const cwdAttr = escapeHtml(cwd || '');
    const sidAttr = escapeHtml(sid);
    return `
      <div class="rounded-lg border border-[var(--border)] mb-2" style="background:rgba(255,255,255,0.02);">
        <div class="flex items-center gap-2 px-3 py-2 cursor-pointer hover:bg-white/5"
             onclick="this.nextElementSibling.style.display=this.nextElementSibling.style.display==='none'?'':'none';">
          <span class="text-[10px] mono text-[var(--text-dim)]">${sid.slice(0, 8)}</span>
          <span class="font-semibold text-xs flex-1 truncate">${items.length}Г— ${t('мң„мһ„')} вҶ’ ${agents.map(a => `<span class="chip chip-accent text-[9px]">${escapeHtml(a)}</span>`).join(' ')}</span>
          ${errCount ? `<span class="chip chip-err text-[9px]">${errCount} ${t('мӢӨнҢЁ')}</span>` : ''}
          <span class="text-[10px] text-[var(--text-dim)]">${fmtRel(lastTs)}</span>
          <span class="text-[10px] text-[var(--text-dim)]">${tokSum.toLocaleString()} tok</span>
          <button class="btn text-[10px]" data-cwd="${cwdAttr}" data-sid="${sidAttr}"
            onclick="event.stopPropagation();_spawnSubagentCli(this.dataset.cwd, this.dataset.sid)">рҹ–Ҙ ${t('CLI')}</button>
        </div>
        <div style="display:none;" class="px-3 py-2 border-t border-[var(--border)]">
          ${items.map(it => `
            <div class="flex items-start gap-2 py-1.5 border-b border-[var(--border)] last:border-b-0">
              <span class="chip text-[9px]" style="white-space:nowrap;">${escapeHtml(it.agent)}</span>
              <div class="flex-1 min-w-0">
                <div class="text-[11px]" style="overflow-wrap:anywhere;color:var(--text);">${escapeHtml(it.inputSummary || '(no preview)')}</div>
                <div class="text-[10px] text-[var(--text-dim)] mt-0.5">${escapeHtml(it.tool || '')} В· ${(it.turnTokens||0).toLocaleString()} tok В· ${fmtRel(it.ts)}${it.hadError ? ' В· <span style="color:#fca5a5;">вҡ  error</span>' : ''}</div>
              </div>
            </div>
          `).join('')}
        </div>
      </div>`;
  });
  return rows.join('');
}

// v2.41.0 вҖ” spawn a Terminal.app on the source session via the existing
// /api/session/spawn route (which also handles cwd resolution).
async function _spawnSubagentCli(cwd, sessionId) {
  if (!sessionId) return;
  try {
    const r = await api('/api/session/spawn', {
      method: 'POST', headers: {'Content-Type':'application/json'},
      body: JSON.stringify({ sessionId, cwd: cwd || '' }),
    });
    if (r.ok) toast(t('Terminal м—җм„ң м„ём…ҳ мһ¬к°ң мӨ‘вҖҰ'), 'ok');
    else      toast(t('CLI мӢӨн–ү мӢӨнҢЁ: ') + (r.error || ''), 'err');
  } catch (e) {
    toast(t('CLI мӢӨн–ү мӢӨнҢЁ: ') + e.message, 'err');
  }
}

function scrollToSessions() {
  // v2.36.3 вҖ” scroll inside the dedicated #projectSnapshotBody container so
  // the smooth-scroll lands the section header at the top of the visible
  // area rather than scrolling the entire viewport.
  const header = [...document.querySelectorAll('.modal h3, .modal .text-xs')].find(el => el.textContent && el.textContent.includes('м„ём…ҳ нһҲмҠӨнҶ лҰ¬'));
  if (!header) return;
  const body = document.getElementById('projectSnapshotBody');
  if (body) {
    const top = header.getBoundingClientRect().top - body.getBoundingClientRect().top + body.scrollTop - 8;
    body.scrollTo({ top, behavior: 'smooth' });
  } else {
    header.scrollIntoView({ behavior: 'smooth', block: 'start' });
  }
}

async function openToolBreakdown(cwd) {
  showModalLoading(t('лҸ„кө¬ мӮ¬мҡ© лӮҙм—ӯ лЎңл”©вҖҰ'));
  try {
    const d = await api('/api/project/tool-breakdown?cwd=' + encodeURIComponent(cwd));
    if (d.error) { closeModal(); toast(errMsg(d), 'err'); return; }
    const top = d.tools[0] ? d.tools[0].n : 1;
    const rows = d.tools.map(t => {
      const pct = Math.round((t.n / top) * 100);
      return `
        <div class="py-1.5 border-b border-[var(--border)]">
          <div class="flex justify-between items-center mb-1">
            <span class="mono text-xs truncate pr-2">${escapeHtml(t.tool)}</span>
            <span class="mono text-xs font-bold">${t.n}${t.errors ? ` <span class="text-[var(--err)]">вң–${t.errors}</span>`:''}</span>
          </div>
          <div class="h-1 bg-white/5 rounded"><div style="width:${pct}%; height:100%; background:var(--grad); border-radius:inherit;"></div></div>
        </div>`;
    }).join('');
    showModal(`
      <div class="p-5 border-b border-[var(--border)] flex justify-between items-start">
        <div>
          <div class="text-[11px] uppercase tracking-widest text-[var(--text-dim)]">лҸ„кө¬ мӮ¬мҡ© л“ңлҰҙлӢӨмҡҙ</div>
          <h2 class="text-lg font-bold truncate">${escapeHtml(cwd)}</h2>
          <div class="text-xs text-[var(--text-mute)] mt-1">${d.sessionCount}к°ң м„ём…ҳм—җм„ң ${d.total}нҡҢ нҳём¶ң В· ${d.tools.length}мў… лҸ„кө¬</div>
        </div>
        <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
      </div>
      <div class="flex-1 overflow-y-auto p-5">
        ${rows || '<div class="empty">лҸ„кө¬ мӮ¬мҡ© кё°лЎқ м—ҶмқҢ</div>'}
      </div>
    `);
  } catch (e) {
    closeModal(); toast(e.message, 'err');
  }
}

