async function startAiRecommend(cwd) {
  const slot = document.getElementById('aiRecSlot');
  if (!slot) return;
  slot.innerHTML = `
    <div class="p-5 border-b border-[var(--border)]" style="background: linear-gradient(135deg, rgba(167,139,250,0.12), rgba(244,114,182,0.08));">
      <div class="flex items-center gap-3">
        <div class="shimmer w-6 h-6 rounded-full"></div>
        <div class="flex-1">
          <div class="font-semibold text-sm gradient-text">рҹӨ– Claude м—җкІҢ мқҙ н”„лЎңм қнҠё л¶„м„қ мҡ”мІӯ мӨ‘вҖҰ</div>
          <div class="text-xs text-[var(--text-mute)] mt-0.5">нҸүк·  30~120мҙҲ мҶҢмҡ” В· cwd=<span class="mono">${escapeHtml(cwd)}</span> м—җм„ң claude CLI мӢӨн–ү</div>
          <div id="aiRecProgress" class="text-[10px] mono text-[var(--text-dim)] mt-1">мҡ”мІӯ м „мҶЎ мӨ‘вҖҰ</div>
        </div>
      </div>
    </div>`;

  // к°„лӢЁн•ң м§„н–ү н‘ңмӢң (мӢӨм ң мҠӨнҠёлҰ¬л°ҚмқҖ м•„лӢҳ вҖ” кІҪкіј мҙҲл§Ң м—…лҚ°мқҙнҠё)
  const started = Date.now();
  const tick = setInterval(() => {
    const p = document.getElementById('aiRecProgress');
    if (p) p.textContent = `кІҪкіј ${Math.round((Date.now()-started)/1000)}мҙҲ В· claude CLI мқ‘лӢө лҢҖкё°вҖҰ`;
  }, 1000);

  try {
    const r = await api('/api/project/ai-recommend', {
      method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({ cwd, lang: _curLang })
    });
    clearInterval(tick);
    if (r.error) {
      slot.innerHTML = `
        <div class="p-5 border-b border-[var(--border)]">
          <div class="card p-4" style="border-color: rgba(248,113,113,0.4);">
            <div class="font-semibold text-sm text-[var(--err)] mb-1">вқҢ AI м¶”мІң мӢӨнҢЁ</div>
            <div class="text-xs text-[var(--text-mute)]">${escapeHtml(r.error)}</div>
            ${r.rawResponse ? `<details class="mt-2"><summary class="text-xs cursor-pointer">мӣҗліё мқ‘лӢө ліҙкё°</summary><pre class="mono text-[10px] whitespace-pre-wrap bg-[var(--code-bg)] p-2 rounded mt-2 max-h-[260px] overflow-y-auto">${escapeHtml(r.rawResponse)}</pre></details>`:''}
            <button class="btn mt-3 text-xs" onclick='startAiRecommend(${JSON.stringify(cwd)})'>лӢӨмӢң мӢңлҸ„</button>
          </div>
        </div>`;
      return;
    }
    renderAiRecommendations(r, cwd);
  } catch (e) {
    clearInterval(tick);
    slot.innerHTML = `<div class="p-5"><div class="card p-4"><div class="text-[var(--err)]">мӢӨнҢЁ: ${escapeHtml(e.message)}</div></div></div>`;
  }
}

