window.showEditCustomProviderModal = async (cpId) => {
  const cached = state.data._aiProviders;
  const cp = (cached?.customProviders || []).find(c => c.id === cpId);
  if (!cp) { toast(t('н”„лЎңл°”мқҙлҚ”лҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ'), 'err'); return; }
  showAddCustomProviderModal(cp);
};

