// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// OLLAMA лӘЁлҚё н—ҲлёҢ (Task 1)
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
let _ollamaCatalogData = [];
let _ollamaInstalledData = [];
let _ollamaCurrentCat = 'all';
let _ollamaPullTimers = {};

// в”Җв”Җ Ollama Serve кҙҖлҰ¬ в”Җв”Җ
async function _ollamaServeCheckStatus() {
  const dot = document.getElementById('ollamaServeDot');
  const hostEl = document.getElementById('ollamaServeHost');
  const msgEl = document.getElementById('ollamaServeMsg');
  const startBtn = document.getElementById('ollamaServeStartBtn');
  const stopBtn = document.getElementById('ollamaServeStopBtn');
  if (!dot) return;
  try {
    const s = await api('/api/ollama/serve/status');
    if (s.running) {
      dot.style.background = 'var(--ok)';
      hostEl.textContent = s.host || '';
      msgEl.textContent = t('мӢӨн–ү мӨ‘');
      startBtn.style.display = 'none';
      stopBtn.style.display = s.managedByDashboard ? '' : 'none';
    } else {
      dot.style.background = 'var(--err)';
      hostEl.textContent = '';
      msgEl.textContent = t('лҜёмӢӨн–ү');
      startBtn.style.display = '';
      stopBtn.style.display = 'none';
    }
    // лЎңк·ё н‘ңмӢң
    if (s.log && s.log.length) {
      const logEl = document.getElementById('ollamaServeLog');
      if (logEl) {
        logEl.style.display = '';
        logEl.textContent = s.log.join('\n');
        logEl.scrollTop = logEl.scrollHeight;
      }
    }
  } catch(e) {
    dot.style.background = 'var(--text-dim)';
    msgEl.textContent = t('мғҒнғң нҷ•мқё мӢӨнҢЁ');
  }
}

async function _ollamaServeStart() {
  const msgEl = document.getElementById('ollamaServeMsg');
  if (msgEl) msgEl.textContent = t('мӢңмһ‘ мӨ‘...');
  const startBtn = document.getElementById('ollamaServeStartBtn');
  if (startBtn) startBtn.disabled = true;
  try {
    const r = await api('/api/ollama/serve/start', { method: 'POST', body: '{}' });
    if (r.ok) {
      toast(r.message || t('Ollama мӢңмһ‘лҗЁ'), 'ok');
      _ollamaServeCheckStatus();
      // н”„лЎңл°”мқҙлҚ” н—¬мҠӨлҸ„ мғҲлЎңкі м№Ё
      if (typeof _aiRefreshHealth === 'function') _aiRefreshHealth();
    } else {
      toast(errMsg(r), 'err');
    }
  } catch(e) {
    toast(String(e), 'err');
  }
  if (startBtn) startBtn.disabled = false;
}

async function _ollamaServeStop() {
  const ok = await confirmModal(t('OllamaлҘј м •м§Җн•ҳмӢңкІ мҠөлӢҲк№Ң?'));
  if (!ok) return;
  try {
    const r = await api('/api/ollama/serve/stop', { method: 'POST', body: '{}' });
    toast(r.message || t('Ollama м •м§ҖлҗЁ'), 'ok');
    _ollamaServeCheckStatus();
  } catch(e) { toast(String(e), 'err'); }
}

// в”Җв”Җ Ollama м—”м§„ м„Өм • в”Җв”Җ
async function _ollamaLoadSettings() {
  try {
    const s = await api('/api/ollama/settings');
    const chatSel = document.getElementById('ollamaChatModelSelect');
    const embedSel = document.getElementById('ollamaEmbedModelSelect');
    if (!chatSel || !embedSel) return;

    // мұ„нҢ… лӘЁлҚё мҳөм…ҳ
    chatSel.innerHTML = `<option value="">${t('мһҗлҸҷ м„ нғқ (мІ« лІҲм§ё м„Өм№ҳ лӘЁлҚё)')}</option>`;
    for (const m of (s.installedChat || [])) {
      const sel = m.id === s.chatModel ? 'selected' : '';
      chatSel.innerHTML += `<option value="${escapeHtml(m.id)}" ${sel}>${escapeHtml(m.label)}${m.note ? ' вҖ” ' + escapeHtml(t(m.note)) : ''}</option>`;
    }

    // мһ„лІ л”© лӘЁлҚё мҳөм…ҳ
    embedSel.innerHTML = `<option value="">${t('мһҗлҸҷ м„ нғқ')}</option>`;
    for (const m of (s.installedEmbed || [])) {
      const sel = m.id === s.embedModel ? 'selected' : '';
      embedSel.innerHTML += `<option value="${escapeHtml(m.id)}" ${sel}>${escapeHtml(m.label)}${m.note ? ' вҖ” ' + escapeHtml(t(m.note)) : ''}</option>`;
    }

    // м„Өм№ҳлҗң лӘЁлҚёмқҙ м—Ҷмңјл©ҙ м•ҲлӮҙ
    if (!(s.installedChat || []).length) {
      chatSel.innerHTML += `<option disabled>${t('м„Өм№ҳлҗң мұ„нҢ… лӘЁлҚё м—ҶмқҢ вҖ” лӘЁлҚё н—ҲлёҢм—җм„ң лӢӨмҡҙлЎңл“ң')}</option>`;
    }
    if (!(s.installedEmbed || []).length) {
      embedSel.innerHTML += `<option disabled>${t('м„Өм№ҳлҗң мһ„лІ л”© лӘЁлҚё м—ҶмқҢ вҖ” bge-m3 к¶ҢмһҘ')}</option>`;
    }
  } catch(e) {
    // Ollama лҜёмӢӨн–ү мӢң л¬ҙмӢң
  }
}

async function _ollamaSaveSettings() {
  const chatModel = document.getElementById('ollamaChatModelSelect')?.value || '';
  const embedModel = document.getElementById('ollamaEmbedModelSelect')?.value || '';
  const msgEl = document.getElementById('ollamaSettingsMsg');
  try {
    const r = await api('/api/ollama/settings/save', {
      method: 'POST',
      body: JSON.stringify({ chatModel, embedModel }),
    });
    if (r.ok) {
      if (msgEl) msgEl.innerHTML = `<span style="color:var(--ok)">вң“ ${t('м„Өм • м ҖмһҘлҗЁ')}</span>`;
      toast(t('Ollama м—”м§„ м„Өм •мқҙ м ҖмһҘлҗҳм—ҲмҠөлӢҲлӢӨ'), 'ok');
    } else {
      if (msgEl) msgEl.innerHTML = `<span style="color:var(--err)">вң— ${errMsg(r)}</span>`;
    }
  } catch(e) {
    if (msgEl) msgEl.innerHTML = `<span style="color:var(--err)">вң— ${escapeHtml(String(e))}</span>`;
  }
}

function _ollamaSwitchTab(tab) {
  const catalogView = document.getElementById('ollamaCatalogView');
  const installedView = document.getElementById('ollamaInstalledView');
  const tabCatalog = document.getElementById('ollamaTabCatalog');
  const tabInstalled = document.getElementById('ollamaTabInstalled');
  if (!catalogView || !installedView) return;

  if (tab === 'catalog') {
    catalogView.style.display = '';
    installedView.style.display = 'none';
    if (tabCatalog) { tabCatalog.style.background = 'var(--accent)'; tabCatalog.style.color = '#fff'; }
    if (tabInstalled) { tabInstalled.style.background = ''; tabInstalled.style.color = ''; }
  } else {
    catalogView.style.display = 'none';
    installedView.style.display = '';
    if (tabInstalled) { tabInstalled.style.background = 'var(--accent)'; tabInstalled.style.color = '#fff'; }
    if (tabCatalog) { tabCatalog.style.background = ''; tabCatalog.style.color = ''; }
    _ollamaRenderInstalled();
  }
}

async function _ollamaLoadCatalog() {
  try {
    const d = await cachedApi('/api/ollama/catalog');
    _ollamaCatalogData = d.models || d.catalog || [];
    _ollamaRenderCatalog();
  } catch (e) {
    const grid = document.getElementById('ollamaCatalogGrid');
    if (grid) grid.innerHTML = `<div class="text-xs" style="color:var(--text-dim)">${t('Ollama м№ҙнғҲлЎңк·ёлҘј л¶Ҳлҹ¬мҳ¬ мҲҳ м—ҶмҠөлӢҲлӢӨ.')} <button class="btn btn-sm" onclick="_ollamaLoadCatalog()">${t('мһ¬мӢңлҸ„')}</button></div>`;
  }
}

async function _ollamaLoadInstalled() {
  try {
    const d = await api('/api/ollama/models');
    _ollamaInstalledData = d.models || [];
    // refresh installed flag on catalog rows
    const installedNames = new Set(_ollamaInstalledData.map(m => (m.name || m.model || '').replace(/:latest$/, '')));
    _ollamaCatalogData.forEach(m => {
      m._installed = installedNames.has(m.name) || installedNames.has(m.id);
    });
    _ollamaRenderCatalog();
    // fix(v2.45.2): table was never repainted after data load вҖ” installed
    // models stayed hidden behind the "no models installed" placeholder.
    _ollamaRenderInstalled();
  } catch (e) {
    // installed load failed вҖ” silent
  }
}

function _ollamaRefresh() {
  _ollamaLoadCatalog();
  _ollamaLoadInstalled();
}
window._ollamaRefresh = _ollamaRefresh;
window._ollamaSwitchTab = _ollamaSwitchTab;

function _ollamaFilterCat(cat) {
  _ollamaCurrentCat = cat;
  document.querySelectorAll('.ollama-cat-filter').forEach(btn => {
    if (btn.dataset.cat === cat) {
      btn.style.background = 'var(--accent)'; btn.style.color = '#fff';
      btn.classList.add('active');
    } else {
      btn.style.background = ''; btn.style.color = '';
      btn.classList.remove('active');
    }
  });
  _ollamaRenderCatalog();
}
window._ollamaFilterCat = _ollamaFilterCat;

function _ollamaFilterCatalog() {
  _ollamaRenderCatalog();
}
window._ollamaFilterCatalog = _ollamaFilterCatalog;

function _ollamaRenderCatalog() {
  const grid = document.getElementById('ollamaCatalogGrid');
  if (!grid) return;
  const searchVal = (document.getElementById('ollamaCatalogSearch')?.value || '').toLowerCase();
  let items = _ollamaCatalogData;

  if (_ollamaCurrentCat !== 'all') {
    items = items.filter(m => {
      const cat = (m.category || m.type || '').toLowerCase();
      const tags = (m.tags || []).map(tg => tg.toLowerCase());
      return cat === _ollamaCurrentCat || tags.includes(_ollamaCurrentCat);
    });
  }

  if (searchVal) {
    items = items.filter(m =>
      (m.name || '').toLowerCase().includes(searchVal) ||
      (m.description || '').toLowerCase().includes(searchVal) ||
      (m.id || '').toLowerCase().includes(searchVal)
    );
  }

  if (items.length === 0) {
    grid.innerHTML = `<div class="text-sm" style="color:var(--text-dim)">${t('мқјм№ҳн•ҳлҠ” лӘЁлҚёмқҙ м—ҶмҠөлӢҲлӢӨ.')}</div>`;
    return;
  }

  grid.innerHTML = items.map(m => {
    const installed = m._installed;
    const sizeStr = m.size ? _formatBytes(m.size) : (m.sizeLabel || 'вҖ”');
    const tags = (m.tags || []).slice(0, 4);
    const tagChips = tags.map(tg => `<span class="chip text-[10px]">${escapeHtml(tg)}</span>`).join(' ');
    const statusChip = installed
      ? `<span class="chip chip-ok text-[10px]">${t('м„Өм№ҳлҗЁ')}</span>`
      : `<span class="chip text-[10px]" style="color:var(--text-dim)">${t('лҜём„Өм№ҳ')}</span>`;
    const actionBtn = installed
      ? `<button class="btn btn-sm text-xs" style="color:var(--err);border-color:rgba(248,113,113,0.3);" onclick="_ollamaDelete('${escapeHtml(m.name || m.id)}')">${t('мӮӯм ң')}</button>`
      : `<button class="btn btn-sm btn-primary text-xs" onclick="_ollamaPull('${escapeHtml(m.name || m.id)}')">в¬Ү ${t('лӢӨмҡҙлЎңл“ң')}</button>`;

    return `<div class="card p-4 hover-lift" style="display:flex;flex-direction:column;justify-content:space-between;">
      <div>
        <div class="flex items-center justify-between mb-2">
          <h4 class="font-semibold text-sm" style="color:var(--text)">${escapeHtml(m.name || m.id)}</h4>
          ${statusChip}
        </div>
        <p class="text-xs mb-2" style="color:var(--text-mute);display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden;">${escapeHtml(m.description || '')}</p>
        <div class="flex flex-wrap gap-1 mb-2">${tagChips}</div>
        <div class="text-[11px]" style="color:var(--text-dim)">${t('нҒ¬кё°')}: ${escapeHtml(sizeStr)}</div>
      </div>
      <div class="mt-3 flex justify-end">${actionBtn}</div>
    </div>`;
  }).join('');
}

function _ollamaRenderInstalled() {
  const tbody = document.getElementById('ollamaInstalledBody');
  if (!tbody) return;

  if (_ollamaInstalledData.length === 0) {
    tbody.innerHTML = `<tr><td colspan="7" class="text-center text-sm" style="color:var(--text-dim)">${t('м„Өм№ҳлҗң Ollama лӘЁлҚёмқҙ м—ҶмҠөлӢҲлӢӨ.')}</td></tr>`;
    return;
  }

  tbody.innerHTML = _ollamaInstalledData.map(m => {
    const name = m.name || m.model || 'вҖ”';
    const size = m.size ? _formatBytes(m.size) : 'вҖ”';
    const family = m.details?.family || m.family || 'вҖ”';
    const paramSize = m.details?.parameter_size || m.parameter_size || 'вҖ”';
    const quant = m.details?.quantization_level || m.quantization_level || 'вҖ”';
    const modified = m.modified_at ? new Date(m.modified_at).toLocaleDateString() : 'вҖ”';

    return `<tr>
      <td class="font-semibold text-sm" style="color:var(--text)">${escapeHtml(name)}</td>
      <td class="text-xs">${escapeHtml(size)}</td>
      <td class="text-xs">${escapeHtml(family)}</td>
      <td class="text-xs">${escapeHtml(paramSize)}</td>
      <td class="text-xs">${escapeHtml(quant)}</td>
      <td class="text-xs">${escapeHtml(modified)}</td>
      <td>
        <div class="flex gap-1">
          <button class="btn btn-sm text-xs" onclick="_ollamaShowInfo('${escapeHtml(name)}')">${t('мғҒм„ё')}</button>
          <button class="btn btn-sm text-xs" style="color:var(--err);" onclick="_ollamaDelete('${escapeHtml(name)}')">${t('мӮӯм ң')}</button>
        </div>
      </td>
    </tr>`;
  }).join('');
}

async function _ollamaPull(modelName) {
  try {
    const r = await api('/api/ollama/pull', {
      method: 'POST',
      body: JSON.stringify({ name: modelName })
    });
    const pullId = r.pullId || r.id || modelName;

    // м§„н–үлҘ  UI н‘ңмӢң
    const progressEl = document.getElementById('ollamaPullProgress');
    const nameEl = document.getElementById('ollamaPullModelName');
    const barEl = document.getElementById('ollamaPullBar');
    const percentEl = document.getElementById('ollamaPullPercent');
    const statusEl = document.getElementById('ollamaPullStatus');

    if (progressEl) progressEl.style.display = '';
    if (nameEl) nameEl.textContent = modelName;
    if (barEl) barEl.style.width = '0%';
    if (percentEl) percentEl.textContent = '0%';
    if (statusEl) statusEl.textContent = t('лӢӨмҡҙлЎңл“ң мӢңмһ‘...');

    toast(t('лӘЁлҚё лӢӨмҡҙлЎңл“ңлҘј мӢңмһ‘н•©лӢҲлӢӨ') + ': ' + modelName, 'ok');

    // v2.33.6 вҖ” ETA + л°”мқҙнҠё м§„н–үлҘ  кі„мӮ°
    const fmtBytes = (b) => {
      if (!b) return '';
      if (b < 1024*1024) return (b/1024).toFixed(1) + ' KB';
      if (b < 1024*1024*1024) return (b/(1024*1024)).toFixed(1) + ' MB';
      return (b/(1024*1024*1024)).toFixed(2) + ' GB';
    };
    const fmtEta = (sec) => {
      if (!isFinite(sec) || sec <= 0) return '';
      if (sec < 60) return Math.round(sec) + 's';
      if (sec < 3600) return Math.floor(sec/60) + 'm ' + Math.round(sec%60) + 's';
      return Math.floor(sec/3600) + 'h ' + Math.floor((sec%3600)/60) + 'm';
    };
    // 2мҙҲ к°„кІ© нҸҙл§Ғ
    if (_ollamaPullTimers[pullId]) clearInterval(_ollamaPullTimers[pullId]);
    _ollamaPullTimers[pullId] = setInterval(async () => {
      // v2.46.0 perf вҖ” pause polling while tab is hidden.
      if (document.hidden) return;
      try {
        const s = await api('/api/ollama/pull-status?pullId=' + encodeURIComponent(pullId));
        const pct = Math.min(100, Math.max(0, s.percent || s.progress || 0));
        const status = s.status || '';
        // ETA м¶”м •: (кІҪкіјмӢңк°„ / pct) * (100 - pct)
        let extra = '';
        if (s.bytesDownloaded && s.bytesTotal) {
          extra = ` В· ${fmtBytes(s.bytesDownloaded)} / ${fmtBytes(s.bytesTotal)}`;
        }
        if (s.startedAt && pct > 2 && pct < 100) {
          const elapsed = Date.now()/1000 - s.startedAt;
          const eta = (elapsed / pct) * (100 - pct);
          const etaStr = fmtEta(eta);
          if (etaStr) extra += ' В· ETA ' + etaStr;
        }
        const lineHint = s.lastLine ? ` вҖ” ${s.lastLine.slice(0,80)}` : '';

        if (barEl) barEl.style.width = pct + '%';
        if (percentEl) percentEl.textContent = Math.round(pct) + '%' + extra;
        if (statusEl) statusEl.textContent = (status === 'pulling' ? t('лӢӨмҡҙлЎңл“ң мӨ‘...') : status) + lineHint;

        if (pct >= 100 || status === 'success' || status === 'complete' || s.done) {
          clearInterval(_ollamaPullTimers[pullId]);
          delete _ollamaPullTimers[pullId];
          if (barEl) barEl.style.width = '100%';
          if (percentEl) percentEl.textContent = '100%';
          if (statusEl) statusEl.textContent = t('мҷ„лЈҢ');
          toast(t('лӘЁлҚё лӢӨмҡҙлЎңл“ң мҷ„лЈҢ') + ': ' + modelName, 'ok');
          setTimeout(() => {
            if (progressEl) progressEl.style.display = 'none';
            _ollamaRefresh();
          }, 1500);
        } else if (s.error) {
          clearInterval(_ollamaPullTimers[pullId]);
          delete _ollamaPullTimers[pullId];
          if (statusEl) statusEl.textContent = t('мҳӨлҘҳ') + ': ' + (s.error || '');
          toast(t('лӘЁлҚё лӢӨмҡҙлЎңл“ң мӢӨнҢЁ') + ': ' + (s.error || ''), 'err');
        }
      } catch (e) {
        clearInterval(_ollamaPullTimers[pullId]);
        delete _ollamaPullTimers[pullId];
        if (statusEl) statusEl.textContent = t('мғҒнғң нҷ•мқё мӢӨнҢЁ');
      }
    }, 2000);
  } catch (e) {
    toast(t('лӘЁлҚё лӢӨмҡҙлЎңл“ң мҡ”мІӯ мӢӨнҢЁ') + ': ' + (e.message || e), 'err');
  }
}
window._ollamaPull = _ollamaPull;

async function _ollamaDelete(modelName) {
  const ok = await confirmModal({
    title: t('лӘЁлҚё мӮӯм ң'),
    message: t('мқҙ лӘЁлҚёмқ„ мӮӯм ңн•ҳмӢңкІ мҠөлӢҲк№Ң?') + ' вҖ” ' + modelName,
    confirmLabel: t('мӮӯм ң'),
    danger: true
  });
  if (!ok) return;
  try {
    await api('/api/ollama/delete', {
      method: 'POST',
      body: JSON.stringify({ name: modelName })
    });
    toast(t('лӘЁлҚё мӮӯм ң мҷ„лЈҢ') + ': ' + modelName, 'ok');
    _ollamaRefresh();
  } catch (e) {
    toast(t('лӘЁлҚё мӮӯм ң мӢӨнҢЁ') + ': ' + (e.message || e), 'err');
  }
}
window._ollamaDelete = _ollamaDelete;

async function _ollamaShowInfo(modelName) {
  showModalLoading(t('лӘЁлҚё м •ліҙлҘј л¶Ҳлҹ¬мҳӨлҠ” мӨ‘...'));
  try {
    const d = await api('/api/ollama/info?name=' + encodeURIComponent(modelName));
    const info = d.info || d;
    const modelfile = info.modelfile || info.Modelfile || 'вҖ”';
    const parameters = info.parameters || info.Parameters || 'вҖ”';
    const template = info.template || info.Template || 'вҖ”';

    showModal(`
      <div class="p-5" style="max-width:700px;">
        <div class="flex items-center justify-between mb-4">
          <h3 class="text-base font-semibold" style="color:var(--text)">рҹҰҷ ${escapeHtml(modelName)}</h3>
          <button class="btn text-xs" onclick="closeModal()">вң•</button>
        </div>
        <div class="mb-4">
          <h4 class="text-xs font-semibold mb-1" style="color:var(--text-mute)">${t('Modelfile')}</h4>
          <pre class="text-xs whitespace-pre-wrap break-words" style="max-height:200px;overflow-y:auto;color:var(--text-mute);background:var(--code-bg);padding:12px;border-radius:8px;">${escapeHtml(modelfile)}</pre>
        </div>
        <div class="mb-4">
          <h4 class="text-xs font-semibold mb-1" style="color:var(--text-mute)">${t('нҢҢлқјлҜён„°')}</h4>
          <pre class="text-xs whitespace-pre-wrap break-words" style="max-height:150px;overflow-y:auto;color:var(--text-mute);background:var(--code-bg);padding:12px;border-radius:8px;">${escapeHtml(parameters)}</pre>
        </div>
        <div class="mb-4">
          <h4 class="text-xs font-semibold mb-1" style="color:var(--text-mute)">${t('н…ңн”ҢлҰҝ')}</h4>
          <pre class="text-xs whitespace-pre-wrap break-words" style="max-height:150px;overflow-y:auto;color:var(--text-mute);background:var(--code-bg);padding:12px;border-radius:8px;">${escapeHtml(template)}</pre>
        </div>
      </div>
    `);
  } catch (e) {
    closeModal();
    toast(t('лӘЁлҚё м •ліҙлҘј л¶Ҳлҹ¬мҳ¬ мҲҳ м—ҶмҠөлӢҲлӢӨ') + ': ' + (e.message || e), 'err');
  }
}
window._ollamaShowInfo = _ollamaShowInfo;

function _formatBytes(bytes) {
  if (!bytes || bytes === 0) return '0 B';
  const k = 1024;
  const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.floor(Math.log(bytes) / Math.log(k));
  return parseFloat((bytes / Math.pow(k, i)).toFixed(1)) + ' ' + sizes[i];
}

// Cost chart instances now live in the shared _chartInstances Map.

window.__lastCostsData = null; // л№„мҡ© лҚ°мқҙн„° мәҗмӢң вҖ” мҠӨнғқ л°” м°ЁнҠём—җм„ң мһ¬мӮ¬мҡ©
window.initCostCharts = async () => {
  try {
    const d = await cachedApi('/api/ai-providers/costs', 20000);
    if (!d || !d.ok) return;
    window.__lastCostsData = d; // мәҗмӢң м ҖмһҘ
    const costs = d.costs || {};
    const daily = costs.daily || [];        // [{date, cost, tokens, calls}]
    const byProvider = costs.byProvider || []; // [{provider, cost, tokens, calls}]
    const totals = costs.totals || {};      // {totalCalls, totalTokens, totalCostUSD}

    // мҡ”м•Ҫ м№ҙл“ң м—…лҚ°мқҙнҠё
    const elCalls = document.getElementById('costTotalCalls');
    const elTokens = document.getElementById('costTotalTokens');
    const elUSD = document.getElementById('costTotalUSD');
    if (elCalls) elCalls.textContent = (totals.totalCalls || 0).toLocaleString();
    if (elTokens) elTokens.textContent = (totals.totalTokens || 0).toLocaleString();
    if (elUSD) elUSD.textContent = '$' + (totals.totalCostUSD || 0).toFixed(4);

    // кіөнҶө Chart.js мғүмғҒ
    const textColor = getComputedStyle(document.documentElement).getPropertyValue('--text-mute').trim() || '#a0a0a8';
    const gridColor = getComputedStyle(document.documentElement).getPropertyValue('--border').trim() || 'rgba(255,255,255,0.07)';

    // мқјлі„ л№„мҡ© нғҖмһ„лқјмқё (лқјмқё м°ЁнҠё)
    const ctxTimeline = document.getElementById('costTimeline');
    if (ctxTimeline) {
      _renderChart(ctxTimeline, {
        type: 'line',
        data: {
          labels: daily.map(d => d.date),
          datasets: [{
            label: t('л№„мҡ© (USD)'),
            data: daily.map(d => d.cost || 0),
            borderColor: '#d97757',
            backgroundColor: 'rgba(217,119,87,0.15)',
            fill: true,
            tension: 0.35,
            pointRadius: 3,
            pointBackgroundColor: '#d97757',
          }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { labels: { color: textColor, font: { size: 11 } } },
            tooltip: { callbacks: { label: ctx => '$' + (ctx.parsed.y || 0).toFixed(4) } },
          },
          scales: {
            x: { ticks: { color: textColor, font: { size: 10 } }, grid: { color: gridColor } },
            y: { ticks: { color: textColor, font: { size: 10 }, callback: v => '$' + v.toFixed(2) }, grid: { color: gridColor } },
          }
        }
      });
    }

    // н”„лЎңл°”мқҙлҚ”лі„ л№„мҡ© л№„көҗ (лҸ„л„ӣ м°ЁнҠё)
    const ctxProvider = document.getElementById('costByProvider');
    if (ctxProvider) {
      const providerColors = ['#d97757','#7dd3fc','#4ade80','#c084fc','#fbbf24','#f87171','#a78bfa','#38bdf8'];
      _renderChart(ctxProvider, {
        type: 'doughnut',
        data: {
          labels: byProvider.map(p => p.provider),
          datasets: [{
            data: byProvider.map(p => p.cost || 0),
            backgroundColor: byProvider.map((_, i) => providerColors[i % providerColors.length]),
            borderColor: 'transparent',
            borderWidth: 2,
          }]
        },
        options: {
          responsive: true, maintainAspectRatio: false,
          plugins: {
            legend: { position: 'right', labels: { color: textColor, font: { size: 11 }, padding: 12 } },
            tooltip: { callbacks: { label: ctx => ctx.label + ': $' + (ctx.parsed || 0).toFixed(4) } },
          }
        }
      });
    }
  } catch(e) { /* л№„мҡ© API лҜём§Җмӣҗ мӢң мЎ°мҡ©нһҲ л¬ҙмӢң */ }
};

// в”Җв”Җ л©ҖнӢ° AI л№„көҗ лӘЁл“ң в”Җв”Җ
window.runMultiCompare = async () => {
  const prompt = (document.getElementById('multiComparePrompt')?.value || '').trim();
  if (!prompt) { toast(t('н”„лЎ¬н”„нҠёлҘј мһ…л Ҙн•ҳм„ёмҡ”'), 'warn'); return; }
  const cbs = document.querySelectorAll('.multi-compare-cb:checked');
  const selectedIds = Array.from(cbs).map(cb => cb.value);
  if (!selectedIds.length) { toast(t('н”„лЎңл°”мқҙлҚ”лҘј м„ нғқн•ҳм„ёмҡ”'), 'warn'); return; }

  const resultsEl = document.getElementById('multiCompareResults');
  if (!resultsEl) return;
  resultsEl.innerHTML = `<div class="text-sm" style="color:var(--text-dim)">${t('л№„көҗ мӢӨн–ү мӨ‘...')} (${selectedIds.length} ${t('н”„лЎңл°”мқҙлҚ”')})</div>`;

  // лӘЁл“  н”„лЎңл°”мқҙлҚ”м—җ лҸҷмӢңм—җ мҡ”мІӯ
  const promises = selectedIds.map(async (pid) => {
    const start = Date.now();
    try {
      const r = await api('/api/ai-providers/test', {
        method: 'POST',
        body: JSON.stringify({ providerId: pid, prompt }),
      });
      const elapsed = Date.now() - start;
      const resp = r.response || {};
      return {
        providerId: pid,
        ok: !!r.ok,
        output: resp.output || r.error || t('мқ‘лӢө м—ҶмқҢ'),
        duration: resp.duration_ms || elapsed,
        tokens: resp.tokens || 0,
        error: r.ok ? null : (r.error || resp.error || t('мӢӨнҢЁ')),
      };
    } catch(e) {
      return { providerId: pid, ok: false, output: '', duration: Date.now() - start, tokens: 0, error: String(e) };
    }
  });

  const results = await Promise.allSettled(promises);
  const providers = (state.data._aiProviders?.providers) || [];

  const cards = results.map(r => {
    const v = r.status === 'fulfilled' ? r.value : { providerId: '?', ok: false, output: '', duration: 0, tokens: 0, error: t('мҡ”мІӯ мӢӨнҢЁ') };
    const p = providers.find(x => x.id === v.providerId) || {};
    const statusChip = v.ok
      ? '<span class="chip chip-ok text-xs">' + t('м„ұкіө') + '</span>'
      : '<span class="chip chip-err text-xs">' + t('мӢӨнҢЁ') + '</span>';
    return `
      <div class="card p-4 flex-1 min-w-[260px]">
        <div class="flex items-center justify-between mb-2">
          <div class="flex items-center gap-2">
            <span class="text-lg">${p.icon || 'рҹ”Ң'}</span>
            <span class="font-semibold text-sm" style="color:var(--text)">${escapeHtml(p.name || v.providerId)}</span>
          </div>
          ${statusChip}
        </div>
        <div class="flex gap-3 mb-2">
          <span class="chip text-xs">${v.duration}ms</span>
          <span class="chip text-xs">${(v.tokens || 0).toLocaleString()} ${t('нҶ нҒ°')}</span>
        </div>
        ${v.error ? `<div class="text-xs mb-2" style="color:var(--err)">${escapeHtml(v.error)}</div>` : ''}
        <pre class="text-xs whitespace-pre-wrap break-words" style="max-height:200px;overflow-y:auto;color:var(--text-mute);background:var(--code-bg);padding:8px;border-radius:8px;">${escapeHtml((v.output || '').substring(0, 2000))}</pre>
      </div>`;
  }).join('');

  resultsEl.innerHTML = `<div class="flex flex-wrap gap-4">${cards}</div>`;
};

