        <pre class="mono text-[10px] whitespace-pre-wrap bg-[var(--code-bg)] p-3 rounded max-h-[300px] overflow-y-auto">${escapeHtml(JSON.stringify(d.statusLine || { _hint: 'settings.json м—җ statusLine нӮӨ м¶”к°Җ' }, null, 2))}</pre>
