// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.learner = async () => {
  const d = await api('/api/learner/patterns');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('лҚ°мқҙн„°лҘј л¶Ҳлҹ¬мҳӨм§Җ лӘ»н–ҲмҠөлӢҲлӢӨ')}</div>`;
  if ((d.sessions || 0) === 0) {
    return `
      ${viewHeader('рҹҺ“ Learner', t('learner_subtitle', 'мөңк·ј м„ём…ҳм—җм„ң л°ҳліөлҗҳлҠ” нҢЁн„ҙмқ„ мһҗлҸҷ м¶”м¶ң. AI нҢҗлӢЁ м—Ҷмқҙ нҶөкі„ кё°л°ҳ.'), 'learner')}
      <div class="card p-6 text-center text-[12px]" style="color:var(--text-dim)">
        ${t('learner_no_sessions', 'мөңк·ј 30мқј м„ём…ҳмқҙ м—ҶмҠөлӢҲлӢӨ. Claude Code лҘј н•ң лІҲ мқҙмғҒ мӮ¬мҡ©н•ҳм„ёмҡ”.')}
      </div>`;
  }
  const stats = d.stats || {};
  const topTools = (stats.topTools || []).slice(0, 8);
  const maxTool = topTools.reduce((m, x) => Math.max(m, x.count), 1);
  const lb = stats.lengthBuckets || {};
  const totalSess = d.sessions || 0;

  const toolRows = topTools.map(x => `
    <div class="flex items-center gap-2 text-[11px]">
      <span class="w-28 font-mono truncate" title="${escapeHtml(x.name)}">${escapeHtml(x.name)}</span>
      <div class="flex-1 h-3 rounded" style="background:rgba(255,255,255,0.06); position:relative;">
        <div style="background:var(--accent);height:100%;border-radius:4px;width:${(x.count/maxTool*100).toFixed(0)}%;"></div>
      </div>
      <span class="w-10 text-right font-mono" style="color:var(--text-dim)">${x.count}</span>
    </div>`).join('');

  const patternCards = (d.patterns || []).map((p, i) => {
    if (p.type === 'repeated_prompt') {
      return `
        <div class="card p-3">
          <div class="flex items-start justify-between mb-1 gap-2">
            <div class="text-[12px] font-semibold">рҹ“қ ${t('learner_repeated_prompt', 'л°ҳліө н”„лЎ¬н”„нҠё')}</div>
            <span class="chip text-[10px]">${p.count}Г—</span>
          </div>
          <div class="text-[11px] mb-2 line-clamp-2" style="color:var(--text-mute)">${escapeHtml(p.detail)}</div>
          <button class="btn btn-primary text-[11px] w-full"
                  onclick='_learnerToPromptLib(${JSON.stringify(p.action).replace(/'/g, "&#39;")})'>
            вҶ’ ${t('learner_to_prompt_lib', 'Prompt Library лЎң м ҖмһҘ')}
          </button>
        </div>`;
    } else if (p.type === 'tool_sequence') {
      return `
        <div class="card p-3">
          <div class="flex items-start justify-between mb-1 gap-2">
            <div class="text-[12px] font-semibold">рҹ”Җ ${t('learner_tool_seq', 'Tool мӢңнҖҖмҠӨ')}</div>
            <span class="chip text-[10px]">${p.count}Г—</span>
          </div>
          <div class="text-[11px] mb-2">
            ${p.action.sequence.map(s => `<span class="chip text-[10px] font-mono">${escapeHtml(s)}</span>`).join(' вҶ’ ')}
          </div>
          <div class="text-[10px] mb-2" style="color:var(--text-dim)">${escapeHtml(p.detail)}</div>
          <button class="btn btn-primary text-[11px] w-full" onclick="go('workflows')">
            вҶ’ ${t('learner_to_workflows', 'мӣҢнҒ¬н”ҢлЎңмҡ° нғӯмңјлЎң мқҙлҸҷ')}
          </button>
        </div>`;
    }
    return '';
  }).join('') || `<div class="text-[11px]" style="color:var(--text-dim)">${t('learner_no_patterns', 'м•„м§Ғ м ңм•Ҳн•  нҢЁн„ҙмқҙ м¶©л¶„нһҲ лҲ„м Ғлҗҳм§Җ м•Ҡм•ҳмҠөлӢҲлӢӨ.')}</div>`;

  const lengthsTotal = (lb.small||0)+(lb.medium||0)+(lb.large||0)+(lb.huge||0);
  const bar = (n) => lengthsTotal ? (n/lengthsTotal*100).toFixed(0) : 0;

  return `
    ${viewHeader('рҹҺ“ Learner', t('learner_subtitle', 'мөңк·ј м„ём…ҳм—җм„ң л°ҳліөлҗҳлҠ” нҢЁн„ҙмқ„ мһҗлҸҷ м¶”м¶ң. AI нҢҗлӢЁ м—Ҷмқҙ нҶөкі„ кё°л°ҳ.'), 'learner')}

    <div class="grid grid-cols-1 md:grid-cols-3 gap-3 mb-4">
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('learner_sessions_scanned', 'мҠӨмә”н•ң м„ём…ҳ')}</div>
        <div class="text-2xl font-bold mt-1 font-mono">${totalSess}</div>
        <div class="text-[10px]" style="color:var(--text-dim)">${t('learner_days_window', `мөңк·ј ${d.days}мқј`)}</div>
      </div>
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider">${t('learner_total_tokens', 'лҲ„м Ғ нҶ нҒ°')}</div>
        <div class="text-2xl font-bold mt-1 font-mono" style="color:var(--accent)">${(stats.totalTokens||0).toLocaleString()}</div>
      </div>
      <div class="card p-4">
        <div class="text-[10px] text-[var(--text-dim)] uppercase tracking-wider mb-2">${t('learner_length_dist', 'м„ём…ҳ кёёмқҙ л¶„нҸ¬')}</div>
        <div class="flex gap-1 h-4 rounded overflow-hidden" style="background:rgba(255,255,255,0.05);">
          <div style="width:${bar(lb.small||0)}%;background:#4ade80" title="small вүӨ10: ${lb.small||0}"></div>
          <div style="width:${bar(lb.medium||0)}%;background:#60a5fa" title="medium 10-50: ${lb.medium||0}"></div>
          <div style="width:${bar(lb.large||0)}%;background:#a78bfa" title="large 50-200: ${lb.large||0}"></div>
          <div style="width:${bar(lb.huge||0)}%;background:#f472b6" title="huge >200: ${lb.huge||0}"></div>
        </div>
        <div class="flex gap-2 text-[9px] mt-1" style="color:var(--text-dim)">
          <span>рҹҹў ${lb.small||0} small</span><span>рҹ”ө ${lb.medium||0} med</span>
          <span>рҹҹЈ ${lb.large||0} large</span><span>рҹҢё ${lb.huge||0} huge</span>
        </div>
      </div>
    </div>

    <div class="grid grid-cols-1 lg:grid-cols-2 gap-4 mb-4">
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">рҹӣ пёҸ ${t('learner_top_tools', 'мһҗмЈј м“°лҠ” Tool')}</div>
        <div class="space-y-1.5">${toolRows || `<div class="text-[10px]" style="color:var(--text-dim)">${t('лҚ°мқҙн„° м—ҶмқҢ')}</div>`}</div>
      </div>
      <div class="card p-4">
        <div class="text-[12px] font-semibold mb-2">рҹ’Ў ${t('learner_suggestions', 'мһҗлҸҷ м¶”м¶ңлҗң м ңм•Ҳ')}</div>
        <div class="grid grid-cols-1 gap-2">${patternCards}</div>
      </div>
    </div>

    <div class="text-[10px]" style="color:var(--text-dim)">
      ${t('learner_hint', 'л¶„м„қмқҖ мҷ„м „нһҲ лЎңм»¬м—җм„ң мҲҳн–үлҗ©лӢҲлӢӨ. Claude API нҳём¶ң м—ҶмқҢ. м ңм•Ҳ м№ҙл“ңлҠ” нҒҙлҰӯ мӢң н•ҙлӢ№ нғӯмңјлЎң мқҙлҸҷн•ҳм—¬ мҲҳлҸҷ м ҖмһҘн•  мҲҳ мһҲмҠөлӢҲлӢӨ.')}
    </div>
  `;
};

function _learnerToPromptLib(action) {
  try {
    state.data.pl = state.data.pl || {};
    state.data.pl.editing = {
      title: (action.suggestedTitle || '').slice(0, 80) || 'From Learner',
      body: action.body || '',
      tags: ['learner'], tagsRaw: 'learner',
      keywords: [], keywordsRaw: '',
      model: '',
    };
    go('promptLibrary');
    toast(t('learner_prefilled', 'м—җл””н„°м—җ лҜёлҰ¬ мұ„мӣҢмЎҢмҠөлӢҲлӢӨ вҖ” кІҖнҶ  нӣ„ м ҖмһҘн•ҳм„ёмҡ”'), 'ok');
  } catch (e) { toast(String(e), 'err'); }
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// v2.42.0 вҖ” Four new Anthropic API labs:
