VIEWS.computerUseLab = async () => {
  const ex = await api('/api/computer-use-lab/examples');
  const hist = await api('/api/computer-use-lab/history');
  const items = (hist.items || []).slice(0, 10);
  const examples = (ex.examples || []).map(e =>
    `<button class="chip text-[10px] cursor-pointer" onclick="document.getElementById('cuPrompt').value=${jsonAttr(e.prompt)};document.getElementById('cuW').value=${e.screenSize.width};document.getElementById('cuH').value=${e.screenSize.height};">${escapeHtml(e.title)}</button>`).join(' ');
  return `
    <h1 class="text-2xl font-bold mb-1">рҹ–ұпёҸ ${t('Computer Use Lab')}</h1>
    <p class="text-sm text-[var(--text-mute)] mb-4">${t('Anthropic computer-use-2025-01-24 beta В· plan-only (мӢӨн–үн•ҳм§Җ м•ҠмқҢ)')}</p>
    <div class="card p-4 mb-3" style="background:rgba(251,191,36,0.06);border-color:rgba(251,191,36,0.3);">
      <div class="text-[11px] mb-2" style="color:#fcd34d;">вҡ  ${t('лҢҖмӢңліҙл“ңлҠ” лӘЁлҚёмқҳ tool planл§Ң н‘ңмӢң вҖ” мӢӨм ң л§Ҳмҡ°мҠӨ/нӮӨліҙл“ң м ңм–ҙлҠ” н•ҳм§Җ м•ҠмҠөлӢҲлӢӨ.')}</div>
    </div>
    <div class="card p-4 mb-3">
      <div class="flex flex-wrap gap-1 mb-2">${examples}</div>
      <textarea id="cuPrompt" class="input w-full" rows="3" placeholder="${t('мҳҲ: Open Finder and click DocumentsвҖҰ')}"></textarea>
      <div class="flex flex-wrap items-center gap-2 mt-2">
        <select id="cuModel" class="input">${(ex.models||[]).map(m => `<option>${m}</option>`).join('')}</select>
        <input id="cuW" class="input" type="number" value="1920" style="width:90px" title="width"/>
        <span>Г—</span>
        <input id="cuH" class="input" type="number" value="1080" style="width:90px" title="height"/>
        <input id="cuShot" class="input flex-1" type="text" placeholder="${t('мҠӨнҒ¬лҰ°мғ· кІҪлЎң (~/.claude н•ҳмң„, м„ нғқ)')}"/>
        <button class="btn-primary btn" onclick="_cuRun()">в–¶ ${t('мӢӨн–ү')}</button>
      </div>
    </div>
    <div id="cuResult" class="mb-3"></div>
    ${items.length ? `
    <div class="card p-3 mb-3">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('мөңк·ј нҳём¶ң')}</div>
      ${items.map(h => `<div class="flex items-center gap-2 py-1 border-b border-[var(--border)] text-[11px]">
        <span class="mono">${h.model}</span>
        <span class="flex-1 truncate">${escapeHtml(h.prompt||'')}</span>
        <span class="chip text-[10px]">${h.toolPlanCount} ${t('нҲҙ нҳём¶ң')}</span>
        <span class="text-[10px] text-[var(--text-dim)]">${(h.tokensIn+h.tokensOut).toLocaleString()} tok В· $${(h.costUsd||0).toFixed(4)}</span>
        ${h.error ? `<span class="chip chip-err text-[10px]">err</span>` : ''}
      </div>`).join('')}
    </div>` : ''}
  `;
};
async function _cuRun() {
  const prompt = document.getElementById('cuPrompt').value;
  const model = document.getElementById('cuModel').value;
  const width = parseInt(document.getElementById('cuW').value, 10) || 1920;
  const height = parseInt(document.getElementById('cuH').value, 10) || 1080;
  const screenshotPath = document.getElementById('cuShot').value || '';
  const out = document.getElementById('cuResult');
  if (out) out.innerHTML = `<div class="card p-4 text-center text-xs">${t('мӢӨн–ү мӨ‘вҖҰ')}</div>`;
  try {
    const r = await api('/api/computer-use-lab/run', { method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ prompt, model, screenSize: {width, height}, screenshotPath }) });
    if (!r.ok) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(r.error||'')}</div>`; return; }
    out.innerHTML = `
      <div class="card p-4">
        <div class="flex flex-wrap gap-2 text-[11px] mb-2">
          <span class="chip">${escapeHtml(r.model)}</span>
          <span class="chip">${r.tokensIn}/${r.tokensOut} tok</span>
          <span class="chip">$${(r.costUsd||0).toFixed(4)}</span>
          <span class="chip">${r.durationMs}ms</span>
        </div>
        <div class="text-[11px] uppercase text-[var(--text-dim)] mt-2 mb-1">${t('Tool Plan')} (${r.toolPlan.length})</div>
        ${r.toolPlan.length ? r.toolPlan.map((p,i) => `
          <div class="card p-2 mb-1" style="background:rgba(0,0,0,0.2);">
            <div class="text-[11px]"><span class="chip text-[9px]">${i+1}</span> <span class="font-semibold mono">${escapeHtml(p.action)}</span></div>
            <pre class="mono text-[10px] mt-1" style="white-space:pre-wrap;">${escapeHtml(JSON.stringify(p.params, null, 2))}</pre>
          </div>`).join('') : `<div class="empty text-xs">${t('нҲҙ нҳём¶ң м—ҶмқҢ вҖ” лӘЁлҚёмқҙ н…ҚмҠӨнҠёлЎңл§Ң мқ‘лӢө')}</div>`}
        ${r.text ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mt-3 mb-1">${t('н…ҚмҠӨнҠё мқ‘лӢө')}</div><div class="text-xs">${escapeHtml(r.text)}</div>` : ''}
        ${r.imageWarning ? `<div class="text-[11px] mt-2" style="color:#fcd34d;">вҡ  ${escapeHtml(r.imageWarning)}</div>` : ''}
      </div>`;
  } catch (e) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(e.message)}</div>`; }
}

VIEWS.memoryLab = async () => {
  const ex = await api('/api/memory-lab/examples');
  const hist = await api('/api/memory-lab/history');
  const blocks = await api('/api/memory-lab/blocks');
  const items = (hist.items || []).slice(0, 10);
  const examples = (ex.examples || []).map(e =>
    `<button class="chip text-[10px] cursor-pointer" onclick="document.getElementById('mlPrompt').value=${jsonAttr(e.prompt)};">${escapeHtml(e.title)}</button>`).join(' ');
  return `
    <h1 class="text-2xl font-bold mb-1">рҹ§© ${t('Memory Lab')}</h1>
    <p class="text-sm text-[var(--text-mute)] mb-4">${t('Anthropic memory-2025-08-18 beta В· м„ңлІ„мёЎ memory blocks лқјмҡҙл“ңнҠёлҰҪ')}</p>
    <div class="card p-4 mb-3">
      <div class="flex flex-wrap gap-1 mb-2">${examples}</div>
      <textarea id="mlPrompt" class="input w-full" rows="3" placeholder="${t('мҳҲ: лӮҙ мқҙлҰ„мқҖ Alex мқҙкі  к°„кІ°н•ң лӢөліҖ м„ нҳё. кё°м–өн•ҙмӨҳ.')}"></textarea>
      <div class="flex items-center gap-2 mt-2">
        <select id="mlModel" class="input">${(ex.models||[]).map(m => `<option>${m}</option>`).join('')}</select>
        <button class="btn-primary btn" onclick="_mlRun()">в–¶ ${t('мӢӨн–ү')}</button>
      </div>
    </div>
    <div id="mlResult" class="mb-3"></div>
    ${(blocks.items && blocks.items.length) ? `
    <div class="card p-3 mb-3">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">рҹ“Ұ ${t('кҙҖм°°лҗң л©”лӘЁлҰ¬ лё”лЎқ')} (${blocks.items.length})</div>
      ${blocks.items.slice(0,20).map(b => `<div class="flex gap-2 py-1 border-b border-[var(--border)] text-[11px]">
        <span class="mono font-semibold">${escapeHtml(b.key||'')}</span>
        <span class="flex-1 truncate text-[var(--text-mute)]">${escapeHtml(b.value||'')}</span>
      </div>`).join('')}
    </div>` : ''}
    ${items.length ? `
    <div class="card p-3 mb-3">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('мөңк·ј нҳём¶ң')}</div>
      ${items.map(h => `<div class="py-1 border-b border-[var(--border)] text-[11px]">
        <div class="flex items-center gap-2"><span class="mono">${h.model}</span><span class="flex-1 truncate">${escapeHtml(h.prompt||'')}</span>
          <span class="chip text-[10px]">${(h.memoryEvents||[]).length} ${t('мқҙлІӨнҠё')}</span>
          <span class="text-[10px] text-[var(--text-dim)]">$${(h.costUsd||0).toFixed(4)}</span></div>
      </div>`).join('')}
    </div>` : ''}
  `;
};
async function _mlRun() {
  const prompt = document.getElementById('mlPrompt').value;
  const model = document.getElementById('mlModel').value;
  const out = document.getElementById('mlResult');
  if (out) out.innerHTML = `<div class="card p-4 text-center text-xs">${t('мӢӨн–ү мӨ‘вҖҰ')}</div>`;
  try {
    const r = await api('/api/memory-lab/run', { method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ prompt, model }) });
    if (!r.ok) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(r.error||'')}</div>`; return; }
    out.innerHTML = `
      <div class="card p-4">
        <div class="flex flex-wrap gap-2 text-[11px] mb-2">
          <span class="chip">${escapeHtml(r.model)}</span>
          <span class="chip">${r.tokensIn}/${r.tokensOut} tok</span>
          <span class="chip">$${(r.costUsd||0).toFixed(4)}</span>
          <span class="chip">${r.durationMs}ms</span>
        </div>
        ${r.memoryEvents.length ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mt-2 mb-1">${t('л©”лӘЁлҰ¬ мқҙлІӨнҠё')} (${r.memoryEvents.length})</div>
          ${r.memoryEvents.map(ev => `<div class="card p-2 mb-1" style="background:rgba(0,0,0,0.2);">
            <span class="chip chip-accent text-[10px]">${escapeHtml(ev.op)}</span>
            <span class="mono text-[11px] ml-2">${escapeHtml(ev.key||'(no key)')}</span>
            ${ev.value ? `<div class="text-[11px] mt-1" style="color:var(--text-mute);">${escapeHtml(ev.value)}</div>` : ''}
          </div>`).join('')}` : `<div class="empty text-xs">${t('л©”лӘЁлҰ¬ мқҙлІӨнҠё м—ҶмқҢ вҖ” лӘЁлҚёмқҙ л©”лӘЁлҰ¬лҘј мӮ¬мҡ©н•ҳм§Җ м•ҠмқҢ')}</div>`}
        ${r.text ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mt-3 mb-1">${t('мқ‘лӢө')}</div><div class="text-xs">${escapeHtml(r.text)}</div>` : ''}
      </div>`;
  } catch (e) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(e.message)}</div>`; }
}

VIEWS.advisorLab = async () => {
  const ex = await api('/api/advisor-lab/examples');
  const hist = await api('/api/advisor-lab/history');
  const items = (hist.items || []).slice(0, 10);
  const examples = (ex.examples || []).map(e =>
    `<button class="chip text-[10px] cursor-pointer" onclick="document.getElementById('alPrompt').value=${jsonAttr(e.prompt)};">${escapeHtml(e.title)}</button>`).join(' ');
  return `
    <h1 class="text-2xl font-bold mb-1">рҹ§ӯ ${t('Advisor Lab')}</h1>
    <p class="text-sm text-[var(--text-mute)] mb-4">${t('Executor (м Җл№„мҡ©/л№ лҰ„) + Advisor (кі м§ҖлҠҘ/лҠҗлҰј) нҺҳм–ҙл§Ғ вҖ” л№„мҡ©/н’Ҳм§Ҳ лҚёнғҖ мӢңк°Ғнҷ”')}</p>
    <div class="card p-4 mb-3">
      <div class="flex flex-wrap gap-1 mb-2">${examples}</div>
      <textarea id="alPrompt" class="input w-full" rows="3" placeholder="${t('лҸҷмқј н”„лЎ¬н”„нҠёк°Җ л‘җ лӘЁлҚём—җ ліҙлӮҙм§Җкі  кІ°кіјк°Җ л№„көҗлҗ©лӢҲлӢӨ.')}"></textarea>
      <div class="flex items-center gap-2 mt-2 flex-wrap">
        <label class="text-xs">${t('Executor')}: <select id="alExec" class="input">${(ex.executors||[]).map(m => `<option>${m}</option>`).join('')}</select></label>
        <label class="text-xs">${t('Advisor')}: <select id="alAdv" class="input">${(ex.advisors||[]).map(m => `<option ${m==='claude-opus-4-7'?'selected':''}>${m}</option>`).join('')}</select></label>
        <button class="btn-primary btn" onclick="_alRun()">в–¶ ${t('мӢӨн–ү')}</button>
      </div>
    </div>
    <div id="alResult" class="mb-3"></div>
    ${items.length ? `
    <div class="card p-3 mb-3">
      <div class="text-[11px] uppercase text-[var(--text-dim)] mb-2">${t('мөңк·ј нҳём¶ң')}</div>
      ${items.map(h => `<div class="py-1 border-b border-[var(--border)] text-[11px] flex flex-wrap gap-2">
        <span class="mono">${h.executor}вҶ’${h.advisor}</span>
        <span class="flex-1 truncate">${escapeHtml(h.prompt||'')}</span>
        <span class="text-[10px] text-[var(--text-dim)]">$${(h.costUsd||0).toFixed(4)}</span>
        <span class="text-[10px] text-[var(--text-dim)]">${h.durationMs}ms</span>
      </div>`).join('')}
    </div>` : ''}
  `;
};
async function _alRun() {
  const prompt = document.getElementById('alPrompt').value;
  const executor = document.getElementById('alExec').value;
  const advisor = document.getElementById('alAdv').value;
  const out = document.getElementById('alResult');
  if (out) out.innerHTML = `<div class="card p-4 text-center text-xs">${t('мӢӨн–ү мӨ‘ (executor вҶ’ advisor)вҖҰ')}</div>`;
  try {
    const r = await api('/api/advisor-lab/run', { method:'POST', headers:{'Content-Type':'application/json'},
      body: JSON.stringify({ prompt, executor, advisor }) });
    if (!r.ok) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(r.error||'')}${r.stage?` (${r.stage})`:''}</div>`; return; }
    const e1 = r.executor, e2 = r.advisor, dl = r.delta;
    out.innerHTML = `
      <div class="grid grid-cols-1 md:grid-cols-2 gap-3 mb-3">
        <div class="card p-4">
          <div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">вҡЎ ${t('Executor')}</div>
          <div class="font-semibold text-sm mb-2 mono">${escapeHtml(e1.model)}</div>
          <div class="flex gap-2 mb-2 text-[11px]"><span class="chip">${e1.tokensIn}/${e1.tokensOut} tok</span><span class="chip">$${e1.costUsd.toFixed(4)}</span><span class="chip">${e1.durationMs}ms</span></div>
          <div class="text-xs" style="white-space:pre-wrap;">${escapeHtml(e1.response||'')}</div>
        </div>
        <div class="card p-4" style="border-color:rgba(244,114,182,0.3);">
          <div class="text-[11px] uppercase" style="color:#f9a8d4;">рҹ§ӯ ${t('Advisor')}</div>
          <div class="font-semibold text-sm mb-2 mono">${escapeHtml(e2.model)}</div>
          <div class="flex gap-2 mb-2 text-[11px]"><span class="chip">${e2.tokensIn}/${e2.tokensOut} tok</span><span class="chip">$${e2.costUsd.toFixed(4)}</span><span class="chip">${e2.durationMs}ms</span></div>
          <div class="text-xs" style="white-space:pre-wrap;">${escapeHtml(e2.response||'')}</div>
        </div>
      </div>
      <div class="card p-3 text-[11px]">
        <span class="font-semibold">${t('лҚёнғҖ')}:</span>
        <span class="ml-2">${t('нҶ нҒ°')}: ${dl.tokensDiff>0?'+':''}${dl.tokensDiff}</span>
        <span class="ml-2">${t('л№„мҡ©')}: ${dl.costDiff>0?'+':''}$${dl.costDiff.toFixed(4)}</span>
        <span class="ml-2">${t('м§Җм—°')}: ${dl.latencyDiff>0?'+':''}${dl.latencyDiff}ms</span>
      </div>`;
  } catch (e) { out.innerHTML = `<div class="card p-4" style="color:#fca5a5;">${escapeHtml(e.message)}</div>`; }
}

VIEWS.routines = async () => {
  const r = await api('/api/routines/list');
  const items = r.items || [];
  return `
    <div class="mb-4 flex items-start justify-between gap-2 flex-wrap">
      <div>
        <h1 class="text-2xl font-bold">рҹ”Ғ ${t('Claude Code Routines')}</h1>
        <p class="text-sm text-[var(--text-mute)] mt-1">${t('Path:')} <code class="mono">${escapeHtml(r.dir||'~/.claude/scheduled-tasks')}</code></p>
      </div>
      <button class="btn-primary btn" onclick="_routineEdit()">пјӢ ${t('мғҲ лЈЁнӢҙ')}</button>
    </div>
    ${items.length ? `<div class="grid gap-2" style="grid-template-columns:repeat(auto-fill, minmax(320px, 1fr));">
      ${items.map(it => `<div class="card p-3" style="background:rgba(167,139,250,0.04);">
        <div class="font-semibold text-sm mono mb-1 truncate">${escapeHtml(it.name)} ${it.enabled?'':'<span class="chip chip-warn text-[9px]">disabled</span>'}</div>
        <div class="text-[11px] text-[var(--text-mute)] line-clamp-2 mb-1" style="min-height:2em;">${escapeHtml(it.description||'')}</div>
        <div class="text-[10px] text-[var(--text-dim)] mb-1">${t('мҠӨмјҖмӨ„')}: <span class="mono">${escapeHtml(it.schedule||'(none)')}</span></div>
        <pre class="mono text-[10px]" style="background:rgba(0,0,0,0.3);padding:6px;border-radius:6px;max-height:80px;overflow:auto;">${escapeHtml(it.command||'(empty)')}</pre>
        <div class="flex gap-1 mt-2 flex-wrap">
          <button class="btn text-[10px]" onclick="_routineRun('${escapeHtml(it.name)}', false)">в–¶ ${t('мӢӨн–ү')}</button>
          <button class="btn text-[10px]" onclick="_routineRun('${escapeHtml(it.name)}', true)">рҹ‘Ғ ${t('Dry-run')}</button>
          <button class="btn text-[10px]" onclick="_routineEdit('${escapeHtml(it.name)}')">${t('нҺём§‘')}</button>
          <button class="btn text-[10px]" style="color:#fca5a5;" onclick="_routineDelete('${escapeHtml(it.name)}')">${t('мӮӯм ң')}</button>
        </div>
      </div>`).join('')}</div>` : `<div class="card empty">${t('лЈЁнӢҙмқҙ м—ҶмҠөлӢҲлӢӨ. пјӢ мғҲ лЈЁнӢҙ мңјлЎң л§Ңл“Өм–ҙліҙм„ёмҡ”.')}</div>`}
  `;
};
async function _routineEdit(name) {
  let initial = { name: name || '', description: '', schedule: '0 */6 * * *', command: '', cwd: '~/', enabled: true };
  if (name) {
    const r = await api('/api/routines/get/' + encodeURIComponent(name));
    if (r.ok) initial = r.meta;
  }
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <h2 class="text-lg font-bold">рҹ”Ғ ${name ? t('лЈЁнӢҙ нҺём§‘') : t('мғҲ лЈЁнӢҙ')}</h2>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div class="p-5 overflow-y-auto" style="max-height:75vh;">
      <label class="block mb-2"><div class="text-xs font-semibold mb-1">${t('мқҙлҰ„')} *</div>
        <input id="rtName" class="input w-full mono" value="${escapeHtml(initial.name)}" ${name?'readonly':''} placeholder="my-routine"></label>
      <label class="block mb-2"><div class="text-xs font-semibold mb-1">${t('м„ӨлӘ…')}</div>
        <input id="rtDesc" class="input w-full" value="${escapeHtml(initial.description)}"></label>
      <label class="block mb-2"><div class="text-xs font-semibold mb-1">${t('мҠӨмјҖмӨ„ (cron)')}</div>
        <input id="rtSched" class="input w-full mono" value="${escapeHtml(initial.schedule)}" placeholder="0 */6 * * *"></label>
      <label class="block mb-2"><div class="text-xs font-semibold mb-1">${t('лӘ…л №')} *</div>
        <textarea id="rtCmd" class="input w-full mono" rows="3" placeholder="claude --print 'do the thing'">${escapeHtml(initial.command)}</textarea></label>
      <label class="block mb-2"><div class="text-xs font-semibold mb-1">${t('мһ‘м—… л””л үнҶ лҰ¬ (cwd)')}</div>
        <input id="rtCwd" class="input w-full mono" value="${escapeHtml(initial.cwd)}" placeholder="~/work/proj"></label>
      <label class="flex items-center gap-2 mb-3"><input type="checkbox" id="rtEnabled" ${initial.enabled?'checked':''}/> <span class="text-xs">${t('нҷңм„ұ')}</span></label>
      <div class="flex gap-2 pt-3 border-t border-[var(--border)]">
        <button class="btn-primary btn" onclick="_routineSave()">рҹ’ҫ ${t('м ҖмһҘ')}</button>
        <button class="btn" onclick="closeModal()">${t('м·ЁмҶҢ')}</button>
      </div>
    </div>
  `);
}
async function _routineSave() {
  const body = {
    name: document.getElementById('rtName').value.trim(),
    description: document.getElementById('rtDesc').value,
    schedule: document.getElementById('rtSched').value,
    command: document.getElementById('rtCmd').value,
    cwd: document.getElementById('rtCwd').value,
    enabled: document.getElementById('rtEnabled').checked,
  };
  if (!body.name || !body.command) { toast(t('мқҙлҰ„кіј лӘ…л №мқҙ н•„мҡ”н•©лӢҲлӢӨ'), 'err'); return; }
  try {
    const r = await api('/api/routines/save', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify(body) });
    if (r.ok) { toast(t('м ҖмһҘлҗЁ'), 'ok'); closeModal(); renderView(); }
    else toast(t('м ҖмһҘ мӢӨнҢЁ: ') + (r.error||''), 'err');
  } catch (e) { toast(t('м ҖмһҘ мӢӨнҢЁ: ') + e.message, 'err'); }
}
async function _routineDelete(name) {
  if (!confirm(t('мқҙ лЈЁнӢҙмқ„ мӮӯм ңн• к№Ңмҡ”?'))) return;
  const r = await api('/api/routines/delete', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({name}) });
  if (r.ok) { toast(t('мӮӯм ңлҗЁ'), 'ok'); renderView(); }
  else toast(t('мӮӯм ң мӢӨнҢЁ: ') + (r.error||''), 'err');
}
async function _routineRun(name, dryRun) {
  if (!dryRun && !confirm(t('мқҙ лЈЁнӢҙмқ„ м§ҖкёҲ мӢӨн–үн• к№Ңмҡ”?'))) return;
  toast(dryRun ? t('Dry-runвҖҰ') : t('мӢӨн–ү мӨ‘вҖҰ'), 'info');
  const r = await api('/api/routines/run', { method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({name, dryRun}) });
  showModal(`
    <div class="p-5 border-b border-[var(--border)] flex items-center justify-between">
      <h2 class="text-lg font-bold">${dryRun ? 'рҹ‘Ғ ' : 'в–¶ '}${escapeHtml(name)} ${r.ok ? 'вң“' : 'вң—'}</h2>
      <button class="btn-ghost btn" onclick="closeModal()">вң•</button>
    </div>
    <div class="p-5 overflow-y-auto" style="max-height:75vh;">
      ${r.command ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">${t('лӘ…л №')}</div><pre class="mono text-[11px] mb-3" style="background:rgba(0,0,0,0.3);padding:6px;border-radius:6px;">${escapeHtml(r.command)}</pre>` : ''}
      ${r.cwd ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">cwd</div><pre class="mono text-[11px] mb-3">${escapeHtml(r.cwd)}</pre>` : ''}
      ${r.error ? `<div style="color:#fca5a5;">${escapeHtml(r.error)}</div>` : ''}
      ${r.stdout ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">stdout (returncode=${r.returncode}, ${r.durationMs}ms)</div><pre class="mono text-[11px] mb-3" style="background:rgba(0,0,0,0.3);padding:6px;border-radius:6px;max-height:240px;overflow:auto;white-space:pre-wrap;">${escapeHtml(r.stdout)}</pre>` : ''}
      ${r.stderr ? `<div class="text-[11px] uppercase text-[var(--text-dim)] mb-1">stderr</div><pre class="mono text-[11px]" style="background:rgba(50,0,0,0.2);padding:6px;border-radius:6px;max-height:240px;overflow:auto;white-space:pre-wrap;">${escapeHtml(r.stderr)}</pre>` : ''}
    </div>
  `);
}

// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
// SESSION REPLAY LAB (v2.25.0) вҖ” Claude Code JSONL нғҖмһ„лқјмқё мһ¬мғқ
// в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
VIEWS.sessionReplay = async () => {
  const d = await api('/api/session-replay/list');
  if (!d.ok) return `<div class="card p-6 text-[12px]">${t('лҚ°мқҙн„°лҘј л¶Ҳлҹ¬мҳӨм§Җ лӘ»н–ҲмҠөлӢҲлӢӨ')}</div>`;
  const files = d.files || [];
  const sel = state.data._srSelected || '';
  const fmt = (n) => n < 1024 ? n + 'B' : n < 1048576 ? (n/1024).toFixed(1) + 'KB' : (n/1048576).toFixed(2) + 'MB';
  const fmtTime = (ms) => new Date(ms).toLocaleString();
  const fileList = files.length
    ? files.map(f => `
        <div class="card p-2 flex items-center justify-between gap-2 ${sel === f.path ? 'border-[var(--accent)]' : ''}" style="border-width:1px;cursor:pointer;" onclick="_srSelect('${escapeHtml(f.path)}')">
          <div class="min-w-0 flex-1">
            <div class="text-[11px] font-mono truncate">${escapeHtml(f.project)}</div>
            <div class="text-[10px] text-[var(--text-dim)] truncate">${escapeHtml(f.path.split('/').pop())}</div>
          </div>
          <div class="text-[10px] text-[var(--text-mute)] flex-shrink-0 text-right">
            <div>${fmt(f.size)}</div>
            <div>${fmtTime(f.mtime)}</div>
          </div>
        </div>`).join('')
    : `<div class="text-[11px]" style="color:var(--text-dim)">${t('sr_no_sessions', 'м„ём…ҳ JSONL мқҙ м—ҶмҠөлӢҲлӢӨ. Claude Code лҘј мөңмҶҢ н•ң лІҲ мӮ¬мҡ©н•ҙ мЈјм„ёмҡ”.')}</div>`;

  return `
    ${viewHeader('рҹҺһпёҸ Session Replay', t('sr_subtitle', 'Claude Code м„ём…ҳ лЎңк·ё(JSONL)лҘј мӢңк°„мҲңмңјлЎң мһ¬мғқ В· нҲҙ нҳём¶ң к°•мЎ° В· лҲ„м Ғ нҶ нҒ° м°ЁнҠё'), 'sessionReplay')}
    <div class="grid grid-cols-1 lg:grid-cols-[320px_1fr] gap-4">
      <div class="space-y-2" style="max-height:70vh;overflow-y:auto;">
        <div class="text-[10px] uppercase tracking-wider" style="color:var(--text-dim)">${t('sr_recent', 'мөңк·ј 50 м„ём…ҳ')}</div>
        ${fileList}
      </div>
      <div id="srDetail">
        ${sel ? '<div class="text-[11px]" style="color:var(--text-dim)">лЎңл”© мӨ‘...</div>' : `<div class="card p-6 text-[12px]" style="color:var(--text-dim)">${t('sr_pick', 'мҷјмӘҪм—җм„ң м„ём…ҳмқ„ м„ нғқн•ҳм„ёмҡ”.')}</div>`}
      </div>
    </div>
  `;
};

function _srSelect(path) {
  state.data._srSelected = path;
  renderView();
  setTimeout(() => _srLoad(path), 20);
}

// v2.33.8 вҖ” sessionReplay нӮӨліҙл“ң л„Өл№„ (J/K/мҲ«мһҗ/Home/End)
function _srHighlight(idx) {
  const rows = document.querySelectorAll('.sr-event-row');
  if (!rows.length) return;
  const n = rows.length;
  idx = Math.max(0, Math.min(n - 1, idx));
  rows.forEach(r => r.style.outline = '');
  const row = rows[idx];
  if (!row) return;
  row.style.outline = '2px solid var(--accent)';
  row.scrollIntoView({ block: 'nearest', behavior: 'smooth' });
  state.data._srCurIdx = idx;
}
_KEYDOWN_HANDLERS.push((e) => {
  if (state.view !== 'sessionReplay') return;
  if (['INPUT','TEXTAREA','SELECT'].includes((document.activeElement||{}).tagName)) return;
  const events = state.data._srEvents || [];
  if (!events.length) return;
  let cur = state.data._srCurIdx;
  if (cur == null || cur < 0) cur = -1;
  const n = events.length;
  if (e.key === 'j' || e.key === 'J') { e.preventDefault(); _srHighlight(cur + 1); return true; }
  if (e.key === 'k' || e.key === 'K') { e.preventDefault(); _srHighlight(cur - 1); return true; }
  if (e.key === 'Home') { e.preventDefault(); _srHighlight(0); return true; }
  if (e.key === 'End') { e.preventDefault(); _srHighlight(n - 1); return true; }
  if (/^[1-9]$/.test(e.key)) {
    e.preventDefault();
    const pct = parseInt(e.key, 10) / 10;
    _srHighlight(Math.floor((n - 1) * pct));
    return true;
  }
});

async function _srLoad(path) {
  const host = document.getElementById('srDetail');
  if (!host) return;
  try {
    const r = await api('/api/session-replay/load?path=' + encodeURIComponent(path));
    if (!r.ok) { host.innerHTML = `<div class="card p-4 text-[12px]" style="color:var(--danger)">${escapeHtml(r.error||'error')}</div>`; return; }
    const events = r.events || [];
    // нҶ нҒ° лҲ„м Ғ мҠӨнҢҢнҒ¬лқјмқё кі„мӮ°
    let acc = 0;
    const points = events.map(e => { acc += (e.tokensIn||0) + (e.tokensOut||0); return acc; });
    const maxAcc = Math.max(1, ...points);
    const spark = points.length ? events.map((e, i) => {
      const x = (i / Math.max(1, points.length - 1)) * 600;
      const y = 40 - (points[i] / maxAcc) * 36;
      return `${i===0?'M':'L'}${x.toFixed(1)},${y.toFixed(1)}`;
    }).join(' ') : '';
    // v2.33.8 вҖ” к°Ғ мқҙлІӨнҠё row м—җ data-sr-idx л¶Җм—¬, J/K/мҲ«мһҗ нӮӨліҙл“ң л„Өл№„
    state.data._srEvents = events;
    state.data._srCurIdx = -1;
    const evtRows = events.map((e, idx) => {
      const roleColor = e.role === 'assistant' ? '#60a5fa' : e.role === 'user' ? '#fbbf24' : '#9ca3af';
      const time = e.ts ? new Date(e.ts).toLocaleTimeString() : '';
      const hasToolUse = (e.summary||'').includes('[tool_use:');
      const bg = hasToolUse ? 'background:rgba(168, 139, 250, 0.08);' : '';
      return `
        <div class="text-[10px] flex gap-2 py-1 border-b border-[var(--border)] sr-event-row" data-sr-idx="${idx}" style="${bg}">
          <span class="font-mono flex-shrink-0" style="color:var(--text-dim);width:80px;">${time}</span>
          <span class="font-semibold flex-shrink-0" style="color:${roleColor};width:70px;">${escapeHtml(e.role || e.type || '-')}</span>
          <span class="flex-1 break-all">${escapeHtml(e.summary || e.operation || '')}</span>
          <span class="flex-shrink-0 font-mono" style="color:var(--text-mute);">${e.tokensIn||0}вҶ“ ${e.tokensOut||0}вҶ‘</span>
        </div>`;
    }).join('');
    host.innerHTML = `
      <div class="card p-3 mb-3">
        <div class="grid grid-cols-3 gap-3 mb-2">
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('мқҙлІӨнҠё')}</div><div class="text-lg font-semibold">${events.length}${r.truncated?'+':''}</div></div>
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('нҶ нҒ° мһ…л Ҙ')}</div><div class="text-lg font-semibold" style="color:#60a5fa">${(r.totalTokensIn||0).toLocaleString()}</div></div>
          <div><div class="text-[10px]" style="color:var(--text-dim)">${t('нҶ нҒ° м¶ңл Ҙ')}</div><div class="text-lg font-semibold" style="color:#f472b6">${(r.totalTokensOut||0).toLocaleString()}</div></div>
        </div>
        ${spark ? `<svg viewBox="0 0 600 40" width="100%" height="40"><path d="${spark}" fill="none" stroke="var(--accent)" stroke-width="1.5" /></svg>` : ''}
        <div class="text-[10px] font-mono break-all" style="color:var(--text-dim)">${escapeHtml(r.path)}</div>
        <div class="text-[10px] mt-1" style="color:var(--text-dim)">вҢЁ ${t('J/K')} ${t('мқҙлІӨнҠё мқҙлҸҷ')} В· ${t('1-9')} ${t('10% м җн”„')} В· ${t('Home/End')} ${t('мІҳмқҢ/лҒқ')}</div>
      </div>
      <div class="card p-3" id="srEventList" style="max-height:60vh;overflow-y:auto;">
        ${evtRows || `<div class="text-[11px]" style="color:var(--text-dim)">(empty)</div>`}
      </div>
    `;
  } catch (e) { host.innerHTML = `<div class="card p-4 text-[12px]" style="color:var(--danger)">${escapeHtml(String(e))}</div>`; }
}

