// Terminal м„Өм№ҳ/нӣ… мҷ„лЈҢлҘј polling мңјлЎң к°җм§Җн•ҙ мһҗлҸҷ renderView (v2.24.1)
let _rtkPollTimer = null;

function _rtkStopPolling() {
  if (_rtkPollTimer) { clearInterval(_rtkPollTimer); _rtkPollTimer = null; }
}

function _rtkStartPolling(mode) {
  _rtkStopPolling();
  const started = Date.now();
  const timeout = mode === 'hook' ? 120000 : 300000;   // нӣ… 2л¶„, м„Өм№ҳ 5л¶„
  const interval = mode === 'hook' ? 1500 : 2500;
  toast(
    mode === 'hook'
      ? t('rtk_polling_hook', 'нӣ… нҷңм„ұнҷ” к°җм§Җ мӨ‘ вҖ” мҷ„лЈҢлҗҳл©ҙ мһҗлҸҷ мғҲлЎңкі м№Ё')
      : t('rtk_polling_install', 'м„Өм№ҳ мҷ„лЈҢ к°җм§Җ мӨ‘ вҖ” мҷ„лЈҢлҗҳл©ҙ мһҗлҸҷ мғҲлЎңкі м№Ё'),
    'info',
  );
  _rtkPollTimer = setInterval(async () => {
    if (Date.now() - started > timeout) {
      _rtkStopPolling();
      toast(t('rtk_polling_timeout', 'к°җм§Җ мӢңк°„ мҙҲкіј вҖ” м§Ғм ‘ мғҲлЎңкі м№Ён•ҙ мЈјм„ёмҡ”'), 'warn');
      return;
    }
    try {
      const r = await api('/api/rtk/status');
      const hit = mode === 'hook' ? !!r.hookInstalled : !!r.installed;
      if (hit) {
        _rtkStopPolling();
        toast(
          mode === 'hook'
            ? t('rtk_detected_hook', 'нӣ… нҷңм„ұ к°җм§Җ вҖ” нғӯ мғҲлЎңкі м№Ё')
            : t('rtk_detected_install', 'rtk м„Өм№ҳ к°җм§Җ вҖ” нғӯ мғҲлЎңкі м№Ё'),
          'ok',
        );
        if (state.view === 'rtk') renderView();
      }
    } catch {}
  }, interval);
}

async function _rtkInstall(method) {
  const ok = await confirmModal(t('rtk_install_confirm', `Terminal м°Ҫмқ„ м—ҙкі  ${method} лЎң м„Өм№ҳн•©лӢҲлӢӨ. кі„мҶҚн• к№Ңмҡ”?`));
  if (!ok) return;
  try {
    const r = await api('/api/rtk/install', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ method }),
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    if (r.already) { toast(t('мқҙлҜё м„Өм№ҳлҗЁ'), 'info'); return; }
    toast(t('rtk_install_launched', 'Terminal м°Ҫмқҙ м—ҙл ёмҠөлӢҲлӢӨ вҖ” м„Өм№ҳ мҷ„лЈҢ нӣ„ мқҙ нғӯмқ„ мғҲлЎңкі м№Ён•ҳм„ёмҡ”'), 'ok');
    _rtkStartPolling('install');
  } catch (e) { toast(String(e), 'err'); }
}

async function _wfNotifyTest(target) {
  if (!__wf.current) return;
  const nf = __wf.current.notify || {};
  const url = (target === 'slack' ? nf.slack : nf.discord) || '';
  if (!url.trim()) { toast(t('notify_url_empty', 'URL мқ„ лЁјм Җ мһ…л Ҙн•ҳм„ёмҡ”'), 'err'); return; }
  try {
    const r = await api('/api/notify/test', {
      method: 'POST', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ target, url }),
    });
    if (r.ok) toast(t('notify_test_sent', 'н…ҢмҠӨнҠё л©”мӢңм§Җ м „мҶЎлҗЁ'), 'ok');
    else toast(errMsg(r), 'err');
  } catch (e) { toast(String(e), 'err'); }
}

async function _rtkUninstallHook() {
  const ok = await confirmModal(t('rtk_uninstall_confirm', 'Claude Code settings.json м—җм„ң rtk нӣ… н•ӯлӘ©л§Ң м ңкұ°н•©лӢҲлӢӨ (л°ұм—… мһҗлҸҷ мғқм„ұ). rtk л°”мқҙл„ҲлҰ¬лҠ” мң м§Җлҗ©лӢҲлӢӨ. кі„мҶҚн• к№Ңмҡ”?'));
  if (!ok) return;
  try {
    const r = await api('/api/rtk/uninstall-hook', {
      method: 'POST', headers: { 'Content-Type': 'application/json' }, body: '{}',
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    if (r.removed === 0) { toast(t('rtk_no_hook_to_remove', 'м ңкұ°н•  rtk нӣ…мқҙ м—ҶмҠөлӢҲлӢӨ'), 'info'); return; }
    toast(t('rtk_hook_removed', `rtk нӣ… ${r.removed}к°ң м ңкұ°лҗЁ (л°ұм—… ліҙмЎҙ)`).replace('${r.removed}', r.removed), 'ok');
    if (state.view === 'rtk') renderView();
  } catch (e) { toast(String(e), 'err'); }
}

async function _rtkInit() {
  const ok = await confirmModal(t('rtk_init_confirm', 'rtk init -g лҘј мӢӨн–үн•ҳл©ҙ Claude Code settings.json мқҙ мҲҳм •лҗ©лӢҲлӢӨ. кі„мҶҚн• к№Ңмҡ”?'));
  if (!ok) return;
  try {
    const r = await api('/api/rtk/init', {
      method: 'POST', headers: { 'Content-Type': 'application/json' }, body: '{}',
    });
    if (!r.ok) { toast(errMsg(r), 'err'); return; }
    toast(t('rtk_init_launched', 'rtk init -g --auto-patch мӢӨн–ү вҖ” settings.json мһҗлҸҷ нҢЁм№ҳ'), 'ok');
    _rtkStartPolling('hook');
  } catch (e) { toast(String(e), 'err'); }
}

