document.getElementById('btn-latest-features').onclick = async () => {
  const btn = document.getElementById('btn-latest-features');
  const orig = btn.innerHTML;
  btn.disabled = true;
  btn.innerHTML = '<span>вҸі</span><span>Claude м—җкІҢ мЎ°мӮ¬ мӨ‘вҖҰ (~1л¶„)</span>';
  try {
    const r = await api('/api/features/refresh', {
      method:'POST', headers:{'Content-Type':'application/json'}, body: JSON.stringify({}),
    });
    if (r.error) { toast(errMsg(r), 'err'); return; }
    const n = (r.features||[]).length;
    toast(n ? `вңЁ мӢ кё°лҠҘ ${n}к°ң л°ңкІ¬! мўҢмёЎ 'рҹҶ• мӢ кё°лҠҘ' нғӯ нҷ•мқё` : 'мғҲлЎңмҡҙ кё°лҠҘ м—ҶмқҢ (мқҙлҜё мөңмӢ )', n?'ok':'info');
    if (state.view === 'features') renderView();
    else go('features');
  } catch (e) { toast(e.message, 'err'); }
  finally { btn.disabled = false; btn.innerHTML = orig; }
};
