// в”Җв”Җ н…Ңл§Ҳ в”Җв”Җ
const _ALL_THEMES = ['dark','light','midnight','forest','sunset'];
// v2.33.4 вҖ” 'auto' лҠ” prefers-color-scheme л”°лқјк°Җкё° (dark вҶ” light)
function _resolveAutoTheme() {
  try {
    return window.matchMedia && window.matchMedia('(prefers-color-scheme: light)').matches ? 'light' : 'dark';
  } catch { return 'dark'; }
}
function _applyTheme(th) {
  // мӢӨм ң DOM м Ғмҡ© лЎңм§Ғ вҖ” auto мқј л•ҢлҠ” resolvedTheme мӮ¬мҡ©
  const resolved = th === 'auto' ? _resolveAutoTheme() : th;
  _ALL_THEMES.forEach(t => document.body.classList.remove('theme-' + t));
  document.body.classList.add('theme-' + resolved);
  const isLight = resolved === 'light';
  if (window.Chart) {
    Chart.defaults.color = isLight ? '#555' : '#a0a0a8';
    Chart.defaults.borderColor = isLight ? 'rgba(0,0,0,0.08)' : 'rgba(255,255,255,0.07)';
  }
  document.documentElement.style.colorScheme = isLight ? 'light' : 'dark';
}
function setTheme(th) {
  document.body.classList.add('theme-switching');
  setTimeout(() => _applyTheme(th), 50);
  setTimeout(() => { document.body.classList.remove('theme-switching'); renderView(); }, 550);
  // мІҙнҒ¬л§ҲнҒ¬ вҖ” 'auto' лҸ„ лҸ…лҰҪ н•ӯлӘ©мңјлЎң м·Ёкёү
  document.querySelectorAll('.theme-check').forEach(el => {
    el.style.display = el.getAttribute('data-theme') === th ? '' : 'none';
  });
  try { localStorage.setItem('cc-theme', th); } catch {}
  // auto лӘЁл“ңм—җм„ңл§Ң OS ліҖкІҪ кө¬лҸ…
  try {
    if (window._themeMql) { window._themeMql.onchange = null; window._themeMql = null; }
    if (th === 'auto' && window.matchMedia) {
      const mql = window.matchMedia('(prefers-color-scheme: light)');
      mql.onchange = () => _applyTheme('auto');
      window._themeMql = mql;
    }
  } catch {}
}
(function _initTheme() {
  try {
    const saved = localStorage.getItem('cc-theme');
    if (saved === 'auto') {
      _applyTheme('auto');
      document.querySelectorAll('.theme-check').forEach(el => {
        el.style.display = el.getAttribute('data-theme') === 'auto' ? '' : 'none';
      });
      if (window.matchMedia) {
        const mql = window.matchMedia('(prefers-color-scheme: light)');
        mql.onchange = () => _applyTheme('auto');
        window._themeMql = mql;
      }
      return;
    }
    if (saved && saved !== 'dark' && _ALL_THEMES.includes(saved)) {
      _ALL_THEMES.forEach(t => document.body.classList.remove('theme-' + t));
      document.body.classList.add('theme-' + saved);
      document.querySelectorAll('.theme-check').forEach(el => {
        el.style.display = el.getAttribute('data-theme') === saved ? '' : 'none';
      });
      if (saved === 'light' && window.Chart) { Chart.defaults.color = '#555'; Chart.defaults.borderColor = 'rgba(0,0,0,0.08)'; }
      if (saved !== 'light') document.documentElement.style.colorScheme = 'dark';
      else document.documentElement.style.colorScheme = 'light';
    }
  } catch {}
})();

// в”Җв”Җ м–ём–ҙ (i18n) в”Җв”Җ
// лҹ°нғҖмһ„ лЎңлҚ”: /api/locales/{lang}.json мқ„ fetch н•ҳм—¬ I18N[lang] м—җ мұ„мӣҖ.
// кіјкұ° мқёлқјмқё I18N.en В· zhMap мӮ¬м „мқҖ dist/locales/*.json мңјлЎң л¶„лҰ¬лҗЁ.
const I18N = { ko: {} };

async function _loadLocale(lang) {
  if (!lang || lang === 'ko') return I18N.ko;
  if (I18N[lang] && Object.keys(I18N[lang]).length) return I18N[lang];
  try {
    const r = await fetch(`/api/locales/${encodeURIComponent(lang)}.json`, { cache: 'no-store' });
    if (!r.ok) {
      console.warn('[i18n] locale fetch failed', lang, r.status);
      I18N[lang] = {};
      return I18N[lang];
    }
    I18N[lang] = await r.json();
    return I18N[lang];
  } catch (e) {
    console.warn('[i18n] locale load error', lang, e);
    I18N[lang] = {};
    return I18N[lang];
  }
}


// в”Җв”Җ DOM мһҗлҸҷ лІҲм—ӯ м—”м§„ в”Җв”Җ
// renderView() нӣ„ DOM лӮҙ н•ңкөӯм–ҙ н…ҚмҠӨнҠё л…ёл“ңлҘј мӮ¬м „ кё°л°ҳмңјлЎң көҗмІҙ
const _KO_RE = /[к°Җ-нһЈ]/;
let _domTranslateCache = {};

// м •к·ңмӢқ нҠ№мҲҳл¬ёмһҗ мқҙмҠӨмјҖмқҙн”„
function _escReForI18n(s) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

// к°Ғ нӮӨм—җ лҢҖн•ҙ "н•ңкёҖ кІҪкі„ мқёмӢқ м№ҳнҷҳ нҢЁн„ҙ" мқ„ лҜёлҰ¬ л§Ңл“Өм–ҙ л‘”лӢӨ.
// кёҙ нӮӨ(5+)лҠ” л°”лЎң includes + split мңјлЎң, м§§мқҖ нӮӨ(1-4)лҠ” Hangul boundary ліҙнҳё regex лЎң.
function _buildKeyPatterns(keys) {
  return keys.map(k => {
    if (k.length >= 5) return { k, short: false };
    const pat = new RegExp(
      `(?<![\\uAC00-\\uD7A3])${_escReForI18n(k)}(?![\\uAC00-\\uD7A3])`,
      'g'
    );
    return { k, short: true, pat };
  });
}

function _translateDOM(root) {
  if (_curLang === 'ko') return;
  const dict = I18N[_curLang];
  if (!dict) return;
  if (!_domTranslateCache[_curLang]) {
    const keys = Object.keys(dict).filter(k => _KO_RE.test(k)).sort((a,b) => b.length - a.length);
    _domTranslateCache[_curLang] = { keys, patterns: _buildKeyPatterns(keys) };
  }
  const { keys, patterns } = _domTranslateCache[_curLang];

  const applyAll = (txt) => {
    for (const { k, short, pat } of patterns) {
      if (!txt.includes(k)) continue;
      if (short) {
        txt = txt.replace(pat, dict[k]);
      } else {
        txt = txt.split(k).join(dict[k]);
      }
    }
    return txt;
  };

  // в”Җв”Җ 1лӢЁкі„: data-i18n мҶҚм„ұ м§Ғм ‘ мІҳлҰ¬ (мҳҒл¬ё нӮӨ + н•ңкёҖ нӮӨ лӘЁл‘җ) в”Җв”Җ
  root.querySelectorAll('[data-i18n]').forEach(el => {
    const key = el.getAttribute('data-i18n');
    if (key && dict[key]) {
      el.textContent = dict[key];
    }
  });
  root.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    const key = el.getAttribute('data-i18n-placeholder');
    if (key && dict[key]) {
      el.setAttribute('placeholder', dict[key]);
    }
  });

  // в”Җв”Җ 2лӢЁкі„: н•ңкёҖ н…ҚмҠӨнҠё мҶҚм„ұ м№ҳнҷҳ в”Җв”Җ
  if (keys.length) {
    root.querySelectorAll('[placeholder],[title],[alt],[aria-label]').forEach(el => {
      ['placeholder','title','alt','aria-label'].forEach(attr => {
        const v = el.getAttribute(attr);
        if (v && _KO_RE.test(v)) {
          const nv = applyAll(v);
          if (nv !== v) el.setAttribute(attr, nv);
        }
      });
    });

    // в”Җв”Җ 3лӢЁкі„: н…ҚмҠӨнҠё л…ёл“ң мҲҳм§‘ В· көҗмІҙ в”Җв”Җ
    const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
    let node;
    while (node = walker.nextNode()) {
      const t = node.textContent;
      if (!t || !_KO_RE.test(t) || !t.trim()) continue;
      const trimmed = t.trim();
      // 1) м „мІҙ мқјм№ҳ мҡ°м„ 
      if (dict[trimmed]) {
        node.textContent = t.replace(trimmed, dict[trimmed]);
        continue;
      }
      // 2) нҢЁн„ҙ мҲңм°Ё м Ғмҡ© (кёҙ нӮӨ мҡ°м„  + м§§мқҖ нӮӨлҠ” Hangul boundary ліҙнҳё)
      const next = applyAll(t);
      if (next !== t) node.textContent = next;
    }
  }
}
// t() лІҲм—ӯ н•ЁмҲҳ вҖ” Korean мӣҗл¬ё лҳҗлҠ” кө¬мЎ°нҷ” нӮӨлҘј л°ӣлҠ”лӢӨ.
//   1-arg: single Korean argument - ko м—җм„ңлҠ” к·ёлҢҖлЎң, лӢӨлҘё м–ём–ҙлҠ” dict мЎ°нҡҢ
//   2-arg: structured key + fallback - ko/лҜёлІҲм—ӯ мӢң fallback мӮ¬мҡ©
// кө¬мЎ°нҷ” нӮӨ(мҳҒл¬ёл§Ң) к°Җ ko лӘЁл“ңм—җ мҳӨл©ҙ лҰ¬н„°лҹҙлЎң мғҲлҠ” кІғмқ„ л°©м§Җ.
function t(key, fallback) {
  if (_curLang === 'ko') {
    // н•ңкёҖ мӣҗл¬ёмқҖ к·ёлҢҖлЎң, кө¬мЎ°нҷ” нӮӨлҠ” fallback > key мҲң
    if (_KO_RE && _KO_RE.test(key)) return key;
    return fallback != null ? fallback : key;
  }
  const dict = I18N[_curLang];
  if (dict && dict[key]) return dict[key];
  return fallback != null ? fallback : key;
}

// NAV лқјлІЁ мӣҗліё ліҙкҙҖ
const _NAV_LABELS_KO = {};
NAV.forEach(n => { _NAV_LABELS_KO[n.id] = n.label; });

let _curLang = 'ko';
function setLang(lang) {
  // мҝ нӮӨ м„Өм • нӣ„ нҺҳмқҙм§Җ лҰ¬лЎңл“ң вҖ” лҹ°нғҖмһ„ лЎңлҚ”к°Җ /api/locales/{lang}.json мқ„ лӢӨмӢң fetch
  document.cookie = `cc-lang=${lang};path=/;max-age=${365*86400}`;
  location.reload();
}
// нҳ„мһ¬ м–ём–ҙ к°җм§Җ (мҝ нӮӨ + ?lang= мҝјлҰ¬ нҢҢлқјлҜён„°)
(function _initLang() {
  const m = document.cookie.match(/cc-lang=(\w+)/);
  if (m) _curLang = m[1];
  const ql = new URLSearchParams(location.search).get('lang');
  if (ql && ['en','zh'].includes(ql)) {
    _curLang = ql;
    document.cookie = `cc-lang=${ql};path=/;max-age=${365*86400}`;
  }
  // мІҙнҒ¬л§ҲнҒ¬ лҸҷкё°нҷ”
  document.querySelectorAll('.lang-check').forEach(el => {
    el.style.display = el.dataset.lang === _curLang ? '' : 'none';
  });
})();
// л№„лҸҷкё° лЎңмјҖмқј мӨҖл№„: boot() мҷҖ _translateDOM м–‘мӘҪмқҙ мқҙ Promise лҘј await н•ңлӢӨ
window._i18nReady = _loadLocale(_curLang).then(() => {
  _translateDOM(document.body);
  // лҹ°нғҖмһ„м—җ innerHTML лЎң м¶”к°ҖлҗҳлҠ” лҸҷм Ғ м»Ён…җмё  (лӘЁлӢ¬ В· мҠ¬лЎҜ л“ұ) лҘј мһҗлҸҷ лІҲм—ӯ
  if (_curLang !== 'ko' && typeof MutationObserver !== 'undefined') {
    let _i18nPending = new Set();
    let _i18nTimer = null;
    const _i18nFlush = () => {
      _i18nTimer = null;
      const nodes = Array.from(_i18nPending);
      _i18nPending.clear();
      for (const n of nodes) {
        if (n.isConnected) _translateDOM(n);
      }
    };
    // SVG мә”лІ„мҠӨ + мҪ”л“ң лё”лЎқмқҖ лІҲм—ӯ л¶Ҳн•„мҡ” вҖ” MutationObserverм—җм„ң м ңмҷё
    const _i18nSkipTags = new Set(['SVG','svg','CODE','code','PRE','pre','SCRIPT','STYLE','CANVAS']);
    const _i18nSkipIds = new Set(['wfNodes','wfEdges','wfViewport','wfTutNodes','wfTutEdges','wfTutSvg','wfMinimap']);
    const mo = new MutationObserver(muts => {
      for (const m of muts) {
        for (const node of m.addedNodes) {
          if (!node || node.nodeType !== 1) continue;
          if (_i18nSkipTags.has(node.tagName)) continue;
          if (_i18nSkipIds.has(node.id)) continue;
          // SVG лӮҙл¶Җ мҡ”мҶҢлҸ„ м ңмҷё
          if (node.closest && node.closest('svg')) continue;
          _i18nPending.add(node);
        }
      }
      if (_i18nPending.size && !_i18nTimer) {
        _i18nTimer = requestAnimationFrame(_i18nFlush);
      }
    });
    mo.observe(document.body, { childList: true, subtree: true });
    window._i18nObserver = mo;
  }
});
function _syncNavToggleVisibility() {
  const isMobile = window.matchMedia('(max-width: 900px)').matches;
  const collapsed = document.body.classList.contains('sb-collapsed');
  // лӘЁл°”мқј OR лҚ°мҠӨнҒ¬нҶұм—җм„ң м ‘нһҢ кІҪмҡ° вҶ’ н—ӨлҚ” нҶ кёҖ н‘ңмӢң. нҺјм№ң лҚ°мҠӨнҒ¬нҶұмқҖ sbToggle мӮ¬мҡ©.
  document.getElementById('navToggle').style.display = (isMobile || collapsed) ? '' : 'none';
}
function _toggleSidebar() {
  const isMobile = window.matchMedia('(max-width: 900px)').matches;
  if (isMobile) {
    const sb = document.getElementById('sidebar');
    sb.classList.toggle('open');
    document.body.classList.toggle('sidebar-open', sb.classList.contains('open'));
  } else {
    document.body.classList.toggle('sb-collapsed');
    try { localStorage.setItem('sb-collapsed', document.body.classList.contains('sb-collapsed') ? '1' : '0'); } catch {}
  }
  _syncNavToggleVisibility();
}
document.getElementById('sbToggle').onclick = _toggleSidebar;
document.getElementById('navToggle').onclick = _toggleSidebar;
window.addEventListener('resize', _syncNavToggleVisibility);
try { if (localStorage.getItem('sb-collapsed') === '1') document.body.classList.add('sb-collapsed'); } catch {}
_syncNavToggleVisibility();
